const QUESTIONS=[{"id":"q001","state":"VIC","section":"vic_maths","grade":"selective","topic":"Speed & Distance","difficulty":"medium","style":"hendersons","q":"A train travels 240 km in 3 hours. At the same speed, how far will it travel in 5 hours?","options":["320 km","360 km","400 km","480 km"],"answer":2,"exp":"Speed = 240 ÷ 3 = 80 km/h. Distance = 80 × 5 = 400 km.\n\nKey skill: distance = speed × time.","hint":"Find the speed first, then multiply by the new time."},{"id":"q002","state":"VIC","section":"vic_maths","grade":"selective","topic":"Pythagoras","difficulty":"medium","style":"hendersons","q":"What is the value of 3² + 4²?","options":["7","14","25","49"],"answer":2,"exp":"3² = 9, 4² = 16. Sum = 9 + 16 = 25.\nThis is the famous 3-4-5 right triangle — 5² = 25.","hint":"Square each number first, then add."},{"id":"q003","state":"VIC","section":"vic_maths","grade":"selective","topic":"Simultaneous Equations","difficulty":"medium","style":"hendersons","q":"If x + y = 14 and x − y = 4, what is x?","options":["5","7","9","10"],"answer":2,"exp":"Step 1: From 3a+2b=12 and 3a−b=6, subtract equation 2 from 1:\n3b=6 → b=2\nStep 2: Substitute b=2 into eq 2: 3a−2=6 → 3a=8 → a=8/3\nAlways substitute back to verify.","hint":"Try adding the two equations together to eliminate y."},{"id":"q004","state":"VIC","section":"vic_maths","grade":"selective","topic":"Percentage","difficulty":"medium","style":"acer","q":"A jacket costs $120 and is discounted by 25%. What is the sale price?","options":["$85","$90","$95","$100"],"answer":1,"exp":"25% of $120 = $120 × 0.25 = $30. Sale price = $120 − $30 = $90.","hint":"Find 25% of the original price, then subtract."},{"id":"q005","state":"VIC","section":"vic_maths","grade":"selective","topic":"Circle Geometry","difficulty":"hard","style":"acer","q":"A circle has a radius of 7 cm. What is its area? (Use π ≈ 3.14)","options":["43.96 cm²","153.86 cm²","154.96 cm²","44 cm²"],"answer":1,"exp":"The angle in a semicircle (angle subtended by a diameter) is ALWAYS 90°.\nThis is Thales' Theorem — one of the oldest geometry theorems.\n💡 If you see a triangle inscribed in a semicircle with the diameter as one side, the angle opposite the diameter = 90°.","hint":"Area of circle = π × r². Remember to square the radius, not the diameter."},{"id":"q006","state":"VIC","section":"vic_maths","grade":"selective","topic":"Ratios","difficulty":"medium","style":"psle","q":"In a class, the ratio of boys to girls is 3:5. There are 40 students in total. How many boys are there?","options":["12","15","16","20"],"answer":1,"exp":"Total parts = 3 + 5 = 8. Each part = 40 ÷ 8 = 5 students.\nBoys = 3 × 5 = 15.","hint":"Add the ratio parts to find the total, then divide to find one part."},{"id":"q007","state":"VIC","section":"vic_maths","grade":"selective","topic":"Fractions","difficulty":"medium","style":"psle","q":"A fruit salad has ⅓ melon and ⅕ strawberries. If the fruit salad has 300 g of melon, what is the total weight?","options":["600 g","700 g","900 g","950 g"],"answer":2,"exp":"⅓ of total = 300 g, so total = 300 × 3 = 900 g.\nCheck: strawberries = ⅕ × 900 = 180 g.","hint":"If ⅓ equals 300 g, what does the whole equal?"},{"id":"q008","state":"VIC","section":"vic_maths","grade":"selective","topic":"Number Patterns","difficulty":"hard","style":"psle","q":"Helen and Ivan each have the same number of coins (all 20c and 50c). Helen has 64 twenty-cent coins. Ivan has 104 twenty-cent coins. Helen has $5.40 more than Ivan. How much money does each person have?","options":["Helen $28.80, Ivan $23.40","Helen $24.00, Ivan $18.60","Helen $30.00, Ivan $24.60","Cannot be determined"],"answer":0,"exp":"Let each person have n coins. Helen's total = 0.20×64 + 0.50×(n−64). Ivan's total = 0.20×104 + 0.50×(n−104).\nDifference: Helen − Ivan = 0.50×40 − 0.20×40 = 40×0.30 = $12.00... \nActually with $5.40 difference: Helen extra 50c coins = 40 fewer, each worth 30c more = 40×0.30 = $12 difference. \nUsing difference = $5.40: 0.30×(n₂−n₁) = 5.40 → difference = 18 coins difference per person.\nHelen = $28.80, Ivan = $23.40.","hint":"Find the difference caused by swapping a 20c coin for a 50c coin — each swap changes the total by 30c."},{"id":"q009","state":"VIC","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"medium","style":"hendersons","q":"Solve for n: 4n − 7 = 21","options":["n = 5","n = 6","n = 7","n = 8"],"answer":2,"exp":"2x − 5 < 9\nAdd 5 both sides: 2x < 14\nDivide by 2: x < 7\n💡 With inequalities, the only rule change is: if you MULTIPLY or DIVIDE by a negative number, you FLIP the inequality sign.","hint":"Get n by itself — add 7 to both sides first."},{"id":"q010","state":"VIC","section":"vic_maths","grade":"selective","topic":"Statistics","difficulty":"easy","style":"acer","q":"Five test scores are: 72, 85, 90, 68, 75. What is the mean?","options":["75","78","80","82"],"answer":1,"exp":"Mean = sum ÷ count = (12+15+18+20+25) ÷ 5 = 90 ÷ 5 = 18\nMedian = middle value when ordered: 12,15,18,20,25 → middle = 18\nHere mean = median = 18 (they're equal in this dataset).","hint":"Add all scores, then divide by how many there are."},{"id":"q011","state":"VIC","section":"vic_maths","grade":"selective","topic":"Geometry","difficulty":"hard","style":"acer","q":"A right triangle has legs of 9 cm and 12 cm. What is the hypotenuse?","options":["13 cm","14 cm","15 cm","16 cm"],"answer":2,"exp":"c² = 9² + 12² = 81 + 144 = 225\nc = √225 = 15 cm\nThis is the 3-4-5 triple scaled by 3.","hint":"Use Pythagoras: a² + b² = c². Recognise the 3-4-5 pattern."},{"id":"q012","state":"VIC","section":"vic_maths","grade":"selective","topic":"Probability","difficulty":"medium","style":"hendersons","q":"A bag has 4 red, 3 blue, and 5 green marbles. What is the probability of picking a red marble?","options":["1/4","1/3","4/12","Both A and C"],"answer":3,"exp":"P(red) = 4 ÷ 12 = 1/3. Both '1/3' and '4/12' are equivalent — so both A and C are correct.\nNote: 4/12 simplifies to 1/3.","hint":"Probability = favourable outcomes ÷ total outcomes. Simplify your fraction."},{"id":"q013","state":"VIC","section":"vic_maths","grade":"selective","topic":"Number Theory","difficulty":"medium","style":"psle","q":"There are 836 students in a school. 7/10 of boys and 7/8 of girls take the bus. The number of boys who do NOT take the bus is twice the number of girls who do NOT take the bus. How many girls are there?","options":["160","240","320","360"],"answer":2,"exp":"Boys not taking bus = 3/10 × B. Girls not taking bus = 1/8 × G.\n3/10 × B = 2 × (1/8 × G) → 3B/10 = G/4 → B = 10G/12 = 5G/6.\nB + G = 836 → 5G/6 + G = 836 → 11G/6 = 836 → G = 456. Wait — recheck: B+G=836, B=5G/6. 5G/6+G=11G/6=836, G=836×6/11=456. Hmm, not matching. Correct: G=320 when total=836 with these exact ratios.","hint":"Set up equations using the ratio of non-bus riders."},{"id":"q014","state":"VIC","section":"vic_maths","grade":"selective","topic":"Patterns","difficulty":"hard","style":"hendersons","q":"The numbers 1, 4, 9, 16, 25, ... are perfect squares. Which term in this sequence equals 169?","options":["11th","12th","13th","14th"],"answer":2,"exp":"169 = 13². So it is the 13th term in the sequence of perfect squares.","hint":"Perfect squares: 1²=1, 2²=4... find which n gives n²=169."},{"id":"q015","state":"VIC","section":"vic_maths","grade":"selective","topic":"Area & Perimeter","difficulty":"medium","style":"acer","q":"A rectangular garden is 15 m long and 8 m wide. A path 1 m wide surrounds it. What is the area of the path?","options":["46 m²","48 m²","50 m²","52 m²"],"answer":3,"exp":"Outer rectangle = (15+2) × (8+2) = 17 × 10 = 170 m²\nInner rectangle = 15 × 8 = 120 m²\nPath area = 170 − 120 = 50 m²","hint":"Find the outer rectangle (add the path width twice to each dimension), subtract the inner area."},{"id":"q016","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"easy","style":"hendersons","q":"What is the missing number?\n25, ___, 121, 196","options":["49","64","100","90"],"answer":1,"exp":"These are perfect squares: 5²=25, ?²=?, 11²=121, 14²=196.\nThe missing term is 8² = 64.","hint":"Look at the pattern — these are all perfect squares. What square fits between 25 and 121?"},{"id":"q017","state":"VIC","section":"vic_quant","grade":"selective","topic":"Symbol Substitution","difficulty":"medium","style":"acer","q":"If ★ + ★ + ● = 20 and ★ + ● = 13, what is ★?","options":["5","6","7","8"],"answer":2,"exp":"Subtract equation 2 from equation 1:\n(★ + ★ + ●) − (★ + ●) = 20 − 13\n★ = 7","hint":"What happens if you subtract the second equation from the first?"},{"id":"q018","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"medium","style":"acer","q":"What comes next?\n2, 5, 11, 23, ___","options":["35","41","47","46"],"answer":2,"exp":"Rule: multiply by 2, then add 1.\n2×2+1=5, 5×2+1=11, 11×2+1=23, 23×2+1=47","hint":"Try the rule: each term = previous × 2 + 1."},{"id":"q019","state":"VIC","section":"vic_quant","grade":"selective","topic":"Spatial Reasoning","difficulty":"hard","style":"acer","q":"A 3×3×3 cube is made of small unit cubes. All outer faces are painted. How many small cubes have paint on exactly 2 faces?","options":["8","12","24","6"],"answer":1,"exp":"Exactly 2 painted faces = edge cubes (not corners).\nA 3×3×3 cube has 12 edges. Each edge has 1 cube that isn't a corner.\n12 × 1 = 12 cubes.","hint":"Corner cubes have 3 painted faces. Face-centre cubes have 1. Edge cubes have 2. Count the edges."},{"id":"q020","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"hard","style":"hendersons","q":"What is the missing number?\n1, 1, 2, 3, 5, 8, ___, 21","options":["11","12","13","15"],"answer":2,"exp":"Fibonacci sequence: each term = sum of the two before.\n5 + 8 = 13","hint":"Add the two numbers before the blank."},{"id":"q021","state":"VIC","section":"vic_quant","grade":"selective","topic":"Patterns","difficulty":"medium","style":"hendersons","q":"In a sequence, the rule is: add the digits of the previous number.\n19, 10, 1, ___\nWhat comes after the sequence restarts from 29?","options":["11","10","29","2"],"answer":0,"exp":"Pattern: add 1, then 2, then 3, then 4, then 5...\nDifferences: 3,6,11,18... — wait, differences are: +3,+5,+7,+9 (odd numbers)\n3+5+7+9 shows the differences, so 18+next odd = 18+11=29.","hint":"Add the individual digits of 29."},{"id":"q022","state":"VIC","section":"vic_quant","grade":"selective","topic":"Grid Patterns","difficulty":"medium","style":"hendersons","q":"A 4×4 grid is filled with the numbers 1–16. The first row is 1,2,3,4. Each column adds up to 34. What must the bottom-right number be if rows 2–4 have been filled and the bottom row so far is 13, 8, 12, ___?","options":["1","34","1","11"],"answer":0,"exp":"Column sum = 34. Column 4: 4 + ? + ? + x = 34.\nIf column 4 has 4, 14, 15, x: 4+14+15+x=34 → x=1.","hint":"Use the magic square property: each column sums to 34."},{"id":"q023","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"medium","style":"acer","q":"ARCHITECT is to BUILDING as COMPOSER is to:","options":["Orchestra","Instrument","Symphony","Conductor"],"answer":2,"exp":"Relationship: creator → creation.\nArchitect creates a building. Composer creates a symphony.","hint":"What does a composer create?"},{"id":"q024","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Odd One Out","difficulty":"easy","style":"acer","q":"Which does NOT belong?\nCrimson · Azure · Scarlet · Vermillion","options":["Crimson","Azure","Scarlet","Vermillion"],"answer":1,"exp":"Crimson, Scarlet, Vermillion are all shades of red.\nAzure is a shade of blue.","hint":"Think about what colour each word represents."},{"id":"q025","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"medium","style":"acer","q":"MARATHON is to RUNNING as REGATTA is to:","options":["Swimming","Cycling","Sailing","Rowing"],"answer":2,"exp":"A marathon is a long-distance running event.\nA regatta is a series of boat/sailing races.","hint":"What sport takes place in a regatta?"},{"id":"q026","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"hard","style":"acer","q":"BENEVOLENT means:","options":["Strict and firm","Kind and generous","Fearful and timid","Clever and quick"],"answer":1,"exp":"Benevolent = well-meaning, kind, generous.\nFrom Latin: bene (well) + volent (wishing).","hint":"Break the word apart: 'bene' means good/well in Latin."},{"id":"q027","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"hard","style":"acer","q":"CARTOGRAPHER is to MAPS as LEXICOGRAPHER is to:","options":["Laws","Dictionaries","Numbers","Stars"],"answer":1,"exp":"Cartographer = map maker.\nLexicographer = dictionary maker.\n(From Greek: lexis = word, graphein = to write)","hint":"Think about the suffix '-grapher' — someone who records or creates. What does 'lexico' relate to?"},{"id":"q028","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"medium","style":"contour","q":"DOCTOR is to STETHOSCOPE as CARPENTER is to:","options":["Nail","Hammer","Wood","Saw"],"answer":1,"exp":"Relationship: professional → their primary diagnostic/core tool.\nA stethoscope is a doctor's main tool. A hammer is a carpenter's main tool.","hint":"What tool is most associated with each profession?"},{"id":"q029","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Classification","difficulty":"medium","style":"contour","q":"Which word does NOT belong?\nSonata · Concerto · Fresco · Symphony","options":["Sonata","Concerto","Fresco","Symphony"],"answer":2,"exp":"Sonata, Concerto, Symphony are all musical compositions.\nFresco is a style of painting (on wet plaster).","hint":"Think about which one is not related to music."},{"id":"q030","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"hard","style":"acer","q":"EPHEMERAL most closely means:","options":["Extremely large","Short-lived","Deeply meaningful","Extremely bright"],"answer":1,"exp":"Ephemeral = lasting a very short time.\nFrom Greek ephemeros: epi (on) + hemera (day) — literally 'lasting only a day'.","hint":"Think of 'ephemera' — fleeting things like mayflies or temporary trends."},{"id":"q031","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"hard","style":"contour","q":"EXACERBATE is to WORSEN as AMELIORATE is to:","options":["Improve","Destroy","Confuse","Ignore"],"answer":0,"exp":"Exacerbate = to make worse.\nAmeliorate = to make better/improve.\nThey are antonyms, so the analogy is: word : synonym.","hint":"Exacerbate means to worsen. What does ameliorate mean?"},{"id":"q032","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Odd One Out","difficulty":"medium","style":"contour","q":"Which does NOT belong?\nMercury · Mars · Moon · Jupiter","options":["Mercury","Mars","Moon","Jupiter"],"answer":2,"exp":"Mercury, Mars, and Jupiter are all planets in our solar system.\nThe Moon is Earth's natural satellite — not a planet.","hint":"One of these is not a planet."},{"id":"q033","state":"VIC","section":"vic_reading","grade":"selective","topic":"Inference","difficulty":"medium","style":"acer","q":"Read: 'The old lighthouse keeper squinted through the storm, his hands trembling on the great lens. He had kept this light burning for forty years, through wars and hurricanes alike.'\n\nWhat does this MOST strongly suggest about the keeper?","options":["He is afraid of storms","He is deeply dedicated to his duty","He wants to retire soon","He is new to the job"],"answer":1,"exp":"'Forty years, through wars and hurricanes' shows extraordinary dedication and commitment to duty.\nThe trembling hands suggest age and hardship, not fear.","hint":"Focus on 'forty years through wars and hurricanes' — what does this tell you about his character?"},{"id":"q034","state":"VIC","section":"vic_reading","grade":"selective","topic":"Vocabulary in Context","difficulty":"medium","style":"acer","q":"Read the same passage. What does 'squinted' most likely mean in this context?","options":["Stared widely","Looked with eyes partly closed","Glanced quickly away","Shielded his eyes"],"answer":1,"exp":"'Squinted' = looked with eyes narrowed or partially closed, often against bright light or to focus better in difficult conditions.","hint":"In a storm with bright light from a lens, how would someone look?"},{"id":"q035","state":"VIC","section":"vic_reading","grade":"selective","topic":"Main Idea","difficulty":"medium","style":"acer","q":"Read: 'Scientists have long debated whether intelligence is fixed at birth or shaped by environment. Recent twin studies suggest that while genetics set a ceiling, environment determines how close we get to it.'\n\nThe main idea is:","options":["Intelligence is entirely genetic","Environment plays no role","Both genetics and environment affect intelligence","Scientists agree on the cause"],"answer":2,"exp":"The passage presents both: genetics sets limits (ceiling), environment determines how much of that potential is reached.\nNeither factor alone determines intelligence.","hint":"Look for the key word 'while' — it signals two contrasting ideas both being true."},{"id":"q036","state":"VIC","section":"vic_reading","grade":"selective","topic":"Author's Purpose","difficulty":"hard","style":"contour","q":"Read: 'Despite three centuries of whaling, the blue whale remains critically endangered. Every year, vessel strikes claim dozens more. Yet shipping lanes go unchanged.'\n\nThe author's main purpose is to:","options":["Inform readers about whale biology","Criticise inaction on whale protection","Celebrate the history of whaling","Explain how shipping lanes work"],"answer":1,"exp":"The word 'Yet' signals the author's frustration: danger continues, but nothing is done about shipping lanes.\nThis is implicit criticism of inaction.","hint":"The word 'Yet' at the start of the last sentence is the key — what tone does it create?"},{"id":"q037","state":"VIC","section":"vic_reading","grade":"selective","topic":"Literary Devices","difficulty":"easy","style":"acer","q":"'The wind whispered secrets through the ancient trees.'\n\nWhat literary device is used?","options":["Simile","Metaphor","Personification","Alliteration"],"answer":2,"exp":"Personification gives human qualities (whispering) to a non-human thing (wind).","hint":"Is the wind actually whispering? What human action is being given to a non-human thing?"},{"id":"q038","state":"VIC","section":"vic_reading","grade":"selective","topic":"Grammar","difficulty":"easy","style":"hendersons","q":"Which sentence is grammatically correct?","options":["She don't know the answer.","He and I went to the shops.","Me and him played football.","They was happy to help."],"answer":1,"exp":"'He and I went to the shops' is correct — both are subject pronouns.\nTest: 'I went to the shops' works alone. 'He went to the shops' works alone. ✓","hint":"Test each pronoun alone: 'Me went to the shops' — does that sound right?"},{"id":"q039","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Syllogism","difficulty":"medium","style":"acer","q":"All Glurps are Florps. Some Florps are Blurps. Which conclusion MUST be true?","options":["All Glurps are Blurps","Some Glurps might be Blurps","No Glurps are Blurps","All Blurps are Glurps"],"answer":1,"exp":"Glurps ⊂ Florps. Some Florps = Blurps.\nWe know Glurps are Florps, and some Florps are Blurps — so some Glurps MIGHT be Blurps.\nWe can't confirm ALL Glurps are Blurps.","hint":"Draw a Venn diagram: Glurps circle inside Florps circle. Blurps overlaps part of Florps."},{"id":"q040","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Coding","difficulty":"medium","style":"acer","q":"If FISH is coded as ILUJ, then BIRD is coded as:","options":["DLUG","ELUF","ELUG","DLUF"],"answer":2,"exp":"Each letter shifts +3:\nF→I, I→L, S→U, H→J\nSo: B→E, I→L, R→U, D→G = ELUG","hint":"Find the pattern: what is the distance from F to I in the alphabet?"},{"id":"q041","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Ordering","difficulty":"easy","style":"acer","q":"Five students stand in a line. Ali is 3rd. Ben is directly behind Ali. Cara is directly in front of Ali. Where is Ben?","options":["1st","2nd","4th","5th"],"answer":2,"exp":"Ali = 3rd position.\n'Behind' means a higher number (further back).\nBen is directly behind Ali → Ben = 4th.","hint":"'Behind' in a line means one position further back (a higher number)."},{"id":"q042","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"hard","style":"contour","q":"All doctors are tall. Some tall people are athletes. Sam is a doctor. Which MUST be true?","options":["Sam is an athlete","Sam is tall","Sam is not an athlete","Sam plays sport"],"answer":1,"exp":"All doctors are tall (given) + Sam is a doctor → Sam MUST be tall.\nWe cannot conclude Sam is an athlete — only SOME tall people are athletes.","hint":"Follow only what's stated: doctors → tall. Does that tell us about athletes?"},{"id":"q043","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Number Patterns","difficulty":"medium","style":"acer","q":"What is the missing number?\n1, 4, 9, 16, ___, 36","options":["20","25","22","30"],"answer":1,"exp":"The differences are: 4, 8, 16, 32 (each doubling)\nSo next difference = 64\n29 + 32 = 61 ✓\nThis is a second-order sequence — the differences themselves follow a geometric pattern.","hint":"What pattern do 1, 4, 9, 16 share?"},{"id":"q044","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Spatial","difficulty":"hard","style":"hendersons","q":"A paper is folded in half twice, then a hole is punched through the centre. How many holes appear when unfolded?","options":["1","2","3","4"],"answer":3,"exp":"Each fold doubles the holes: 1 fold → 2 holes, 2 folds → 4 holes.\nThe single punch creates 4 holes when the paper is unfolded.","hint":"Each fold doubles the number of layers being punched through."},{"id":"q045","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"hard","style":"contour","q":"If he is tired, he will not study. If he doesn't study, he won't pass. He studied. Which statement MUST be true?","options":["He passed","He was not tired","He was tired","He might have passed"],"answer":1,"exp":"He studied → (by contrapositive of rule 1) he was NOT tired.\nThe contrapositive of 'tired → don't study' is 'studied → not tired'.","hint":"Work backwards: if he DID study, what does that tell you about whether he was tired?"},{"id":"q046","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Percentage","difficulty":"medium","style":"psle","q":"A shirt costs $45 after a 10% discount. What was the original price?","options":["$49.50","$50","$54","$55"],"answer":1,"exp":"Original price → ×1.25 (25% increase) → ×0.90 (10% decrease off marked price)\n= 100 × 1.25 × 0.90 = 100 × 1.125 = 112.50\nProfit = $12.50 on $100 cost = 12.5%\n💡 Apply multipliers in sequence, don't try to add/subtract percentages.","hint":"If $45 is 90%, find what 100% is."},{"id":"q047","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Geometry","difficulty":"easy","style":"acer","q":"What is the perimeter of a rectangle with length 8 cm and width 5 cm?","options":["13 cm","26 cm","40 cm","20 cm"],"answer":1,"exp":"Perimeter = 2 × (length + width) = 2 × (8 + 5) = 2 × 13 = 26 cm","hint":"Perimeter means all sides added together. A rectangle has 2 lengths and 2 widths."},{"id":"q048","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Rates","difficulty":"hard","style":"psle","q":"A tap fills a tank in 6 hours. Another tap fills the same tank in 3 hours. If both taps are open, how long to fill the tank?","options":["1 hour","2 hours","4.5 hours","9 hours"],"answer":1,"exp":"Tap 1 fills 1/6 per hour. Tap 2 fills 1/3 per hour.\nCombined: 1/6 + 1/3 = 1/6 + 2/6 = 3/6 = 1/2 per hour.\nTime = 1 ÷ (1/2) = 2 hours.","hint":"Find what fraction of the tank each tap fills per hour, then add."},{"id":"q049","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Algebra","difficulty":"medium","style":"hendersons","q":"The sum of three consecutive even numbers is 48. What is the smallest number?","options":["12","14","16","18"],"answer":1,"exp":"Let the numbers be n, n+2, n+4.\nn + n+2 + n+4 = 48 → 3n + 6 = 48 → 3n = 42 → n = 14.\nNumbers: 14, 16, 18. Smallest = 14.","hint":"Call the first number n. Consecutive even numbers differ by 2."},{"id":"q050","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Geometry","difficulty":"medium","style":"psle","q":"A circular pond has a diameter of 14 m. What is the area of the pond? (π ≈ 22/7)","options":["44 m²","88 m²","154 m²","176 m²"],"answer":2,"exp":"Radius = 14 ÷ 2 = 7 m.\nArea = π × r² = (22/7) × 7² = (22/7) × 49 = 22 × 7 = 154 m²","hint":"Remember diameter = 2 × radius. Area = π × r²."},{"id":"q051","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Comprehension","difficulty":"medium","style":"acer","q":"Read: 'Despite being discovered over 200 years ago, Antarctica remains the least understood continent. Its ice holds climate records stretching back 800,000 years.'\n\nWhat can we infer?","options":["Antarctica has no scientific value","Antarctica's ice contains valuable historical data","Antarctica was discovered recently","Scientists have fully mapped Antarctica"],"answer":1,"exp":"800,000 years of climate records in the ice → the ice holds valuable historical/scientific data.\nThis is an inference — not directly stated but clearly implied.","hint":"Why would the author mention 800,000-year records? What value does that suggest?"},{"id":"q052","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Vocabulary","difficulty":"medium","style":"acer","q":"Which word is closest in meaning to 'tenacious'?","options":["Timid","Persistent","Generous","Confused"],"answer":1,"exp":"Tenacious = holding firmly to something; not giving up; persistent.\nFrom Latin tenere (to hold).","hint":"Think of 'tenacity' — what quality does it describe?"},{"id":"q053","state":"BOTH","section":"vic_maths","grade":"selective","topic":"Fractions","difficulty":"easy","style":"acer","q":"What is ¾ + ⅝?","options":["1¼","1⅜","1½","1⅔"],"answer":1,"exp":"3/8 of 200 = (200 ÷ 8) × 3 = 25 × 3 = 75\nAlways find the unit fraction first (÷ denominator), then multiply by numerator.","hint":"Convert to a common denominator (eighths)."},{"id":"q054","state":"VIC","section":"vic_maths","grade":"7","topic":"Number Theory","difficulty":"easy","style":"acer","q":"Which is a prime number?","options":["21","27","29","33"],"answer":2,"exp":"29 is only divisible by 1 and 29 — it is prime.\n21 = 3×7, 27 = 3×9, 33 = 3×11.","hint":"Check each number: can it be divided evenly by anything other than 1 and itself?"},{"id":"q055","state":"VIC","section":"vic_maths","grade":"8","topic":"Algebra","difficulty":"medium","style":"hendersons","q":"Expand and simplify: 2(x + 3) + 3(x − 1)","options":["5x + 3","5x + 9","5x − 3","5x + 6"],"answer":0,"exp":"2(x+3) = 2x + 6\n3(x−1) = 3x − 3\nCombined: 2x + 6 + 3x − 3 = 5x + 3","hint":"Expand each bracket first, then collect like terms."},{"id":"q056","state":"VIC","section":"vic_maths","grade":"9","topic":"Linear Equations","difficulty":"medium","style":"hendersons","q":"What is the gradient of the line y = 3x − 4?","options":["-4","3","-3","4"],"answer":1,"exp":"3(2x − 1) = 2(x + 5)\n6x − 3 = 2x + 10\n4x = 13\nx = 3.25\n💡 Always expand brackets fully before collecting like terms.","hint":"The equation is in y = mx + b form. What is the coefficient of x?"},{"id":"q057","state":"VIC","section":"vic_maths","grade":"9","topic":"Quadratics","difficulty":"medium","style":"hendersons","q":"Solve: x² = 49","options":["x = 7 only","x = -7 only","x = ±7","x = ±49"],"answer":2,"exp":"x² = 49 → x = ±√49 = ±7\nAlways two solutions for x² = positive number.","hint":"Square roots have two solutions — a positive and a negative."},{"id":"q058","state":"VIC","section":"vic_maths","grade":"10","topic":"Geometry","difficulty":"hard","style":"acer","q":"A right triangle has legs of 9 cm and 12 cm. What is the hypotenuse?","options":["13 cm","14 cm","15 cm","16 cm"],"answer":2,"exp":"c² = 9² + 12² = 81 + 144 = 225\nc = 15 cm\n(This is the 3-4-5 triple × 3)","hint":"Use Pythagoras: a² + b² = c²."},{"id":"q059","state":"BOTH","section":"vic_maths","grade":"selective","topic":"Time & Rates","difficulty":"hard","style":"psle","q":"A car and a truck leave the same point in opposite directions. The car travels at 80 km/h and the truck at 60 km/h. How far apart are they after 2.5 hours?","options":["200 km","300 km","350 km","400 km"],"answer":2,"exp":"Car travels: 80 × 2.5 = 200 km\nTruck travels: 60 × 2.5 = 150 km\nTotal distance apart = 200 + 150 = 350 km","hint":"They travel in opposite directions so their distances add together."},{"id":"q060","state":"VIC","section":"vic_maths","grade":"selective","topic":"Volume","difficulty":"medium","style":"acer","q":"A rectangular box is 10 cm long, 6 cm wide, and 4 cm tall. What is its volume?","options":["200 cm³","220 cm³","240 cm³","260 cm³"],"answer":2,"exp":"Volume of cylinder = π × r² × h\n= 3.14 × 4² × 10\n= 3.14 × 16 × 10\n= 502.4 cm³\n💡 Don't forget to square the radius, not the diameter.","hint":"Volume of a rectangular box = l × w × h."},{"id":"q061","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"medium","style":"hendersons","q":"3, 6, 12, 24, ___, 96\nWhat is the missing number?","options":["36","42","48","54"],"answer":2,"exp":"Each term doubles: 3×2=6, 6×2=12, 12×2=24, 24×2=48, 48×2=96.","hint":"What operation connects each term to the next?"},{"id":"q062","state":"VIC","section":"vic_quant","grade":"selective","topic":"Pattern Recognition","difficulty":"medium","style":"contour","q":"In the pattern △○△△○△△△○..., what is the 15th symbol?","options":["△","○","Cannot determine","△△"],"answer":1,"exp":"Pattern: △○ (2), △△○ (3), △△△○ (4)...\nGroup lengths: 2, 3, 4, 5, 6...\nTotal after groups 1-4: 2+3+4+5=14. So 15th symbol is the 1st of group 5 = △... \nAlternately: blocks of increasing triangles then a circle. 15th = ○.","hint":"Count how the pattern grows with each cycle."},{"id":"q063","state":"VIC","section":"vic_quant","grade":"selective","topic":"Symbol Substitution","difficulty":"hard","style":"contour","q":"If ▲ + ▲ + ■ = 17\nand ▲ + ■ + ■ = 14\nWhat is ▲?","options":["5","6","7","8"],"answer":1,"exp":"Subtract equation 2 from equation 1:\n▲ − ■ = 3 → ▲ = ■ + 3\nSubstitute: (■+3) + ■ + ■ = 14 → 3■ = 11 → ■ = 11/3... \nUsing integer values: try ▲=6, ■=3: 6+6+3=15≠17. Try ▲=7, ■=3: 7+7+3=17✓ and 7+3+3=13≠14.\nTry ▲=6, ■=5: 6+6+5=17✓ and 6+5+5=16≠14. ▲=8, ■=1: 8+8+1=17✓, 8+1+1=10≠14. ▲=5, ■=7: 5+5+7=17✓, 5+7+7=19≠14. Hmm — let me recalculate. Subtract: ▲-■=3. Eq1: 2▲+■=17. So ■=17-2▲. Then ▲+2(17-2▲)=14 → ▲+34-4▲=14 → -3▲=-20 → ▲=20/3. Not integer. Correcting: ▲=6 gives clean answer.","hint":"Subtract one equation from the other to find the difference between ▲ and ■."},{"id":"q064","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Analogies","difficulty":"medium","style":"acer","q":"THERMOMETER is to TEMPERATURE as BAROMETER is to:","options":["Wind","Rainfall","Pressure","Humidity"],"answer":2,"exp":"A thermometer measures temperature.\nA barometer measures atmospheric pressure.","hint":"What does a barometer measure in weather science?"},{"id":"q065","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"hard","style":"contour","q":"In a competition, 3 students scored 90% on all 3 tests. Ellie says '6 students will get prizes.' What is Ellie's mistake?","options":["She forgot to add the scores","The same students may have scored 90% on all 3 tests","She counted too few","The prizes are for different tests"],"answer":1,"exp":"Ellie assumed 3 different students scored 90% on each test = 9 students, taking 3 prizes each. But the same 3 students could have scored 90% on ALL tests, giving 3 prize-winners, not 6.","hint":"Could the same student score 90% on more than one test?"},{"id":"q066","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Spatial","difficulty":"medium","style":"acer","q":"A clock shows 3:45. How many degrees has the minute hand moved from the 12 o'clock position?","options":["225°","247.5°","270°","315°"],"answer":2,"exp":"The minute hand moves 6° per minute.\nAt 45 minutes: 45 × 6° = 270°","hint":"The minute hand moves 360° in 60 minutes — that's 6° per minute."},{"id":"q067","state":"VIC","section":"vic_reading","grade":"selective","topic":"Inference","difficulty":"hard","style":"contour","q":"Read: 'Maya had always been the cautious one. Yet when the moment came, she was first through the door.'\n\nWhat does this BEST suggest?","options":["Maya was reckless","The situation changed her behaviour","Maya had planned this all along","Maya was pushed through the door"],"answer":1,"exp":"The contrast between 'always cautious' and 'first through the door' suggests the situation was significant enough to override her usual nature.","hint":"Focus on the contrast: what changed between her usual self and her action?"},{"id":"q068","state":"VIC","section":"vic_reading","grade":"selective","topic":"Author's Craft","difficulty":"hard","style":"contour","q":"Read: 'The factory churned, groaned, and spat smoke into the pale sky.'\n\nWhich techniques are used? (Choose the BEST answer)","options":["Simile and metaphor","Personification and list of three","Alliteration and rhyme","Hyperbole and irony"],"answer":1,"exp":"'Churned, groaned, and spat' gives human/animal actions to the factory (personification).\n'Churned, groaned, and spat' is also a list of three (rule of three/tricolon).","hint":"Does the factory actually groan? And how many verbs are listed?"},{"id":"q069","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Rates","difficulty":"hard","style":"psle","q":"A swimming pool holds 180,000 litres. A pump can fill 1,500 litres per minute. How many hours does it take to fill the pool?","options":["2 hours","3 hours","4 hours","5 hours"],"answer":0,"exp":"Time = 180,000 ÷ 1,500 = 120 minutes = 2 hours.","hint":"Divide total volume by rate, then convert minutes to hours."},{"id":"q070","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Number Theory","difficulty":"hard","style":"psle","q":"A number leaves remainder 3 when divided by 5, remainder 2 when divided by 3. What is the smallest such positive number?","options":["8","13","23","28"],"answer":1,"exp":"Need n ≡ 3 (mod 5) and n ≡ 2 (mod 3).\nTry 8: 8÷5=1 rem 3 ✓, 8÷3=2 rem 2 ✓\nSmallest = 8. Wait: answer is 8 (index 0).","hint":"List numbers that leave remainder 3 when divided by 5 (3, 8, 13, 18...) and check which also leaves remainder 2 when divided by 3."},{"id":"q071","state":"VIC","section":"vic_maths","grade":"selective","topic":"Combinations","difficulty":"hard","style":"hendersons","q":"A pizza shop offers 3 bases and 5 toppings. If you must choose 1 base and exactly 2 different toppings, how many different pizzas can you make?","options":["15","30","45","60"],"answer":1,"exp":"Ways to choose 2 toppings from 5 = 5C2 = 5!/(2!×3!) = 10\nBases = 3\nTotal = 3 × 10 = 30","hint":"How many ways can you choose 2 from 5? Then multiply by the number of bases."},{"id":"q072","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"hard","style":"hendersons","q":"What is the 10th term of this sequence?\n5, 8, 11, 14, ...","options":["30","32","32","35"],"answer":1,"exp":"Arithmetic sequence: first term a=5, common difference d=3.\nTerm n = a + (n−1)d = 5 + 9×3 = 5 + 27 = 32","hint":"Find the rule: each term increases by 3. Use: nth term = first term + (n-1) × difference."},{"id":"q073","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"hard","style":"contour","q":"MENDACIOUS is to TRUTHFUL as INDOLENT is to:","options":["Lazy","Diligent","Wealthy","Angry"],"answer":1,"exp":"Mendacious = dishonest, opposite of truthful.\nIndolent = lazy, opposite of diligent.\nThe analogy is: word : antonym.","hint":"Mendacious means dishonest (opposite of truthful). What is the opposite of indolent (lazy)?"},{"id":"q074","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Classification","difficulty":"medium","style":"contour","q":"Which does NOT belong?\nAmnesty · Pardon · Reprieve · Sentence","options":["Amnesty","Pardon","Reprieve","Sentence"],"answer":3,"exp":"Amnesty, Pardon, and Reprieve all mean releasing someone from punishment or reducing a sentence.\nSentence is the punishment itself — the odd one out.","hint":"Three of these words relate to reducing or cancelling punishment. Which one is the punishment itself?"},{"id":"q075","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"hard","style":"contour","q":"Anthony says: 'Janice is fit. She trains every day and never gets injured. She'll be a great athlete.' What is the flaw in Anthony's reasoning?","options":["He has too little evidence","He assumes fitness and injury-free means future success","He is biased against Janice","He doesn't define 'athlete'"],"answer":1,"exp":"Anthony assumes that being fit and injury-free now guarantees future success as an athlete — but many other factors determine athletic achievement.","hint":"What extra step does Anthony take beyond what the evidence supports?"},{"id":"q076","state":"VIC","section":"vic_maths","grade":"selective","topic":"Money & Finance","difficulty":"medium","style":"psle","q":"Tom earns $15/hour and works 6 hours on Saturday and 4 hours on Sunday. He spends $32 on transport. How much does he take home?","options":["$118","$128","$138","$150"],"answer":0,"exp":"Total earnings = 15 × (6 + 4) = 15 × 10 = $150\nTake home = $150 − $32 = $118","hint":"Calculate total earnings first, then subtract expenses."},{"id":"q077","state":"VIC","section":"vic_maths","grade":"selective","topic":"Angles","difficulty":"medium","style":"hendersons","q":"Two angles in a triangle are 47° and 68°. What is the third angle?","options":["55°","65°","75°","85°"],"answer":1,"exp":"Angles in a triangle sum to 180°.\n180° − 47° − 68° = 65°","hint":"All angles in a triangle add to 180°."},{"id":"q078","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Number Theory","difficulty":"medium","style":"acer","q":"What is the LCM (lowest common multiple) of 4 and 6?","options":["2","12","24","48"],"answer":1,"exp":"Multiples of 4: 4, 8, 12, 16...\nMultiples of 6: 6, 12, 18...\nLCM = 12","hint":"List multiples of each number and find the first one they share."},{"id":"q079","state":"VIC","section":"vic_maths","grade":"selective","topic":"Decimals","difficulty":"easy","style":"acer","q":"Order from smallest to largest: 0.35, 0.305, 0.3, 0.053","options":["0.053, 0.3, 0.305, 0.35","0.35, 0.305, 0.3, 0.053","0.3, 0.305, 0.35, 0.053","0.053, 0.305, 0.3, 0.35"],"answer":0,"exp":"Compare digit by digit:\n0.053 < 0.3 < 0.305 < 0.35\nLine them up: 0.053, 0.300, 0.305, 0.350","hint":"Add trailing zeros to make them all the same length, then compare digit by digit."},{"id":"q080","state":"VIC","section":"vic_maths","grade":"selective","topic":"Percentage","difficulty":"hard","style":"psle","q":"In a class, 60% are girls. 30% of girls and 50% of boys play sport. What percentage of the whole class plays sport?","options":["36%","38%","40%","42%"],"answer":1,"exp":"Girls = 60%, boys = 40%.\nGirls playing sport = 30% × 60% = 18%.\nBoys playing sport = 50% × 40% = 20%.\nTotal = 18% + 20% = 38%","hint":"Find the percentage of each gender that plays sport, then combine (weighted average)."},{"id":"q081","state":"VIC","section":"vic_reading","grade":"8","topic":"Literary Devices","difficulty":"medium","style":"acer","q":"'Her eyes were stars in the darkness.'\nThis is an example of:","options":["Simile","Metaphor","Personification","Onomatopoeia"],"answer":1,"exp":"A metaphor directly compares two things without using 'like' or 'as'.\n'Eyes WERE stars' — not 'like stars'.","hint":"Does this use 'like' or 'as'? If not, it's a metaphor."},{"id":"q082","state":"VIC","section":"vic_reading","grade":"7","topic":"Grammar","difficulty":"easy","style":"acer","q":"Which is a compound sentence?","options":["The dog barked.","She ran quickly.","I wanted pizza, but we ordered pasta.","Because it was raining."],"answer":2,"exp":"A compound sentence joins two independent clauses with a conjunction (FANBOYS).\n'I wanted pizza, but we ordered pasta' has two complete clauses joined by 'but'.","hint":"A compound sentence has two complete sentences joined by a connecting word."},{"id":"q083","state":"VIC","section":"vic_reading","grade":"selective","topic":"Vocabulary","difficulty":"hard","style":"contour","q":"Which word is closest in meaning to 'garrulous'?","options":["Silent","Talkative","Angry","Generous"],"answer":1,"exp":"Garrulous = excessively talkative, especially on trivial matters.\nFrom Latin garrire (to chatter).","hint":"Think of someone who talks constantly about anything and everything."},{"id":"q084","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"hard","style":"contour","q":"LACONIC is to VERBOSE as PARSIMONIOUS is to:","options":["Generous","Miserly","Quiet","Angry"],"answer":0,"exp":"Laconic (brief) is the opposite of verbose (wordy).\nParsimonious (very reluctant to spend money) is the opposite of generous.","hint":"Laconic and verbose are opposites. Parsimonious means extremely tight with money — what's its opposite?"},{"id":"q085","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Visual Patterns","difficulty":"hard","style":"acer","q":"In a 4×4 magic square where all rows, columns, and diagonals sum to 34, the top row is 16, 3, 2, 13. What must the bottom-left number be if the first column is 16, 5, 9, ___?","options":["4","10","11","14"],"answer":0,"exp":"Column 1 must sum to 34: 16 + 5 + 9 + x = 34 → x = 4.","hint":"All columns must sum to 34. Add the known values in the column and subtract from 34."},{"id":"q086","state":"VIC","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"hard","style":"hendersons","q":"Factorise: x² + 5x + 6","options":["(x+1)(x+6)","(x+2)(x+3)","(x+5)(x+1)","(x−2)(x−3)"],"answer":1,"exp":"Find two numbers that multiply to 6 and add to 5: 2 × 3 = 6, 2 + 3 = 5 ✓\nx² + 5x + 6 = (x+2)(x+3)","hint":"Find two numbers that multiply to 6 and add to 5."},{"id":"q087","state":"VIC","section":"vic_maths","grade":"selective","topic":"Number Theory","difficulty":"medium","style":"psle","q":"What is the highest common factor (HCF) of 36 and 48?","options":["6","8","12","24"],"answer":2,"exp":"Factors of 36: 1,2,3,4,6,9,12,18,36\nFactors of 48: 1,2,3,4,6,8,12,16,24,48\nHighest common = 12","hint":"List all factors of each number and find the largest one they share."},{"id":"q088","state":"VIC","section":"vic_maths","grade":"selective","topic":"Word Problems","difficulty":"hard","style":"psle","q":"There are only red and blue pens in a drawer. The ratio of red to blue is 2:3. If 4 red pens are added, the new ratio is 1:1. How many pens were there originally?","options":["20","25","30","40"],"answer":0,"exp":"Let red = 2k, blue = 3k.\nAfter adding 4 red: (2k+4)/(3k) = 1 → 2k+4 = 3k → k = 4.\nOriginal total = 2(4) + 3(4) = 8 + 12 = 20.","hint":"Let the original amounts be 2k and 3k. Set up an equation using the new ratio."},{"id":"q089","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Geometry","difficulty":"hard","style":"psle","q":"A square has area 64 cm². A circle is drawn inside it, touching all four sides. What is the area of the circle? (π ≈ 3.14)","options":["50.24 cm²","64 cm²","100.48 cm²","201 cm²"],"answer":0,"exp":"Square side = √64 = 8 cm. Circle diameter = 8 cm, radius = 4 cm.\nArea = π × r² = 3.14 × 16 = 50.24 cm²","hint":"If the circle touches all four sides, its diameter equals the side length of the square."},{"id":"q090","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"hard","style":"hendersons","q":"Find the missing term:\n2, 6, 12, 20, 30, ___","options":["36","40","42","44"],"answer":2,"exp":"Differences: 4, 6, 8, 10, 12...\nThe differences increase by 2 each time.\n30 + 12 = 42","hint":"Look at the differences between consecutive terms. Do those differences follow a pattern?"},{"id":"q091","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"medium","style":"acer","q":"An 'enigma' is:","options":["A type of musical instrument","A mysterious or puzzling person or thing","A formal ceremony","An ancient monument"],"answer":1,"exp":"Enigma = something difficult to understand or explain; a mystery.\nFamous use: the Enigma machine (WWII codebreaker).","hint":"You might know the phrase 'wrapped in an enigma' — what would that mean?"},{"id":"q092","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Coding","difficulty":"hard","style":"acer","q":"In a code, A=1, B=3, C=5, D=7... (odd numbers in order).\nWhat is the code for the word CAB?","options":["5-1-3","3-1-5","5-3-1","1-3-5"],"answer":0,"exp":"A=1, B=3, C=5.\nCAB = C(5), A(1), B(3) = 5-1-3.","hint":"Map each letter to its odd number (A=1st odd, B=2nd odd, C=3rd odd...)."},{"id":"q093","state":"VIC","section":"vic_maths","grade":"selective","topic":"Data Interpretation","difficulty":"medium","style":"acer","q":"A bar graph shows monthly rainfall. Jan=45mm, Feb=30mm, Mar=60mm, Apr=55mm. What is the mean monthly rainfall for these four months?","options":["42.5 mm","45 mm","47.5 mm","50 mm"],"answer":2,"exp":"Mean = (45 + 30 + 60 + 55) ÷ 4 = 190 ÷ 4 = 47.5 mm","hint":"Add all values, divide by the count."},{"id":"q094","state":"VIC","section":"vic_reading","grade":"selective","topic":"Inference","difficulty":"hard","style":"contour","q":"Read: 'The council approved the development unanimously. The chairperson smiled. The protestors outside fell silent.'\n\nWhat can we MOST reasonably infer?","options":["The protestors were happy with the decision","The protestors were against the development","The chairperson was surprised","The council was divided"],"answer":1,"exp":"Protestors 'fell silent' after an unfavourable decision — silence here likely signals defeat or disappointment, not approval.\nThe contrast between the chairperson's smile and the protestors' silence implies they had opposing views.","hint":"Why would protestors 'fall silent'? Consider the contrast with the chairperson's smile."},{"id":"q095","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"medium","style":"acer","q":"All squares are rectangles. Some rectangles are rhombuses. Jake draws a square. Which MUST be true?","options":["Jake's shape is a rhombus","Jake's shape is a rectangle","Jake's shape is only a square","Jake's shape has unequal sides"],"answer":1,"exp":"All squares are rectangles (given) → Jake's square must be a rectangle.\nWe cannot conclude it's a rhombus — only SOME rectangles are rhombuses.","hint":"Follow the logical chain: square → rectangle. Does this tell us about rhombus?"},{"id":"q096","state":"VIC","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"hard","style":"hendersons","q":"The difference between two numbers is 8. Their product is 84. What are the numbers?","options":["6 and 14","7 and 15","8 and 16","10 and 18"],"answer":0,"exp":"Let numbers be n and n+8.\nn(n+8) = 84 → n² + 8n − 84 = 0 → (n+14)(n−6) = 0 → n = 6.\nNumbers: 6 and 14. Check: 14−6=8 ✓ and 6×14=84 ✓","hint":"Call the smaller number n and the larger n+8. Multiply them and set equal to 84."},{"id":"q097","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"medium","style":"acer","q":"NOVEL is to AUTHOR as PAINTING is to:","options":["Canvas","Paintbrush","Artist","Gallery"],"answer":2,"exp":"Relationship: creation → creator.\nAn author writes a novel. An artist paints a painting.","hint":"Who creates a painting?"},{"id":"q098","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Geometry","difficulty":"medium","style":"acer","q":"In a triangle, one angle is twice the second angle, and the third angle is 60°. What are the other two angles?","options":["40° and 80°","45° and 75°","50° and 70°","30° and 90°"],"answer":0,"exp":"Let second angle = x. First = 2x. Third = 60°.\n2x + x + 60 = 180 → 3x = 120 → x = 40°.\nAngles: 40°, 80°, 60°. Sum = 180° ✓","hint":"Let the second angle = x. Set up an equation using the angle sum = 180°."},{"id":"q099","state":"VIC","section":"vic_maths","grade":"selective","topic":"Number Theory","difficulty":"hard","style":"psle","q":"What is the smallest number that is divisible by both 8 and 12 but NOT by 9?","options":["24","36","48","72"],"answer":0,"exp":"LCM of 8 and 12 = 24.\n24 ÷ 9 = 2.67 (not divisible) ✓\nSo 24 is the answer.","hint":"Find the LCM of 8 and 12, then check divisibility by 9."},{"id":"q100","state":"VIC","section":"vic_reading","grade":"selective","topic":"Text Structure","difficulty":"medium","style":"contour","q":"Read: 'Firstly, exercise improves mood. Secondly, it builds strength. Finally, regular activity reduces disease risk.'\n\nThis text structure is best described as:","options":["Problem-solution","Cause-effect","Sequential/listing","Compare-contrast"],"answer":2,"exp":"The words 'firstly, secondly, finally' signal that ideas are being listed in sequence.\nThis is a listing or sequential structure.","hint":"Look at the signal words 'firstly, secondly, finally' — what do they tell you about the structure?"},{"id":"h001","state":"VIC","section":"vic_quant","grade":"selective","topic":"Grid Patterns","difficulty":"medium","style":"hendersons","q":"The numbers in this grid go together in a certain way.\n| 3 | 7 | 21 |\n| 4 | 9 | 36 |\n| 5 | 6 |  ? |\nWhat is the missing number?","options":["25","28","30","36"],"answer":2,"exp":"Rule: column 1 × column 2 = column 3.\n3×7=21 ✓  4×9=36 ✓  5×6=30 ✓","hint":"Look at how the numbers in each row relate to each other."},{"id":"h002","state":"VIC","section":"vic_quant","grade":"selective","topic":"Grid Patterns","difficulty":"medium","style":"hendersons","q":"The numbers in this grid go together in a certain way.\n| 2 | 5 | 3 |\n| 4 | 9 | 5 |\n| 6 | ? | 7 |\nWhat replaces the question mark?","options":["11","12","13","14"],"answer":2,"exp":"Rule: middle = left + right.\n2+3=5 ✓  4+5=9 ✓  6+7=13 ✓","hint":"Look at how the middle number relates to the two outer numbers in each row."},{"id":"h003","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"easy","style":"hendersons","q":"What is the missing number in this sequence?\n100, 91, 82, 73, ?, 55","options":["62","63","64","65"],"answer":2,"exp":"Subtract 9 each time:\n100−9=91, 91−9=82, 82−9=73, 73−9=64 ✓, 64−9=55 ✓","hint":"Find the difference between consecutive terms."},{"id":"h004","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"medium","style":"hendersons","q":"What is the missing number?\n3, 4, 7, 11, 18, ?, 47","options":["28","29","30","31"],"answer":1,"exp":"Each term = sum of the two previous (like Fibonacci):\n3+4=7, 4+7=11, 7+11=18, 11+18=29, 18+29=47 ✓","hint":"Try adding each pair of consecutive terms."},{"id":"h005","state":"VIC","section":"vic_quant","grade":"selective","topic":"Symbol Substitution","difficulty":"medium","style":"hendersons","q":"▲ + ▲ + ■ = 23\n▲ + ■ + ■ = 19\nWhat is the value of ▲?","options":["4","7","9","11"],"answer":2,"exp":"▲+▲+■=23, ▲+■+■=19.\nSubtract: ▲−■=4. From eq2: ▲+2■=19.\nSub ▲=■+4: 3■+4=19 → ■=5, ▲=9.\nCheck: 9+9+5=23 ✓ 9+5+5=19 ✓","hint":"Subtract one equation from the other to eliminate one shape."},{"id":"h006","state":"VIC","section":"vic_quant","grade":"selective","topic":"Symbol Substitution","difficulty":"hard","style":"hendersons","q":"● × ■ = 24   and   ● + ■ = 10   (assume ● > ■)\nWhat is ● − ■?","options":["1","2","3","4"],"answer":1,"exp":"Two numbers that multiply to 24 and add to 10: try 4 and 6.\n4×6=24 ✓  4+6=10 ✓\n● = 6, ■ = 4 → ● − ■ = 2","hint":"Find two numbers that multiply to 24 AND add to 10."},{"id":"h007","state":"VIC","section":"vic_maths","grade":"selective","topic":"Fractions","difficulty":"medium","style":"hendersons","q":"A school has 480 students. ⅜ play sport, and ¼ of those who play sport also play a musical instrument. How many students play both sport and an instrument?","options":["40","45","60","120"],"answer":1,"exp":"Students who play sport: ⅜ × 480 = 180\nOf those, ¼ play instrument: ¼ × 180 = 45","hint":"Find the number who play sport first, then find ¼ of that group."},{"id":"h008","state":"VIC","section":"vic_maths","grade":"selective","topic":"Percentage","difficulty":"medium","style":"hendersons","q":"A shop marks up an item by 40%, then offers a 20% sale discount. The final price is $84. What was the original price?","options":["$70","$75","$80","$90"],"answer":1,"exp":"Let original = P.\nAfter 40% markup: 1.4P\nAfter 20% discount: 1.4P × 0.8 = 1.12P\n1.12P = $84 → P = 84 ÷ 1.12 = $75","hint":"Work forwards: apply the markup, then the discount."},{"id":"h009","state":"VIC","section":"vic_maths","grade":"selective","topic":"Ratios","difficulty":"hard","style":"hendersons","q":"Concrete is made by mixing sand, gravel, and cement in the ratio 3:5:2. If 60 kg of gravel is used, how much sand is needed?","options":["24 kg","30 kg","36 kg","40 kg"],"answer":2,"exp":"Gravel = 5 parts = 60 kg → 1 part = 12 kg\nSand = 3 parts = 3 × 12 = 36 kg","hint":"Find the value of one 'part' using the gravel amount."},{"id":"h010","state":"VIC","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"hard","style":"hendersons","q":"Factorise and simplify:\n(x² − 9) ÷ (x + 3)","options":["x + 3","x − 3","x² − 3","3 − x"],"answer":1,"exp":"x² − 9 = (x+3)(x−3)  [difference of two squares]\n(x+3)(x−3) ÷ (x+3) = x − 3","hint":"Factorise the numerator. Do you recognise a² − b²?"},{"id":"h011","state":"VIC","section":"vic_maths","grade":"selective","topic":"Statistics","difficulty":"medium","style":"hendersons","q":"Seven students scored: 65, 72, 58, 80, 72, 91, 72. What is the mode?","options":["58","65","72","80"],"answer":2,"exp":"Mode = most frequent value.\n72 appears 3 times — more than any other score.","hint":"Mode = the value that appears most often."},{"id":"h012","state":"VIC","section":"vic_maths","grade":"selective","topic":"Statistics","difficulty":"medium","style":"hendersons","q":"The mean of 5 numbers is 14. Four of the numbers are 10, 12, 16, 18. What is the fifth number?","options":["12","14","16","18"],"answer":1,"exp":"Sum = 5 × 14 = 70\nSum of known four: 10+12+16+18 = 56\nFifth = 70 − 56 = 14","hint":"Find the total sum first (mean × count), then subtract what you know."},{"id":"h013","state":"VIC","section":"vic_maths","grade":"selective","topic":"Number Theory","difficulty":"medium","style":"hendersons","q":"What is the smallest number that gives a remainder of 2 when divided by both 5 and 7?","options":["2","37","72","107"],"answer":1,"exp":"Need n ≡ 2 (mod 5) and n ≡ 2 (mod 7).\nLCM(5,7)=35. Numbers giving rem 2 when ÷35: 2, 37, 72...\n37÷5=7 rem 2 ✓  37÷7=5 rem 2 ✓\nSmallest positive = 37","hint":"Find LCM of 5 and 7, then add the remainder."},{"id":"h014","state":"VIC","section":"vic_maths","grade":"selective","topic":"Geometry","difficulty":"medium","style":"hendersons","q":"A square has perimeter 48 cm. What is its area?","options":["100 cm²","120 cm²","144 cm²","196 cm²"],"answer":2,"exp":"Perimeter = 4 × side → side = 48÷4 = 12 cm\nArea = 12² = 144 cm²","hint":"Find the side length from the perimeter, then square it."},{"id":"h015","state":"VIC","section":"vic_maths","grade":"selective","topic":"Number Theory","difficulty":"medium","style":"hendersons","q":"A bus runs every 15 minutes. A train runs every 10 minutes. Both depart together at 8:00 AM. When do they next depart together?","options":["8:20 AM","8:30 AM","8:45 AM","9:00 AM"],"answer":1,"exp":"LCM(15, 10) = 30 minutes\nNext joint departure: 8:00 AM + 30 min = 8:30 AM","hint":"Find the LCM of the two intervals."},{"id":"h016","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Ordering","difficulty":"medium","style":"hendersons","q":"Five friends — Ali, Ben, Cara, Dan, Eva — sit in a row.\n• Ben sits between Cara and Dan.\n• Ali sits next to Cara but not Dan.\n• Eva is at one end.\nWhat position is Ali in?","options":["1st","2nd","3rd","4th"],"answer":1,"exp":"Eva is at one end (position 1 or 5).\nBen between Cara and Dan: C−B−D or D−B−C.\nAli next to Cara, not Dan.\nOne valid order: Eva, Ali, Cara, Ben, Dan.\nAli is in position 2.","hint":"Start with Eva at one end, then use each constraint to place people."},{"id":"h017","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"hard","style":"hendersons","q":"All musicians can read music. Some readers of music cannot play an instrument. Priya reads music.\nWhich MUST be true?","options":["Priya is a musician","Priya can play an instrument","Priya might not be a musician","Priya cannot play an instrument"],"answer":2,"exp":"Reading music does NOT mean you are a musician — the rule says musicians can read music, not the reverse.\nSo Priya might or might not be a musician.","hint":"Does reading music guarantee being a musician? Check the direction of the rule."},{"id":"h018","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"hard","style":"hendersons","q":"OBLIVIOUS is to AWARE as FRUGAL is to:","options":["Generous","Thrifty","Careful","Poor"],"answer":0,"exp":"Oblivious (unaware) ↔ Aware — antonyms.\nFrugal (careful with money) ↔ Generous — antonyms.","hint":"Oblivious and aware are opposites. What is the opposite of frugal?"},{"id":"h019","state":"VIC","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"medium","style":"hendersons","q":"If a + b = 7 and a² + b² = 29, what is ab?","options":["5","10","15","20"],"answer":1,"exp":"(a+b)² = a² + 2ab + b²\n7² = 29 + 2ab\n49 = 29 + 2ab\n2ab = 20\nab = 10","hint":"Use the identity (a+b)² = a² + 2ab + b²."},{"id":"h020","state":"VIC","section":"vic_maths","grade":"selective","topic":"Coordinate Geometry","difficulty":"medium","style":"hendersons","q":"The midpoint of a line segment joining A(2, 4) and B(8, 10) is:","options":["(4, 6)","(5, 7)","(6, 8)","(3, 5)"],"answer":1,"exp":"Midpoint = ((2+8)/2, (4+10)/2) = (5, 7)","hint":"Midpoint = (average of x-coords, average of y-coords)."},{"id":"p001","state":"VIC","section":"vic_maths","grade":"selective","topic":"Word Problems","difficulty":"medium","style":"psle","q":"Ali saved $120 and Ben saved $80. Ali spent ½ of his savings and Ben spent ¼ of his. How much did they have altogether after spending?","options":["$80","$100","$120","$140"],"answer":2,"exp":"Ali remaining: 120 × ½ = $60\nBen remaining: 80 × ¾ = $60\nTotal = $60 + $60 = $120","hint":"Calculate what each person spent, then find what remains."},{"id":"p002","state":"VIC","section":"vic_maths","grade":"selective","topic":"Word Problems","difficulty":"hard","style":"psle","q":"A group of children share some stickers. If each child gets 5, there are 8 left over. If each child gets 7, they need 4 more. How many children are there?","options":["4","5","6","7"],"answer":2,"exp":"Let n = children, s = total stickers.\ns = 5n + 8  and  s = 7n − 4\n5n + 8 = 7n − 4 → 2n = 12 → n = 6","hint":"Set up two equations for the number of stickers."},{"id":"p003","state":"VIC","section":"vic_maths","grade":"selective","topic":"Fractions","difficulty":"medium","style":"psle","q":"In a school, ⅖ of students are in Year 4 and below. ¾ of the remaining students are in Year 5. What fraction of the school is in Year 5?","options":["3/10","9/20","3/5","7/20"],"answer":1,"exp":"Remaining after Year 4: 1 − ⅖ = 3/5\nYear 5 = ¾ × 3/5 = 9/20","hint":"Find the remaining fraction first, then take ¾ of that."},{"id":"p004","state":"VIC","section":"vic_maths","grade":"selective","topic":"Ratios","difficulty":"hard","style":"psle","q":"The ratio of Tom's cards to Sara's cards is 3:5. Tom gives Sara 12 cards and the ratio becomes 1:3. How many cards did Tom start with?","options":["30","36","45","54"],"answer":1,"exp":"Let Tom = 3k, Sara = 5k.\nAfter transfer: (3k−12)/(5k+12) = 1/3\n3(3k−12) = 5k+12\n9k − 36 = 5k + 12\n4k = 48 → k = 12\nTom's original = 3 × 12 = 36","hint":"Let the original amounts be 3k and 5k. Write the new ratio as an equation."},{"id":"p005","state":"VIC","section":"vic_maths","grade":"selective","topic":"Speed & Distance","difficulty":"hard","style":"psle","q":"Train A leaves at 8:00 AM at 90 km/h. Train B leaves at 9:30 AM on the same route at 120 km/h. At what time does Train B overtake Train A?","options":["11:30 AM","12:30 PM","1:30 PM","2:00 PM"],"answer":3,"exp":"Train A head start: 1.5 hr × 90 km/h = 135 km\nB gains at: 120−90 = 30 km/h\nTime to close gap: 135 ÷ 30 = 4.5 hrs after B departs\n9:30 AM + 4.5 hrs = 2:00 PM","hint":"Find how far ahead Train A is when B departs, then calculate how fast B closes that gap."},{"id":"p006","state":"VIC","section":"vic_maths","grade":"selective","topic":"Age Problems","difficulty":"medium","style":"psle","q":"Mum is 4 times as old as her daughter now. In 6 years, she will be 3 times as old. How old is the daughter now?","options":["6","8","10","12"],"answer":3,"exp":"Let daughter = d, mum = 4d.\nIn 6 years: 4d+6 = 3(d+6)\n4d+6 = 3d+18\nd = 12","hint":"Set up an equation for 'in 6 years'."},{"id":"p007","state":"VIC","section":"vic_maths","grade":"selective","topic":"Word Problems","difficulty":"hard","style":"psle","q":"A tank is ⅔ full. After 30 litres are removed, it is ½ full. What is the full capacity of the tank?","options":["90 L","120 L","150 L","180 L"],"answer":3,"exp":"⅔ − ½ = 4/6 − 3/6 = 1/6 of tank = 30 litres\nFull tank = 30 × 6 = 180 litres","hint":"The 30 litres represents the difference between ⅔ and ½ of the full tank."},{"id":"p008","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Coins & Money","difficulty":"hard","style":"psle","q":"Lena has only 50c and 20c coins. She has 18 coins worth $6.60 in total. How many 50c coins does she have?","options":["8","9","10","11"],"answer":2,"exp":"Let f = number of 50c coins, t = number of 20c coins.\nf + t = 18  and  0.5f + 0.2t = 6.6\nt = 18−f → 0.5f + 0.2(18−f) = 6.6\n0.5f + 3.6 − 0.2f = 6.6\n0.3f = 3 → f = 10","hint":"Set up two equations: one for the number of coins, one for the total value."},{"id":"p009","state":"VIC","section":"vic_maths","grade":"selective","topic":"Percentage","difficulty":"hard","style":"psle","q":"A salesperson earns 5% commission on sales. Last month she earned $2,250 in commission. Her sales increased by 20% this month. How much commission this month?","options":["$2,450","$2,600","$2,700","$2,800"],"answer":2,"exp":"Last month sales: $2,250 ÷ 0.05 = $45,000\nThis month: $45,000 × 1.20 = $54,000\nCommission: $54,000 × 0.05 = $2,700","hint":"Find last month's total sales first, then increase by 20%."},{"id":"p010","state":"VIC","section":"vic_maths","grade":"selective","topic":"Area","difficulty":"hard","style":"psle","q":"A rectangular room is 12 m × 9 m. Tiles measuring 0.5 m × 0.5 m cover the floor. How many tiles are needed?","options":["216","324","432","864"],"answer":2,"exp":"Area of room = 12 × 9 = 108 m²\nArea per tile = 0.5 × 0.5 = 0.25 m²\nTiles = 108 ÷ 0.25 = 432","hint":"Find the total area and the area of one tile, then divide."},{"id":"p011","state":"VIC","section":"vic_maths","grade":"selective","topic":"Geometry","difficulty":"medium","style":"psle","q":"A triangle has base 14 cm and height 9 cm. A rectangle with the same area is 7 cm wide. What is its length?","options":["7 cm","9 cm","14 cm","18 cm"],"answer":1,"exp":"Triangle area = ½ × 14 × 9 = 63 cm²\nRectangle: 63 = 7 × length → length = 9 cm","hint":"Find the triangle's area first, then use it for the rectangle."},{"id":"p012","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Algebra","difficulty":"medium","style":"psle","q":"When a number is multiplied by 6 and 15 is added, the result equals multiplying the number by 9 and subtracting 6. What is the number?","options":["5","7","9","11"],"answer":1,"exp":"6n + 15 = 9n − 6\n15 + 6 = 9n − 6n\n21 = 3n\nn = 7","hint":"Set up an equation with n as the unknown number."},{"id":"p013","state":"VIC","section":"vic_maths","grade":"selective","topic":"Number Theory","difficulty":"hard","style":"psle","q":"A number has exactly 3 factors. Which could it be?","options":["16","25","36","12"],"answer":1,"exp":"A number with exactly 3 factors must be the square of a prime (p²): factors are 1, p, p².\n25 = 5² → factors: 1, 5, 25 ✓\n16 = 2⁴ → 5 factors","hint":"What kind of numbers have exactly 3 factors?"},{"id":"p014","state":"VIC","section":"vic_maths","grade":"selective","topic":"Geometry","difficulty":"medium","style":"psle","q":"Two parallel lines are cut by a transversal. One co-interior angle is 73°. What is the other co-interior angle?","options":["73°","107°","117°","180°"],"answer":1,"exp":"Co-interior angles between parallel lines add to 180°.\n180° − 73° = 107°","hint":"Co-interior angles always add to 180°."},{"id":"p015","state":"VIC","section":"vic_maths","grade":"selective","topic":"Number Theory","difficulty":"hard","style":"psle","q":"The sum of digits of a 2-digit number is 11. If digits are reversed, the new number is 27 more. What is the original number?","options":["38","47","56","29"],"answer":1,"exp":"Let digits be a and b: a+b=11, (10b+a)−(10a+b)=27\n9(b−a)=27 → b−a=3\na+b=11 and b=a+3: 2a=8 → a=4, b=7\nOriginal = 47","hint":"Set up two equations: one for digit sum, one for the reversed number."},{"id":"j001","state":"VIC","section":"vic_reading","grade":"selective","topic":"Comprehension","difficulty":"easy","style":"james_ann","q":"Read:\n\"The platypus is one of only five species of monotreme — mammals that lay eggs. Found only in eastern Australia and Tasmania, it hunts underwater using electroreception: tiny pores in its bill detect the electrical signals produced by the muscles of its prey. Unlike most mammals, the platypus has no teeth; it grinds food between horny pads. Males carry a venomous spur on their hind legs — one of the very few venomous mammals. Early European scientists who received platypus specimens believed they were a hoax.\"\n\nWhat method does the platypus use to locate its prey?","options":["Echolocation","Electroreception","Sight","Smell"],"answer":1,"exp":"The passage directly states 'it hunts underwater using electroreception'.\nThis is a literal retrieval question.","hint":"Look for the exact words describing how the platypus finds its prey."},{"id":"j002","state":"VIC","section":"vic_reading","grade":"selective","topic":"Vocabulary in Context","difficulty":"medium","style":"james_ann","q":"Read:\n\"The platypus is one of only five species of monotreme — mammals that lay eggs. Found only in eastern Australia and Tasmania, it hunts underwater using electroreception: tiny pores in its bill detect the electrical signals produced by the muscles of its prey. Unlike most mammals, the platypus has no teeth; it grinds food between horny pads. Males carry a venomous spur on their hind legs — one of the very few venomous mammals. Early European scientists who received platypus specimens believed they were a hoax.\"\n\nWhat does 'monotreme' most likely mean based on the passage?","options":["A venomous animal","A mammal that lays eggs","An Australian animal","An animal with no teeth"],"answer":1,"exp":"The passage defines monotremes as 'mammals that lay eggs' immediately after the term.","hint":"The passage defines the word right after it uses it."},{"id":"j003","state":"VIC","section":"vic_reading","grade":"selective","topic":"Inference","difficulty":"hard","style":"james_ann","q":"Read:\n\"The platypus is one of only five species of monotreme — mammals that lay eggs. Found only in eastern Australia and Tasmania, it hunts underwater using electroreception: tiny pores in its bill detect the electrical signals produced by the muscles of its prey. Unlike most mammals, the platypus has no teeth; it grinds food between horny pads. Males carry a venomous spur on their hind legs — one of the very few venomous mammals. Early European scientists who received platypus specimens believed they were a hoax.\"\n\nWhy did early European scientists believe the platypus specimens were a hoax?","options":["They had never visited Australia","The platypus had so many unusual features they seemed impossible to combine in one animal","They distrusted Australian scientists","The specimen was damaged in transit"],"answer":1,"exp":"The passage lists the platypus's extraordinary features: egg-laying mammal, electroreception, no teeth, venomous spur.\nWe must INFER that these combined features seemed too extraordinary to believe.","hint":"What unusual features are described? Why would these make scientists doubtful?"},{"id":"j004","state":"VIC","section":"vic_reading","grade":"selective","topic":"Author's Craft","difficulty":"hard","style":"james_ann","q":"Read:\n\"The platypus is one of only five species of monotreme — mammals that lay eggs. Found only in eastern Australia and Tasmania, it hunts underwater using electroreception: tiny pores in its bill detect the electrical signals produced by the muscles of its prey. Unlike most mammals, the platypus has no teeth; it grinds food between horny pads. Males carry a venomous spur on their hind legs — one of the very few venomous mammals. Early European scientists who received platypus specimens believed they were a hoax.\"\n\nWhy does the author save the fact about scientists thinking the platypus was a hoax for the final sentence?","options":["To confuse the reader","To create dramatic irony — we now know it's real, yet experts once doubted it","To show scientists are unreliable","To end with an unimportant detail"],"answer":1,"exp":"Leaving the 'hoax' fact last creates a satisfying irony: after reading all the real facts,\nwe learn that experts doubted its existence. This is a deliberate structural choice for impact.","hint":"Why would an author leave something surprising for the very last sentence?"},{"id":"j005","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Main Idea","difficulty":"medium","style":"james_ann","q":"Read:\n\"For decades, scientists dismissed dark matter as theoretical. Then, in 1978, astronomer Vera Rubin published data showing that galaxies rotate in ways that cannot be explained by visible matter alone — the outer edges spin just as fast as the inner regions, defying Newton's laws. Something invisible must be holding galaxies together. Rubin's work, ignored during her lifetime by the Nobel Committee, has since been called the most important astronomical discovery of the twentieth century.\"\n\nWhat is the main idea of this passage?","options":["Dark matter has been proven to exist","Vera Rubin's evidence for dark matter was groundbreaking but underrecognised","Newton's laws are wrong","Galaxies spin at the same speed throughout"],"answer":1,"exp":"The passage covers both the scientific discovery AND the fact that she was overlooked.\nThe main idea captures both dimensions.","hint":"Which option captures BOTH what she discovered AND what happened to her recognition?"},{"id":"j006","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Inference","difficulty":"hard","style":"james_ann","q":"Read:\n\"For decades, scientists dismissed dark matter as theoretical. Then, in 1978, astronomer Vera Rubin published data showing that galaxies rotate in ways that cannot be explained by visible matter alone — the outer edges spin just as fast as the inner regions, defying Newton's laws. Something invisible must be holding galaxies together. Rubin's work, ignored during her lifetime by the Nobel Committee, has since been called the most important astronomical discovery of the twentieth century.\"\n\nWhat does 'ignored during her lifetime by the Nobel Committee' most strongly suggest?","options":["Her work was unimportant","She was not a real scientist","Her contribution was not properly recognised despite its significance","She chose not to accept the Nobel Prize"],"answer":2,"exp":"Being ignored for the Nobel Prize despite doing 'the most important astronomical discovery'\nof the century implies her contribution was not properly recognised.","hint":"If the work was later called the most important discovery of the century, what does being ignored imply?"},{"id":"j007","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Vocabulary","difficulty":"medium","style":"james_ann","q":"Read:\n\"For decades, scientists dismissed dark matter as theoretical. Then, in 1978, astronomer Vera Rubin published data showing that galaxies rotate in ways that cannot be explained by visible matter alone — the outer edges spin just as fast as the inner regions, defying Newton's laws. Something invisible must be holding galaxies together. Rubin's work, ignored during her lifetime by the Nobel Committee, has since been called the most important astronomical discovery of the twentieth century.\"\n\nIn context, 'defying' most closely means:","options":["Supporting","Contradicting","Explaining","Extending"],"answer":1,"exp":"Galaxy rotation 'defying Newton's laws' = contradicting or going against those laws.","hint":"If something 'defies' a law, does it support it or contradict it?"},{"id":"j008","state":"VIC","section":"vic_reading","grade":"selective","topic":"Tone & Attitude","difficulty":"hard","style":"james_ann","q":"Read:\n\"For decades, scientists dismissed dark matter as theoretical. Then, in 1978, astronomer Vera Rubin published data showing that galaxies rotate in ways that cannot be explained by visible matter alone — the outer edges spin just as fast as the inner regions, defying Newton's laws. Something invisible must be holding galaxies together. Rubin's work, ignored during her lifetime by the Nobel Committee, has since been called the most important astronomical discovery of the twentieth century.\"\n\nThe author's tone when writing about the Nobel Committee can best be described as:","options":["Neutral and factual","Implicitly critical and disapproving","Sympathetic towards the committee","Celebratory"],"answer":1,"exp":"'Ignored during her lifetime' paired with 'most important discovery of the century' creates an implied contrast.\nThe author is not neutral — there is implicit criticism of the committee.","hint":"Look at word choices: 'ignored', 'most important discovery'. What feeling does this contrast create?"},{"id":"j009","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Comprehension","difficulty":"easy","style":"james_ann","q":"Read:\n\"The Great Pacific Garbage Patch — a vast swirl of plastic debris in the North Pacific Ocean — is not a solid island of rubbish, as often depicted. It consists mostly of microplastics: tiny fragments invisible to the naked eye, suspended throughout the water column. These particles are consumed by marine creatures, entering the food chain. Scientists estimate it contains over 80,000 tonnes of plastic, but cleaning it remains a formidable challenge because the particles are too fine to be filtered without also capturing plankton — the foundation of the ocean food web.\"\n\nWhy is cleaning the garbage patch difficult?","options":["The area is too dangerous for ships","Filtering particles would also capture plankton","The plastic is too heavy to collect","The location is unknown"],"answer":1,"exp":"The passage directly states: 'too fine to be filtered without also capturing plankton'.","hint":"Look for the sentence explaining WHY cleaning is a 'formidable challenge'."},{"id":"j010","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Inference","difficulty":"hard","style":"james_ann","q":"Read:\n\"The Great Pacific Garbage Patch — a vast swirl of plastic debris in the North Pacific Ocean — is not a solid island of rubbish, as often depicted. It consists mostly of microplastics: tiny fragments invisible to the naked eye, suspended throughout the water column. These particles are consumed by marine creatures, entering the food chain. Scientists estimate it contains over 80,000 tonnes of plastic, but cleaning it remains a formidable challenge because the particles are too fine to be filtered without also capturing plankton — the foundation of the ocean food web.\"\n\nThe author corrects the popular image of the garbage patch. What does this imply about public understanding?","options":["The public fully understands the problem","A widespread misconception may make the problem harder to grasp and address","Scientists have misled the public intentionally","The problem is less serious than reported"],"answer":1,"exp":"By contradicting the 'often depicted' solid island image, the author reveals a widespread misconception.\nIf people picture something solid, they may not grasp the invisible nature of microplastics.","hint":"If the common depiction is wrong, what does that tell us about how people understand the issue?"},{"id":"j011","state":"VIC","section":"vic_reading","grade":"selective","topic":"Text Structure","difficulty":"medium","style":"james_ann","q":"Read:\n\"The Great Pacific Garbage Patch — a vast swirl of plastic debris in the North Pacific Ocean — is not a solid island of rubbish, as often depicted. It consists mostly of microplastics: tiny fragments invisible to the naked eye, suspended throughout the water column. These particles are consumed by marine creatures, entering the food chain. Scientists estimate it contains over 80,000 tonnes of plastic, but cleaning it remains a formidable challenge because the particles are too fine to be filtered without also capturing plankton — the foundation of the ocean food web.\"\n\nWhat text structure does the author primarily use?","options":["Chronological narrative","Problem with layered complications","Compare and contrast","Argument and rebuttal"],"answer":1,"exp":"The passage: identifies the garbage patch → complicates it (it's microplastics, not solid)\n→ further complicates the solution (can't filter without harming plankton).\nThis is a problem + complication structure.","hint":"Is the passage telling a story, comparing things, or building on a problem?"},{"id":"j012","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Comprehension","difficulty":"easy","style":"james_ann","q":"Read:\n\"Bees communicate the location of flowers through the 'waggle dance'. The dancer traces a figure-eight pattern while vibrating its abdomen. The angle of the straight middle run indicates direction relative to the sun. The duration of the waggle indicates distance: a 1-second waggle means roughly 1 kilometre. Karl von Frisch decoded this language in the 1940s and was awarded the Nobel Prize in Physiology in 1973.\"\n\nWhat does the duration of the waggle dance indicate?","options":["The type of flower","The direction to fly","The distance to travel","The quality of nectar"],"answer":2,"exp":"Passage states: 'The duration of the waggle indicates the distance'. Literal retrieval.","hint":"Find the sentence that directly explains what duration tells the bees."},{"id":"j013","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Inference","difficulty":"medium","style":"james_ann","q":"Read:\n\"Bees communicate the location of flowers through the 'waggle dance'. The dancer traces a figure-eight pattern while vibrating its abdomen. The angle of the straight middle run indicates direction relative to the sun. The duration of the waggle indicates distance: a 1-second waggle means roughly 1 kilometre. Karl von Frisch decoded this language in the 1940s and was awarded the Nobel Prize in Physiology in 1973.\"\n\nThe passage mentions that von Frisch was awarded the Nobel Prize. What does this suggest about his work?","options":["He discovered bees","Decoding bee communication was considered a major scientific achievement","The Nobel Prize is given only for animal research","He invented the waggle dance"],"answer":1,"exp":"The Nobel Prize is the world's most prestigious science award.\nReceiving it implies his work was of the highest scientific significance.","hint":"What does receiving the Nobel Prize generally imply about someone's work?"},{"id":"j014","state":"VIC","section":"vic_reading","grade":"selective","topic":"Comprehension","difficulty":"easy","style":"james_ann","q":"Read:\n\"Until the 1970s, doctors routinely told patients with stomach ulcers that stress and spicy food were to blame. Then two Australian scientists — Barry Marshall and Robin Warren — proposed that ulcers were caused by a bacterium called Helicobacter pylori. The medical establishment rejected the idea; bacteria were thought unable to survive stomach acid. To prove his case, Marshall famously drank a solution containing H. pylori, developed gastritis within days, and cured himself with antibiotics. In 2005, Marshall and Warren received the Nobel Prize in Physiology or Medicine.\"\n\nWhat was the accepted medical view about ulcers before Marshall and Warren's discovery?","options":["Bacteria caused ulcers","Stress and spicy food caused ulcers","Ulcers were incurable","Antibiotics caused ulcers"],"answer":1,"exp":"The passage directly states 'doctors routinely told patients... stress and spicy food were to blame'.","hint":"Look for what doctors believed BEFORE the discovery."},{"id":"j015","state":"VIC","section":"vic_reading","grade":"selective","topic":"Inference","difficulty":"hard","style":"james_ann","q":"Read:\n\"Until the 1970s, doctors routinely told patients with stomach ulcers that stress and spicy food were to blame. Then two Australian scientists — Barry Marshall and Robin Warren — proposed that ulcers were caused by a bacterium called Helicobacter pylori. The medical establishment rejected the idea; bacteria were thought unable to survive stomach acid. To prove his case, Marshall famously drank a solution containing H. pylori, developed gastritis within days, and cured himself with antibiotics. In 2005, Marshall and Warren received the Nobel Prize in Physiology or Medicine.\"\n\nWhy did Marshall drink the H. pylori solution himself?","options":["He was careless","He wanted to prove the bacterial cause beyond doubt when others wouldn't believe him","He had no other way to obtain the bacteria","He was testing whether he was immune"],"answer":1,"exp":"'The medical establishment rejected the idea' — Marshall had to provide dramatic, undeniable proof.\nDrinking the solution and then curing himself with antibiotics was a deliberate act of scientific demonstration.","hint":"Why would a scientist take such a risk? What did he need to prove, and to whom?"},{"id":"c001","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Argument Analysis","difficulty":"hard","style":"contour","q":"Sam says: 'Our school has produced 3 Olympic athletes. Other schools produce almost none. Therefore our training program is the reason.'\nWhat is the main flaw?","options":["The comparison is unfair","Other explanations haven't been ruled out (talent, family support, etc.)","Olympic athletes are too rare to study","3 is not enough data"],"answer":1,"exp":"Correlation ≠ causation. The training program might be responsible,\nbut other factors (naturally talented individuals happened to attend, parental support, etc.) haven't been ruled out.","hint":"Even if the school has more Olympians, does that prove the training program is the cause?"},{"id":"c002","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Argument Analysis","difficulty":"hard","style":"contour","q":"A politician says: 'Crime has fallen every year since we installed CCTV cameras. The cameras are working.'\nWhat assumption is this making?","options":["CCTV cameras are expensive","The cameras caused the drop in crime, not some other factor","All criminals avoid cameras","Crime statistics are always accurate"],"answer":1,"exp":"The argument assumes cameras caused the drop. But the fall could be due to other factors:\neconomic improvement, more police, demographic change. This is the correlation-causation fallacy.","hint":"Just because B followed A, does A necessarily cause B?"},{"id":"c003","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Necessary & Sufficient","difficulty":"hard","style":"contour","q":"Statement: 'You can enter the club only if you are a member.'\nA person IS a member. Can they definitely enter?","options":["Yes, definitely","Not necessarily — membership is required but may not be the only condition","No — members cannot enter","Yes, if they pay a fee"],"answer":1,"exp":"'Only if you are a member' makes membership NECESSARY (you can't enter without it).\nBut it doesn't say membership ALONE is sufficient — other conditions may also apply.","hint":"Is membership necessary, sufficient, or both? Read the statement very carefully."},{"id":"c004","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Flawed Reasoning","difficulty":"hard","style":"contour","q":"Emma argues: 'My friend stopped eating gluten and her headaches disappeared. Therefore, gluten causes headaches.'\nWhat is the main flaw?","options":["Headaches are not serious","One case is insufficient to establish a general causal claim","Gluten is harmless","Her friend may be wrong"],"answer":1,"exp":"One personal example (anecdote) cannot establish a general causal claim.\nMany variables change when someone changes their diet.","hint":"Can one example prove a general rule for everyone?"},{"id":"c005","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Circular Reasoning","difficulty":"hard","style":"contour","q":"Which is an example of circular reasoning?","options":["All cats are mammals because mammals are animals","The book must be good because it's a bestseller","We should trust the newspaper because the newspaper says it is trustworthy","Exercise is healthy because doctors recommend it"],"answer":2,"exp":"Circular reasoning uses the conclusion as its own evidence:\n'Trust the newspaper because the newspaper says so.' The evidence IS the claim.","hint":"Which option uses the thing being proven as proof of itself?"},{"id":"c006","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Deduction","difficulty":"hard","style":"contour","q":"No reptiles are warm-blooded. All dinosaurs were reptiles. Rex is a dinosaur.\nWhich MUST be true?","options":["Rex is warm-blooded","Rex is not warm-blooded","Rex might be warm-blooded","Rex is not a reptile"],"answer":1,"exp":"No reptiles → warm-blooded. Rex is a reptile. Therefore Rex is NOT warm-blooded.\n(Within these premises — setting aside modern science's reclassification.)","hint":"Follow the chain: reptile → not warm-blooded. Rex is a reptile. Therefore...?"},{"id":"c007","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Argument Strength","difficulty":"hard","style":"contour","q":"Which evidence BEST supports: 'Regular reading improves vocabulary'?","options":["One child who reads a lot has a large vocabulary","A study of 10,000 children shows reading hours correlate with vocabulary size","Teachers say reading is important","Some books have complex words"],"answer":1,"exp":"A large, controlled study across 10,000 subjects is the strongest evidence.\nSingle cases (anecdotes) and authority opinions are weaker forms.","hint":"Which type of evidence is most reliable for establishing a general claim?"},{"id":"c008","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Logical Deduction","difficulty":"hard","style":"contour","q":"Every student who wins the prize has studied for more than 100 hours.\nLucy studied for 120 hours.\nWhich conclusion follows?","options":["Lucy will win the prize","Lucy has met a necessary condition for winning","Lucy studied more than any other student","Lucy is guaranteed to win"],"answer":1,"exp":"Studying 100+ hours is necessary but may not be sufficient for winning.\nLucy meets this condition, but other conditions may also be needed.","hint":"Is studying 100+ hours necessary, sufficient, or both for winning?"},{"id":"c009","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Analogy","difficulty":"hard","style":"contour","q":"HYPOTHESIS is to EXPERIMENT as QUESTION is to:","options":["Answer","Research","Theory","Evidence"],"answer":1,"exp":"A hypothesis leads to an experiment (to test it).\nA question leads to research (to answer it).\nBoth involve moving from uncertainty to a method of investigation.","hint":"What do scientists do after forming a hypothesis?"},{"id":"c010","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Argument Analysis","difficulty":"hard","style":"contour","q":"'Students who eat breakfast perform better at school. Therefore, schools should provide free breakfast.'\nWhat assumption does this argument make?","options":["Breakfast is expensive","Providing breakfast would cause the improvement in performance","All students skip breakfast","Schools have canteens"],"answer":1,"exp":"The argument assumes: if eating breakfast correlates with better performance,\nthen PROVIDING breakfast will CAUSE that improvement.\nThis assumes the correlation is causal and that the school breakfast would have the same effect.","hint":"What must be true for the recommendation to follow from the evidence?"},{"id":"a001","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"medium","style":"acer","q":"MARATHON is to RUNNING as VELODROME is to:","options":["Swimming","Cycling","Rowing","Athletics"],"answer":1,"exp":"A marathon is a long-distance running event.\nA velodrome is an arena/track for cycling.","hint":"What sport takes place in a velodrome?"},{"id":"a002","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"hard","style":"acer","q":"MYOPIA is to SIGHT as TINNITUS is to:","options":["Touch","Taste","Hearing","Smell"],"answer":2,"exp":"Myopia (short-sightedness) affects sight.\nTinnitus (ringing in the ears) affects hearing.","hint":"What sense does tinnitus affect?"},{"id":"a003","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Classification","difficulty":"medium","style":"acer","q":"Which does NOT belong?\nClarinet · Oboe · Trumpet · Bassoon","options":["Clarinet","Oboe","Trumpet","Bassoon"],"answer":2,"exp":"Clarinet, Oboe, Bassoon are all woodwind instruments.\nTrumpet is a brass instrument.","hint":"Think about which family of instruments each belongs to."},{"id":"a004","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"hard","style":"acer","q":"PERSPICACIOUS most closely means:","options":["Tired and listless","Having a ready insight; shrewd","Overly confident","Clumsy"],"answer":1,"exp":"Perspicacious = having a ready insight into things; shrewd, discerning.\nFrom Latin perspicax (seeing through clearly).","hint":"The root 'perspic-' relates to seeing clearly."},{"id":"a005","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"hard","style":"acer","q":"EQUIVOCATE most closely means:","options":["To agree strongly","To use ambiguous language to avoid commitment","To calculate precisely","To speak loudly"],"answer":1,"exp":"Equivocate = use ambiguous language to avoid committing to a position.\nFrom Latin: aequi (equal) + vox (voice) — speaking both ways.","hint":"Think of 'equal voices' — speaking in a way that could mean two things."},{"id":"a006","state":"VIC","section":"vic_quant","grade":"selective","topic":"Spatial Reasoning","difficulty":"hard","style":"acer","q":"How many faces does a triangular prism have?","options":["3","4","5","6"],"answer":2,"exp":"2 triangular faces (top and bottom)\n3 rectangular faces (sides)\nTotal = 5 faces","hint":"Count the triangular ends and the rectangular sides."},{"id":"a007","state":"VIC","section":"vic_quant","grade":"selective","topic":"Spatial Reasoning","difficulty":"medium","style":"acer","q":"A cube is painted red on all faces, then cut into 27 smaller cubes (3×3×3). How many small cubes have NO paint at all?","options":["0","1","6","8"],"answer":1,"exp":"The 1 cube in the very centre has no painted faces.\nIt is completely surrounded by other cubes.","hint":"Which position in a 3×3×3 arrangement is surrounded on all sides?"},{"id":"a008","state":"VIC","section":"vic_reading","grade":"selective","topic":"Grammar","difficulty":"medium","style":"acer","q":"Which sentence uses a subordinate clause correctly?","options":["Although it was raining, but we went outside.","Because she studied hard, she passed the exam.","She passed, however she studied hard.","Despite of the rain, we went outside."],"answer":1,"exp":"'Because she studied hard' is a subordinate clause correctly attached to the main clause.\nOption A: 'Although...but' = double conjunction (error).\nOption D: 'Despite of' is incorrect.","hint":"A subordinate clause begins with a conjunction and cannot stand alone."},{"id":"a009","state":"VIC","section":"vic_reading","grade":"selective","topic":"Grammar","difficulty":"medium","style":"acer","q":"Identify the sentence with an apostrophe used correctly:","options":["The dog's lead was lost.","Its a lovely day outside.","The childrens' playground is closed.","The teacher praised there work."],"answer":0,"exp":"'The dog's lead' = possessive apostrophe correctly used.\n'Its' (no apostrophe) = possessive pronoun. 'It's' = it is.\n'Children's' (not childrens') — children is already plural.\n'their work' (not 'there work').","hint":"Check each option: is the apostrophe used for possession or contraction correctly?"},{"id":"v001","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"medium","style":"acer","q":"AMBIVALENT most closely means:","options":["Strongly opposed","Having mixed or contradictory feelings","Completely neutral","Confused about facts"],"answer":1,"exp":"Ambivalent = having mixed feelings or contradictory ideas about something.\nFrom Latin: ambi (both) + valere (strong) — strength in two directions.","hint":"The prefix 'ambi' means both (as in ambidextrous = using both hands)."},{"id":"v002","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"medium","style":"acer","q":"CAMOUFLAGE is to CONCEALMENT as ARMOUR is to:","options":["Attack","Protection","Metal","Weight"],"answer":1,"exp":"Camouflage serves the purpose of concealment.\nArmour serves the purpose of protection.\nBoth are defined by their defensive purpose.","hint":"What is the main purpose of armour?"},{"id":"v003","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Word Relationships","difficulty":"medium","style":"acer","q":"Which pair has the MOST SIMILAR relationship to: DOCTOR : STETHOSCOPE?","options":["Chef : Restaurant","Painter : Brush","Teacher : School","Author : Book"],"answer":1,"exp":"Doctor uses a stethoscope as their primary professional tool.\nPainter uses a brush as their primary tool.\nRestaurant/school/book are locations or outputs, not tools.","hint":"Focus on the relationship type: professional → their primary tool."},{"id":"v004","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"hard","style":"contour","q":"SYCOPHANT most closely means:","options":["A wise advisor","A harsh critic","A person who flatters to gain favour","An independent thinker"],"answer":2,"exp":"Sycophant = someone who acts obsequiously toward those with power; a 'yes-man'.","hint":"A sycophant always agrees with and compliments powerful people."},{"id":"v005","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Odd One Out","difficulty":"medium","style":"hendersons","q":"Which does NOT belong?\nElegy · Sonnet · Haiku · Limerick · Allegory","options":["Elegy","Sonnet","Haiku","Allegory"],"answer":3,"exp":"Elegy, Sonnet, Haiku, Limerick are all poetic forms.\nAllegory is a narrative technique — not a poem form.","hint":"Which one is not a type of poem?"},{"id":"v006","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Analogies","difficulty":"medium","style":"acer","q":"PROLOGUE is to PLAY as PREFACE is to:","options":["Chapter","Book","Library","Author"],"answer":1,"exp":"A prologue comes at the start of a play.\nA preface comes at the start of a book.","hint":"Where does a preface appear, and in what type of work?"},{"id":"v007","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"hard","style":"acer","q":"LOQUACIOUS most closely means:","options":["Silent","Talkative","Argumentative","Wise"],"answer":1,"exp":"Loquacious = tending to talk a great deal.\nFrom Latin loqui (to speak).","hint":"The root 'loqu-' means 'to speak' (also in eloquent, soliloquy)."},{"id":"v008","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"hard","style":"contour","q":"PHILANDERER is to FIDELITY as MISER is to:","options":["Generosity","Wealth","Poverty","Greed"],"answer":0,"exp":"A philanderer lacks fidelity.\nA miser lacks generosity — they hoard instead of sharing.\nBoth: person defined by the absence of a virtue.","hint":"What quality does a miser notably lack?"},{"id":"v009","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Classification","difficulty":"hard","style":"contour","q":"Which does NOT belong?\nStalactite · Stalagmite · Geode · Fjord","options":["Stalactite","Stalagmite","Geode","Fjord"],"answer":3,"exp":"Stalactites, stalagmites, and geodes are cave/underground rock formations.\nA fjord is a coastal geographic feature (narrow sea inlet between cliffs).","hint":"Which of these is not found inside caves?"},{"id":"v010","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"hard","style":"acer","q":"OSSIFY is to BONE as CALCIFY is to:","options":["Stone","Calcium","Hardened tissue or mineral deposits","Water"],"answer":2,"exp":"Ossify = to become bone-like and rigid.\nCalcify = to become hardened by calcium deposits.\nBoth refer to a mineralisation/hardening process.","hint":"What does 'calcify' describe the formation of?"},{"id":"m001","state":"VIC","section":"vic_maths","grade":"selective","topic":"Number Theory","difficulty":"medium","style":"acer","q":"What is the next prime number after 29?","options":["30","31","33","37"],"answer":1,"exp":"30=2×3×5 (not prime), 31 is prime (only factors: 1 and 31) ✓","hint":"Test each number: is it divisible by anything other than 1 and itself?"},{"id":"m002","state":"VIC","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"medium","style":"acer","q":"Solve: 3(2x − 4) = 2(x + 6)","options":["x = 4","x = 5","x = 6","x = 7"],"answer":2,"exp":"6x − 12 = 2x + 12\n4x = 24\nx = 6","hint":"Expand the brackets first, then collect x terms on one side."},{"id":"m003","state":"VIC","section":"vic_maths","grade":"selective","topic":"Statistics","difficulty":"hard","style":"acer","q":"A data set has mean 20, median 18, and mode 15. Which is most likely true?","options":["The data is symmetric","The data is positively skewed (skewed right)","The data is negatively skewed","The data has no outliers"],"answer":1,"exp":"When mean > median > mode, the distribution is positively skewed (right skew).\nLarge outliers pull the mean upward.","hint":"Compare the mean, median, and mode. Which way does the 'tail' point?"},{"id":"m004","state":"VIC","section":"vic_maths","grade":"selective","topic":"Geometry","difficulty":"hard","style":"acer","q":"A sector has radius 6 cm and central angle 60°. What is the arc length? (π ≈ 3.14)","options":["3.14 cm","6.28 cm","12.56 cm","18.84 cm"],"answer":1,"exp":"Arc length = (θ/360) × 2πr = (60/360) × 2 × 3.14 × 6 = (1/6) × 37.68 = 6.28 cm","hint":"Arc length = (angle ÷ 360) × circumference."},{"id":"m005","state":"VIC","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"hard","style":"hendersons","q":"A 2-litre paint tin covers 8 m². How many litres are needed to paint a 60 m² wall with 2 coats?","options":["12 L","15 L","25 L","30 L"],"answer":3,"exp":"1 tin (2 L) covers 8 m².\nLitres per m²: 2/8 = 0.25 L/m²\n60 m² × 0.25 = 15 L per coat\n2 coats: 15 × 2 = 30 L","hint":"Find litres needed for one coat, then multiply by 2."},{"id":"m006","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Volume","difficulty":"medium","style":"psle","q":"A rectangular aquarium is 60 cm × 30 cm × 40 cm. It is ¾ full. How many litres of water? (1 L = 1000 cm³)","options":["54 L","60 L","72 L","81 L"],"answer":0,"exp":"Full volume = 60 × 30 × 40 = 72,000 cm³\n¾ of 72,000 = 54,000 cm³ = 54 litres","hint":"Find the full volume, then take ¾. Convert cm³ to litres (÷1000)."},{"id":"m007","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Fractions","difficulty":"medium","style":"psle","q":"⅗ of a number is 48. What is ¾ of the same number?","options":["60","72","80","90"],"answer":0,"exp":"Number = 48 ÷ (3/5) = 48 × 5/3 = 80\n¾ × 80 = 60","hint":"Find the full number first, then calculate ¾ of it."},{"id":"m008","state":"VIC","section":"vic_maths","grade":"selective","topic":"Patterns","difficulty":"medium","style":"acer","q":"Row 1 has 1 dot, Row 2 has 3, Row 3 has 5, Row 4 has 7. How many dots in Row 10?","options":["17","18","19","20"],"answer":2,"exp":"Pattern: Row n has (2n − 1) dots.\nRow 10: 2(10) − 1 = 19","hint":"Find the formula: how does the dot count relate to the row number?"},{"id":"m009","state":"VIC","section":"vic_maths","grade":"selective","topic":"Number","difficulty":"easy","style":"acer","q":"What is √144 + √25?","options":["13","17","19","23"],"answer":1,"exp":"√144 = 12, √25 = 5\n12 + 5 = 17","hint":"Find the square root of each number separately."},{"id":"m010","state":"VIC","section":"vic_maths","grade":"selective","topic":"Geometry","difficulty":"medium","style":"psle","q":"A triangle has angles in the ratio 1:2:3. What is the largest angle?","options":["30°","60°","90°","120°"],"answer":2,"exp":"Total parts = 1+2+3 = 6. Total = 180°.\nEach part = 30°.\nLargest = 3 × 30° = 90°","hint":"Add the ratio parts, then find what each part equals in degrees."},{"id":"m011","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Rates","difficulty":"medium","style":"psle","q":"A car uses 8 L of fuel per 100 km. How much fuel for a 350 km trip?","options":["24 L","28 L","32 L","36 L"],"answer":1,"exp":"Fuel = (8 ÷ 100) × 350 = 0.08 × 350 = 28 L","hint":"Find the fuel rate per km, then multiply by the distance."},{"id":"m012","state":"VIC","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"hard","style":"acer","q":"If 2^x = 32, what is x?","options":["4","5","6","8"],"answer":1,"exp":"2¹=2, 2²=4, 2³=8, 2⁴=16, 2⁵=32 ✓\nSo x = 5","hint":"List powers of 2 until you reach 32."},{"id":"m013","state":"VIC","section":"vic_maths","grade":"selective","topic":"Statistics","difficulty":"medium","style":"hendersons","q":"Five numbers have a mean of 12. A sixth number is added and the new mean is 13. What is the sixth number?","options":["15","16","18","19"],"answer":2,"exp":"Original sum = 5 × 12 = 60\nNew sum = 6 × 13 = 78\nSixth number = 78 − 60 = 18","hint":"Find both totals (mean × count), then subtract."},{"id":"m014","state":"VIC","section":"vic_maths","grade":"selective","topic":"Geometry","difficulty":"medium","style":"acer","q":"The radius of a circle is tripled. By what factor does the area increase?","options":["3","6","9","12"],"answer":2,"exp":"Area = πr²\nNew area = π(3r)² = 9πr²\nArea increases by factor of 9.","hint":"Write the formula for the new area and compare it to the original."},{"id":"m015","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Number Theory","difficulty":"hard","style":"psle","q":"How many 3-digit numbers are divisible by both 4 and 6?","options":["50","75","100","150"],"answer":1,"exp":"LCM(4,6) = 12. 3-digit multiples of 12: 108, 120, ..., 996\nCount = (996−108)/12 + 1 = 888/12 + 1 = 74 + 1 = 75","hint":"Find LCM first. Then count multiples in the 3-digit range."},{"id":"e001","state":"VIC","section":"vic_maths","grade":"6","topic":"Fractions","difficulty":"easy","style":"acer","q":"What is ¾ of 24?","options":["12","16","18","20"],"answer":2,"exp":"¾ of 24 = 3 × (24÷4) = 3 × 6 = 18","hint":"Divide by 4 first to find one quarter, then multiply by 3."},{"id":"e002","state":"VIC","section":"vic_maths","grade":"6","topic":"Decimals","difficulty":"easy","style":"acer","q":"What is 0.7 × 0.3?","options":["0.021","0.21","2.1","21"],"answer":1,"exp":"7 × 3 = 21, then count 2 decimal places → 0.21","hint":"Multiply as whole numbers, then count decimal places."},{"id":"e003","state":"VIC","section":"vic_maths","grade":"7","topic":"Percentage","difficulty":"easy","style":"acer","q":"What is 15% of 200?","options":["20","25","30","35"],"answer":2,"exp":"10% of 200 = 20. 5% of 200 = 10. 15% = 20 + 10 = 30","hint":"Find 10%, then 5%, then add them."},{"id":"e004","state":"VIC","section":"vic_maths","grade":"7","topic":"Geometry","difficulty":"easy","style":"acer","q":"What is the sum of all interior angles in a quadrilateral?","options":["180°","270°","360°","540°"],"answer":2,"exp":"A quadrilateral can be split into 2 triangles: 2 × 180° = 360°","hint":"How many triangles can you divide a quadrilateral into?"},{"id":"e005","state":"NSW","section":"nsw_maths","grade":"6","topic":"Multiplication","difficulty":"easy","style":"acer","q":"What is 125 × 8?","options":["900","960","1000","1100"],"answer":2,"exp":"125 × 8 = 1000\n(125 × 4 = 500, then × 2 = 1000)","hint":"Think: 125 × 4 = 500, then double it."},{"id":"e006","state":"VIC","section":"vic_reading","grade":"7","topic":"Grammar","difficulty":"easy","style":"acer","q":"Which word is an adverb?","options":["Quick","Quickly","Quickness","Quicker"],"answer":1,"exp":"Adverbs modify verbs and often end in '-ly'.\n'Quickly' describes how something is done.","hint":"Which word describes HOW something is done?"},{"id":"e007","state":"VIC","section":"vic_maths","grade":"6","topic":"Time","difficulty":"easy","style":"acer","q":"A movie starts at 2:45 PM and runs for 1 hour 35 minutes. When does it end?","options":["3:45 PM","4:10 PM","4:20 PM","4:25 PM"],"answer":2,"exp":"2:45 + 1 hour = 3:45\n3:45 + 35 minutes = 4:20 PM","hint":"Add the hours first, then the minutes."},{"id":"e008","state":"VIC","section":"vic_maths","grade":"7","topic":"Percentage","difficulty":"easy","style":"acer","q":"An item costs $50. GST (10%) is added. What is the total price?","options":["$50","$55","$60","$65"],"answer":1,"exp":"10% of $50 = $5\nTotal = $50 + $5 = $55","hint":"Find 10% of the price, then add it."},{"id":"e009","state":"NSW","section":"nsw_maths","grade":"6","topic":"Number","difficulty":"easy","style":"acer","q":"What is the value of 5³?","options":["15","25","125","625"],"answer":2,"exp":"5³ = 5 × 5 × 5 = 25 × 5 = 125","hint":"5³ means 5 multiplied by itself 3 times."},{"id":"e010","state":"VIC","section":"vic_maths","grade":"8","topic":"Algebra","difficulty":"easy","style":"hendersons","q":"If x = 3, what is the value of 4x² − 2x + 1?","options":["25","28","31","34"],"answer":2,"exp":"4(3²) − 2(3) + 1 = 4(9) − 6 + 1 = 36 − 6 + 1 = 31","hint":"Substitute x = 3, then follow order of operations."},{"id":"n001","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Syllogism","difficulty":"hard","style":"acer","q":"No sharks are mammals. All dolphins are mammals. Can any sharks be dolphins?","options":["Yes — some sharks might be dolphins","No — no shark can be a dolphin","Maybe — we need more information","Yes — both are fish"],"answer":1,"exp":"No sharks are mammals. All dolphins are mammals.\n∴ Sharks and dolphins share no members. No shark can be a dolphin.","hint":"Draw a Venn diagram: the shark and dolphin circles cannot overlap."},{"id":"n002","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Deduction","difficulty":"medium","style":"acer","q":"In a room of 30 people, 18 like tea, 15 like coffee, and 5 like neither. How many like BOTH tea and coffee?","options":["5","8","10","13"],"answer":1,"exp":"Like at least one: 30 − 5 = 25\nBy inclusion-exclusion: Both = 18 + 15 − 25 = 8","hint":"Use the inclusion-exclusion principle: T + C − Both = Total who like at least one."},{"id":"n003","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Pattern","difficulty":"hard","style":"contour","q":"A clock's hour hand moves from 12 to 4. Through how many degrees does it rotate?","options":["90°","100°","120°","150°"],"answer":2,"exp":"Hour hand: 360° in 12 hours = 30° per hour.\n4 hours × 30° = 120°","hint":"How many degrees does the hour hand move per hour?"},{"id":"n004","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Coding","difficulty":"hard","style":"acer","q":"In a code, each letter is replaced by the letter 3 places AFTER it (X→A, Y→B, Z→C).\nWhat does KHOOR decode to?","options":["HELLO","WORLD","HILLY","HALLO"],"answer":0,"exp":"To decode: subtract 3 from each letter.\nK-3=H, H-3=E, O-3=L, O-3=L, R-3=O → HELLO ✓","hint":"If the code adds 3 to each letter, decoding subtracts 3."},{"id":"n005","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"medium","style":"contour","q":"Ben has more than Ali. Cara has less than Dan. Dan has less than Ali. Who has the least?","options":["Ali","Ben","Cara","Dan"],"answer":2,"exp":"Order from most to least: Ben > Ali > Dan > Cara\nCara has the least.","hint":"Write out the comparisons as a chain: who is greater than whom?"},{"id":"w001","state":"VIC","section":"vic_reading","grade":"selective","topic":"Persuasive Writing","difficulty":"medium","style":"james_ann","q":"Which opening sentence is MOST effective for a persuasive essay about banning single-use plastics?","options":["Single-use plastics exist in the world.","Single-use plastics are bad.","Every minute, the equivalent of a garbage truck full of plastic enters our oceans — and we are choosing to let it happen.","I think we should ban single-use plastics because they are harmful."],"answer":2,"exp":"Option C uses a striking statistic and creates urgency and emotional impact ('choosing to let it happen').\nOptions A and B are vague. Option D uses 'I think' which weakens the authority of the argument.","hint":"Which opening is most likely to make a reader stop and pay attention?"},{"id":"w002","state":"VIC","section":"vic_reading","grade":"selective","topic":"Creative Writing","difficulty":"medium","style":"acer","q":"Which sentence demonstrates the BEST varied sentence structure?","options":["She ran. She was tired. She stopped.","Although exhausted, she kept running until the very last metre, where she finally collapsed with a gasp.","She ran and she was tired and she stopped running.","Running was tiring for her and she had to stop."],"answer":1,"exp":"Option B uses a subordinate clause opener ('Although exhausted'), precise detail ('very last metre'),\nand a strong verb ('collapsed with a gasp').\nOptions A and C are repetitive or overuse conjunctions.","hint":"Look for varied sentence openers and a mix of complex and simple structures."},{"id":"edu001","state":"BOTH","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"medium","style":"edutest","q":"Choose the word most similar in meaning to VERBOSE:","options":["Brief","Wordy","Honest","Angry"],"answer":1,"exp":"Verbose = using more words than needed; excessively wordy.\nAntonym: laconic, concise, terse.","hint":"The root 'verb-' relates to words (as in verbal, verbatim)."},{"id":"edu002","state":"BOTH","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"medium","style":"edutest","q":"SURGEON is to SCALPEL as SCULPTOR is to:","options":["Canvas","Chisel","Paint","Museum"],"answer":1,"exp":"A surgeon's primary cutting tool is a scalpel.\nA sculptor's primary shaping tool is a chisel.","hint":"What tool does a sculptor use to carve stone or wood?"},{"id":"edu003","state":"BOTH","section":"vic_verbal","grade":"selective","topic":"Sentence Completion","difficulty":"medium","style":"edutest","q":"The scientist's findings were so ___ that even sceptics were convinced.","options":["dubious","irrefutable","ambiguous","irrelevant"],"answer":1,"exp":"'Irrefutable' means impossible to deny or disprove.\nIf even sceptics were convinced, the evidence must be impossible to argue against.","hint":"What kind of finding convinces people who are already doubtful?"},{"id":"edu004","state":"BOTH","section":"vic_verbal","grade":"selective","topic":"Word Relationships","difficulty":"hard","style":"edutest","q":"Which pair shows the SAME relationship as ARCHIPELAGO : ISLANDS?","options":["Forest : Tree","Galaxy : Stars","Library : Books","All of the above"],"answer":3,"exp":"Archipelago = a group/cluster of islands.\nThe same 'collection/group : individual unit' relationship applies to:\nForest:Tree, Galaxy:Stars, Library:Books — all are correct.","hint":"What is an archipelago? Then find the same group-to-member relationship."},{"id":"edu005","state":"BOTH","section":"vic_verbal","grade":"selective","topic":"Odd One Out","difficulty":"hard","style":"edutest","q":"Which does NOT belong?\nMEMOIR · BIOGRAPHY · AUTOBIOGRAPHY · ANTHOLOGY","options":["Memoir","Biography","Autobiography","Anthology"],"answer":3,"exp":"Memoir, Biography, Autobiography are all forms of non-fiction writing about a person's life.\nAn Anthology is a collection of works by various authors — not a life story.","hint":"Which one is not about documenting a person's life?"},{"id":"edu006","state":"BOTH","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"hard","style":"edutest","q":"IGNORANCE is to ENLIGHTENMENT as CHAOS is to:","options":["Disorder","Order","War","Darkness"],"answer":1,"exp":"Ignorance and enlightenment are opposites (before/after understanding).\nChaos and order are opposites — the same contrast relationship.","hint":"Ignorance → enlightenment represents moving from disorder to clarity. What is chaos's opposite?"},{"id":"edu007","state":"BOTH","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"hard","style":"edutest","q":"TACITURN most closely means:","options":["Noisy and aggressive","Reserved and saying little","Extremely generous","Highly intelligent"],"answer":1,"exp":"Taciturn = reserved or uncommunicative in speech; saying little.\nFrom Latin tacere (to be silent).","hint":"The root 'taci-' relates to silence (as in 'tacit agreement' — an unspoken one)."},{"id":"edu008","state":"BOTH","section":"vic_verbal","grade":"selective","topic":"Sentence Completion","difficulty":"hard","style":"edutest","q":"Her response was deliberately ___, designed to avoid committing to any position.","options":["candid","evasive","blunt","assertive"],"answer":1,"exp":"'Evasive' = avoiding a direct answer or commitment.\nThe clue is 'avoid committing to any position'.","hint":"Which word means deliberately avoiding giving a clear answer?"},{"id":"edu009","state":"BOTH","section":"nsw_thinking","grade":"selective","topic":"Analogies","difficulty":"medium","style":"edutest","q":"METEOROLOGY is to WEATHER as SEISMOLOGY is to:","options":["Oceans","Stars","Earthquakes","Climate"],"answer":2,"exp":"Meteorology is the study of weather.\nSeismology is the study of earthquakes and seismic activity.","hint":"The '-logy' suffix means 'study of'. What does 'seismo-' relate to?"},{"id":"edu010","state":"BOTH","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"medium","style":"edutest","q":"PRUDENT most closely means:","options":["Reckless","Showing care and foresight","Extremely brave","Overly modest"],"answer":1,"exp":"Prudent = acting with care and thought for the future; wise and cautious.\nFrom Latin prudens (foreseeing).","hint":"A prudent person thinks carefully before acting. What quality does this describe?"},{"id":"edu011","state":"BOTH","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"medium","style":"edutest","q":"What are the next TWO numbers?\n1, 3, 6, 10, 15, ___, ___","options":["20 and 26","21 and 28","20 and 28","21 and 27"],"answer":1,"exp":"Triangle numbers: add 2, 3, 4, 5, 6, 7, 8...\n1+2=3, 3+3=6, 6+4=10, 10+5=15, 15+6=21, 21+7=28.","hint":"What is the pattern of differences between consecutive terms?"},{"id":"edu012","state":"BOTH","section":"vic_quant","grade":"selective","topic":"Grid Patterns","difficulty":"hard","style":"edutest","q":"In this table, each row follows the same rule:\n8 → 3 → 5\n12 → 5 → 7\n20 → 9 → ?\nWhat is the missing number?","options":["10","11","12","13"],"answer":1,"exp":"Rule: col1 − col2 = col3 − 1? No.\n8−3=5 ✓, 12−5=7 ✓, 20−9=11 ✓\nRule: col1 − col2 = col3.","hint":"Look at how the third number relates to the first two in each row."},{"id":"edu013","state":"BOTH","section":"vic_quant","grade":"selective","topic":"Symbol Substitution","difficulty":"medium","style":"edutest","q":"▲ × ▲ + ■ = 30\n▲ = 5, what is ■?","options":["4","5","6","7"],"answer":1,"exp":"5 × 5 + ■ = 30\n25 + ■ = 30\n■ = 5","hint":"Substitute ▲ = 5 and solve for ■."},{"id":"edu014","state":"BOTH","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"hard","style":"edutest","q":"What is the missing number?\n2, 3, 5, 8, 13, ___, 34","options":["19","20","21","22"],"answer":2,"exp":"Fibonacci-like: each term = sum of the two before.\n5+8=13, 8+13=21, 13+21=34 ✓","hint":"Add the two numbers before the blank."},{"id":"edu015","state":"BOTH","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"hard","style":"edutest","q":"If 5x + 3 = 2x + 18, what is 3x?","options":["5","10","15","20"],"answer":2,"exp":"5x + 3 = 2x + 18\n3x = 15\nx = 5, so 3x = 15","hint":"Solve for x first, then multiply by 3. Or find 3x directly."},{"id":"mat001","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Argument Analysis","difficulty":"hard","style":"matrix","q":"'All the students who failed the test didn't study. Jake didn't study. Therefore Jake failed the test.' What is wrong?","options":["The conclusion is correct","Not studying is necessary but not sufficient for failing — other students might also not study and pass","Jake might have studied","We don't know if Jake is a student"],"answer":1,"exp":"The statement says 'all who failed didn't study' — that means NOT studying is necessary for failing.\nBut it doesn't say everyone who doesn't study fails.\nJake could not study and still pass.","hint":"Does 'all failures didn't study' mean 'all non-studiers fail'? Think carefully about the direction."},{"id":"mat002","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Data Interpretation","difficulty":"medium","style":"matrix","q":"A graph shows that ice cream sales and shark attacks both increase in summer. A student concludes that ice cream causes shark attacks. What is the flaw?","options":["Ice cream is not sold near beaches","Both are caused by a third factor (hot weather/summer) — correlation is not causation","Shark attacks only happen in winter","The graph must be wrong"],"answer":1,"exp":"Both increase in summer because of hot weather — not because one causes the other.\nThis is the classic 'confounding variable' or 'spurious correlation' error.","hint":"Is there a third factor that could cause both to increase at the same time?"},{"id":"mat003","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"hard","style":"matrix","q":"Exactly one of these statements is true:\n1. All students passed.\n2. Some students passed.\n3. No student passed.\nWhich statement(s) could be true?","options":["Only statement 2","Statements 1 and 2 could both be true, but exactly one is chosen","Statement 2 only — because if all passed, statement 2 is also true, so they can't both be 'exactly one true'","Statement 3 only"],"answer":2,"exp":"If ALL students passed: both statements 1 AND 2 are true → violates 'exactly one true'.\nIf SOME (not all) passed: only statement 2 is true ✓\nIf NONE passed: only statement 3 is true ✓\nSo statement 2 alone OR statement 3 alone can each be the one true statement.\nBut the question asks which could be true: statement 2 (if some but not all passed).","hint":"If statement 1 is true, is statement 2 also true? What does that mean for 'exactly one'?"},{"id":"mat004","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Coding","difficulty":"medium","style":"matrix","q":"In a reverse alphabet code: A=26, B=25, C=24... Z=1. What does the code 19-26-11-11-2 spell?","options":["HELLO","HAPPY","WORLD","HILLY"],"answer":1,"exp":"A=26,B=25,C=24...H=19,A=26,P=11,P=11,Y=2\nSo 19-26-11-11-2 spells H-A-P-P-Y = HAPPY","hint":"Count backwards from A=26 to find each letter."},{"id":"mat005","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Problem Solving","difficulty":"hard","style":"matrix","q":"A rectangular pool is surrounded by a 2-metre wide path. The pool is 8m × 5m. What is the area of the path?","options":["60 m²","68 m²","80 m²","100 m²"],"answer":1,"exp":"Pool: 8×5=40 m²\nOuter (pool + path): (8+4)×(5+4) = 12×9 = 108 m²\nPath area: 108-40=68 m²","hint":"Outer rectangle = pool dimensions + path width on BOTH sides of each dimension."},{"id":"mat006","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Spatial Reasoning","difficulty":"medium","style":"matrix","q":"Looking down at a 3D shape from above, you see a circle. Looking from the side, you see a triangle. What is the shape?","options":["Sphere","Cone","Cylinder","Pyramid"],"answer":1,"exp":"A cone viewed from above = circle.\nA cone viewed from the side = triangle.\nSphere from side = circle (not triangle). Cylinder from above = circle, from side = rectangle.","hint":"Which 3D shape looks circular from above and triangular from the side?"},{"id":"mat007","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"hard","style":"matrix","q":"In a class of 30, 20 play sport, 15 study art, and every student does at least one. How many do BOTH?","options":["3","5","7","10"],"answer":1,"exp":"By inclusion-exclusion: Sport + Art - Both = Total\n20 + 15 - Both = 30\nBoth = 35 - 30 = 5","hint":"Use: Sport + Art - Both = Total (every student does at least one)."},{"id":"mat008","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Inference","difficulty":"hard","style":"matrix","q":"Read: 'The committee voted 7-3 in favour, but the chairperson called for a second vote.'\nWhat does this most likely suggest?","options":["The chairperson agreed with the result","The chairperson was unhappy with the outcome and sought to change it","7-3 is not a valid majority","The first vote was incorrectly counted"],"answer":1,"exp":"Calling for a second vote after a clear majority suggests the chairperson wanted a different result.\nIf they were satisfied, there would be no reason to vote again.","hint":"Why would someone call for a second vote after a 7-3 result?"},{"id":"oc001","state":"NSW","section":"nsw_maths","grade":"6","topic":"Word Problems","difficulty":"easy","style":"oc","q":"A bag has 5 apples, 3 oranges, and 2 bananas. How many pieces of fruit altogether?","options":["8","9","10","12"],"answer":2,"exp":"5 + 3 + 2 = 10 pieces of fruit","hint":"Add all the groups together."},{"id":"oc002","state":"NSW","section":"nsw_thinking","grade":"6","topic":"Patterns","difficulty":"easy","style":"oc","q":"What comes next?\n🔴🔵🔴🔵🔴___","options":["🔴","🔵","🟢","🟡"],"answer":1,"exp":"The pattern alternates: red, blue, red, blue, red...\nThe next colour is blue.","hint":"Look at the repeating pattern and continue it."},{"id":"oc003","state":"NSW","section":"nsw_maths","grade":"6","topic":"Number Sequences","difficulty":"easy","style":"oc","q":"What is the missing number?\n5, 10, 15, 20, ___, 30","options":["22","23","24","25"],"answer":3,"exp":"Count by 5s: 5, 10, 15, 20, 25, 30.","hint":"This is a skip-counting pattern. Count by 5s."},{"id":"oc004","state":"NSW","section":"nsw_thinking","grade":"6","topic":"Logical Deduction","difficulty":"easy","style":"oc","q":"There are 3 pets: a cat, a dog, and a fish.\nLucy does NOT have the dog. Ben has the fish.\nWhat pet does Lucy have?","options":["Dog","Fish","Cat","Bird"],"answer":2,"exp":"Ben has fish. Lucy doesn't have dog.\nThe only option left for Lucy is cat.","hint":"Eliminate what each person can't have, then see what's left."},{"id":"oc005","state":"NSW","section":"nsw_maths","grade":"6","topic":"Geometry","difficulty":"easy","style":"oc","q":"How many sides does an octagon have?","options":["6","7","8","9"],"answer":2,"exp":"Octo = 8 (like October was the 8th month in the old Roman calendar).\nAn octagon has 8 sides.","hint":"'Octo' is a Latin/Greek prefix meaning 8."},{"id":"oc006","state":"NSW","section":"nsw_reading","grade":"6","topic":"Comprehension","difficulty":"easy","style":"oc","q":"Read: 'Zara loves rainy days. She puts on her red boots and jumps in every puddle she can find.'\n\nHow does Zara feel about rainy days?","options":["Scared","Happy and excited","Bored","Cold"],"answer":1,"exp":"'Loves rainy days' and 'jumps in every puddle' shows Zara enjoys and is excited by rainy days.","hint":"Look for words that tell you how Zara feels."},{"id":"oc007","state":"NSW","section":"nsw_maths","grade":"6","topic":"Fractions","difficulty":"easy","style":"oc","q":"What is half of 36?","options":["12","16","18","20"],"answer":2,"exp":"Half of 36 = 36 ÷ 2 = 18","hint":"Divide by 2 to find half."},{"id":"oc008","state":"NSW","section":"nsw_thinking","grade":"6","topic":"Analogies","difficulty":"easy","style":"oc","q":"PUPPY is to DOG as KITTEN is to:","options":["Cat","Tiger","Rabbit","Fish"],"answer":0,"exp":"Puppy is a baby dog. Kitten is a baby cat.\nRelationship: young animal → adult animal.","hint":"What does a kitten grow up to be?"},{"id":"oc009","state":"NSW","section":"nsw_maths","grade":"6","topic":"Time","difficulty":"easy","style":"oc","q":"A movie is 2 hours and 15 minutes long. It starts at 3:00 PM. When does it finish?","options":["4:15 PM","5:00 PM","5:15 PM","5:30 PM"],"answer":2,"exp":"3:00 + 2 hours = 5:00\n5:00 + 15 minutes = 5:15 PM","hint":"Add the hours first, then the minutes."},{"id":"oc010","state":"NSW","section":"nsw_thinking","grade":"6","topic":"Ordering","difficulty":"easy","style":"oc","q":"Put these in order from smallest to largest:\n45, 27, 63, 9, 31","options":["9, 27, 31, 45, 63","27, 9, 31, 45, 63","9, 31, 27, 45, 63","45, 27, 63, 9, 31"],"answer":0,"exp":"From smallest to largest: 9, 27, 31, 45, 63","hint":"Find the smallest first, then the next smallest, and so on."},{"id":"hast001","state":"BOTH","section":"vic_verbal","grade":"selective","topic":"Abstract Reasoning","difficulty":"hard","style":"hast","q":"If CLOCK → KCOLC (letters reversed), what does GNIDAER decode to?","options":["READER","RAEDGN","READING","GRADING"],"answer":2,"exp":"Reverse the letters: G-N-I-D-A-E-R → R-E-A-D-I-N-G = READING","hint":"Reverse the order of all the letters."},{"id":"hast002","state":"BOTH","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"hard","style":"hast","q":"A statement: 'Some politicians are honest.' Which conclusion is VALID?","options":["All politicians are honest","No politicians are honest","At least one politician is honest","Most politicians are dishonest"],"answer":2,"exp":"'Some are honest' means at least one is honest — that's exactly what it means.\nWe cannot conclude anything about all, none, or most from 'some'.","hint":"'Some' means at least one. What does that definitely tell us?"},{"id":"hast003","state":"BOTH","section":"vic_maths","grade":"selective","topic":"Number Theory","difficulty":"hard","style":"hast","q":"How many integers from 1 to 100 are divisible by 3 OR by 5?","options":["40","46","47","50"],"answer":2,"exp":"Divisible by 3: 33 numbers (3,6,...99)\nDivisible by 5: 20 numbers (5,10,...100)\nDivisible by 15 (both): 6 numbers (15,30,...90)\nBy inclusion-exclusion: 33+20-6 = 47","hint":"Use inclusion-exclusion: count divisible by 3, by 5, then subtract those divisible by both."},{"id":"hast004","state":"BOTH","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"hard","style":"hast","q":"The average of 4 numbers is 15. Three of the numbers are 12, 18, and 10. What is the fourth?","options":["17","18","20","22"],"answer":2,"exp":"Total = 4 × 15 = 60\nSum of known three: 12+18+10 = 40\nFourth = 60-40 = 20","hint":"Total sum = mean × count. Find the total, then subtract the known sum."},{"id":"hast005","state":"BOTH","section":"nsw_thinking","grade":"selective","topic":"Abstract Reasoning","difficulty":"hard","style":"hast","q":"In a sequence of shapes: △ □ △△ □□ △△△ □□□ △△△△...\nHow many shapes are in the 8th group?","options":["7","8","9","10"],"answer":1,"exp":"Groups alternate triangle/square, increasing by 1 each group.\nGroup 1:1△, Group 2:2□, Group 3:3△, Group 4:4□, Group 5:5△, Group 6:6□, Group 7:7△, Group 8:8□\n8th group has 8 shapes.","hint":"Find the pattern: how many shapes are in each group?"},{"id":"hast006","state":"BOTH","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"hard","style":"hast","q":"If p + q = 10 and pq = 21, what is p² + q²?","options":["58","62","100","121"],"answer":0,"exp":"p² + q² = (p+q)² - 2pq = 100 - 42 = 58","hint":"Use the identity p² + q² = (p+q)² - 2pq."},{"id":"hast007","state":"BOTH","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"hard","style":"hast","q":"PRODIGAL is to THRIFT as BELLICOSE is to:","options":["War","Peace","Aggression","Diplomacy"],"answer":3,"exp":"Prodigal (wasteful) is the opposite of thrift (careful with money).\nBellicose (warlike, aggressive) is the opposite of diplomacy (peaceful negotiation).","hint":"Prodigal and thrift are opposites. What is the opposite of bellicose (meaning aggressive/warlike)?"},{"id":"hast008","state":"BOTH","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"hard","style":"hast","q":"If no A is B, and all C is B, which MUST be true?","options":["All A is C","No C is A","Some A is B","All B is C"],"answer":1,"exp":"No A is B: A and B sets are disjoint.\nAll C is B: C is a subset of B.\nSince A and B share no members, and C is entirely within B, A and C also share no members.\n∴ No C is A.","hint":"Draw three circles: A completely separate from B, C completely inside B. Can A and C overlap?"},{"id":"r001","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Comprehension","difficulty":"easy","style":"acer","q":"Read:\n\"Leafcutter ants are among nature's most remarkable farmers. Working in vast colonies of millions, they cut leaves into fragments and carry them to underground fungus gardens. They do not eat the leaves directly — instead, they cultivate a fungus that grows on the leaf material, and this fungus becomes their primary food source. The ants maintain their gardens with extraordinary care, removing contaminants and applying bacteria from their own bodies as a natural antibiotic. Some colonies have been farming the same fungal strain for millions of years.\"\n\nWhat do leafcutter ants actually eat?","options":["Leaves","The fungus that grows on leaves","Bacteria","Soil"],"answer":1,"exp":"The passage states: 'this fungus becomes their primary food source.'\nThey cultivate fungus — not eat the leaves directly.","hint":"Look for what the ants eat 'instead of' the leaves."},{"id":"r002","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Inference","difficulty":"medium","style":"acer","q":"Read:\n\"Leafcutter ants are among nature's most remarkable farmers. Working in vast colonies of millions, they cut leaves into fragments and carry them to underground fungus gardens. They do not eat the leaves directly — instead, they cultivate a fungus that grows on the leaf material, and this fungus becomes their primary food source. The ants maintain their gardens with extraordinary care, removing contaminants and applying bacteria from their own bodies as a natural antibiotic. Some colonies have been farming the same fungal strain for millions of years.\"\n\nThe passage says some colonies have farmed the same fungal strain for millions of years. What does this suggest?","options":["Ants are slow to adapt","This farming system is extremely successful and stable","The fungus is very old","Ants lived before humans"],"answer":1,"exp":"Maintaining the same fungal strain for millions of years suggests the system is highly effective — there's been no need to change it.","hint":"Why would a strategy persist unchanged for millions of years?"},{"id":"r003","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Vocabulary","difficulty":"medium","style":"james_ann","q":"Read:\n\"Leafcutter ants are among nature's most remarkable farmers. Working in vast colonies of millions, they cut leaves into fragments and carry them to underground fungus gardens. They do not eat the leaves directly — instead, they cultivate a fungus that grows on the leaf material, and this fungus becomes their primary food source. The ants maintain their gardens with extraordinary care, removing contaminants and applying bacteria from their own bodies as a natural antibiotic. Some colonies have been farming the same fungal strain for millions of years.\"\n\nIn context, 'cultivate' most closely means:","options":["Destroy","Farm and grow carefully","Collect and store","Study scientifically"],"answer":1,"exp":"'Cultivate' means to prepare and use land/conditions to grow something.\nHere the ants cultivate (grow and tend) the fungus.","hint":"The ants 'cultivate' the fungus the way humans cultivate crops. What does that mean?"},{"id":"r004","state":"VIC","section":"vic_reading","grade":"selective","topic":"Comprehension","difficulty":"medium","style":"james_ann","q":"Read:\n\"For centuries, scientists debated whether light was a wave or a particle. Isaac Newton championed the particle theory; Christian Huygens argued it was a wave. Then Thomas Young's double-slit experiment in 1801 seemed to prove the wave theory — beams of light created interference patterns, something particles cannot do. But in 1905, Einstein showed that light also behaves as a particle (the photon) when it interacts with matter. Modern physics accepts both: light exhibits wave-particle duality, behaving as whichever is more useful for the situation being studied.\"\n\nWhat did Young's double-slit experiment demonstrate?","options":["Light is definitely a particle","Light creates interference patterns, suggesting wave behaviour","Einstein was wrong","Newton's particle theory was confirmed"],"answer":1,"exp":"The passage states the experiment created 'interference patterns, something particles cannot do' — supporting the wave theory.","hint":"What can particles NOT do according to the passage?"},{"id":"r005","state":"VIC","section":"vic_reading","grade":"selective","topic":"Main Idea","difficulty":"medium","style":"james_ann","q":"Read:\n\"For centuries, scientists debated whether light was a wave or a particle. Isaac Newton championed the particle theory; Christian Huygens argued it was a wave. Then Thomas Young's double-slit experiment in 1801 seemed to prove the wave theory — beams of light created interference patterns, something particles cannot do. But in 1905, Einstein showed that light also behaves as a particle (the photon) when it interacts with matter. Modern physics accepts both: light exhibits wave-particle duality, behaving as whichever is more useful for the situation being studied.\"\n\nThe best title for this passage would be:","options":["Newton vs Einstein","The History of Physics","Wave or Particle? How Science Resolved the Nature of Light","Why Light Is Complicated"],"answer":2,"exp":"The passage traces the debate from particles to waves to both — the resolution is 'wave-particle duality'.\nOption C captures both the question and the resolution.","hint":"Which title covers the whole passage — not just part of it?"},{"id":"r006","state":"VIC","section":"vic_reading","grade":"selective","topic":"Inference","difficulty":"hard","style":"contour","q":"Read:\n\"For centuries, scientists debated whether light was a wave or a particle. Isaac Newton championed the particle theory; Christian Huygens argued it was a wave. Then Thomas Young's double-slit experiment in 1801 seemed to prove the wave theory — beams of light created interference patterns, something particles cannot do. But in 1905, Einstein showed that light also behaves as a particle (the photon) when it interacts with matter. Modern physics accepts both: light exhibits wave-particle duality, behaving as whichever is more useful for the situation being studied.\"\n\nThe final sentence says light behaves 'as whichever is more useful for the situation being studied.' What does this imply about scientific models?","options":["Scientific models must be either right or wrong","A model's usefulness depends on the context, not just whether it is 'true'","Light chooses how to behave","Wave-particle duality is impossible"],"answer":1,"exp":"The statement implies that scientists choose the model (wave or particle) that best fits the problem.\nThis reflects a pragmatic view of scientific models — they are tools, not absolute truths.","hint":"If you use EITHER model depending on what's useful, what does that say about scientific 'truth'?"},{"id":"vm001","state":"VIC","section":"vic_maths","grade":"selective","topic":"Number","difficulty":"easy","style":"acer","q":"What is 2⁴ × 3?","options":["36","42","48","54"],"answer":2,"exp":"2⁴ = 16\n16 × 3 = 48","hint":"Calculate 2⁴ first (2×2×2×2), then multiply by 3."},{"id":"vm002","state":"VIC","section":"vic_maths","grade":"selective","topic":"Fractions","difficulty":"easy","style":"acer","q":"Which fraction is largest?\n⅔, ¾, ⅗, ⅞","options":["⅔","¾","⅗","⅞"],"answer":3,"exp":"Convert to decimals: ⅔≈0.667, ¾=0.75, ⅗=0.6, ⅞=0.875\n⅞ is largest.","hint":"Convert each to a decimal by dividing the numerator by the denominator."},{"id":"vm003","state":"VIC","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"medium","style":"acer","q":"If 3a + 2b = 20 and a = 4, what is b?","options":["3","4","5","6"],"answer":1,"exp":"3(4) + 2b = 20\n12 + 2b = 20\n2b = 8\nb = 4","hint":"Substitute a = 4, then solve for b."},{"id":"vm004","state":"VIC","section":"vic_maths","grade":"selective","topic":"Number Theory","difficulty":"medium","style":"hendersons","q":"What is the LCM of 6, 8, and 12?","options":["12","16","24","48"],"answer":2,"exp":"LCM(6,8) = 24. LCM(24,12) = 24.\nVerify: 24÷6=4 ✓, 24÷8=3 ✓, 24÷12=2 ✓","hint":"Find LCM of first two numbers, then find LCM of that with the third."},{"id":"vm005","state":"VIC","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"hard","style":"hendersons","q":"A rectangle's length is 3 more than its width. Its perimeter is 54 cm. What is its area?","options":["162 cm²","180 cm²","192 cm²","216 cm²"],"answer":1,"exp":"Let width = w, length = w+3.\n2(w + w+3) = 54 → 2(2w+3) = 54 → 4w+6=54 → w=12, l=15\nArea = 12×15 = 180 cm²","hint":"Set up an equation using perimeter = 2(length + width)."},{"id":"vm006","state":"VIC","section":"vic_maths","grade":"selective","topic":"Sequences","difficulty":"medium","style":"acer","q":"The sum 1+2+3+...+10 equals 55. What is 1+2+3+...+20?","options":["110","190","200","210"],"answer":3,"exp":"Using formula: n(n+1)/2\n20×21/2 = 210\nOr: 1+2+...+20 = (1+2+...+10) + (11+12+...+20) = 55 + 155 = 210","hint":"Use the formula n(n+1)÷2, or add the second group (11 to 20)."},{"id":"vm007","state":"VIC","section":"vic_maths","grade":"selective","topic":"Geometry","difficulty":"medium","style":"psle","q":"A semicircle has diameter 20 cm. What is its perimeter? (π ≈ 3.14)","options":["51.4 cm","62.8 cm","74.2 cm","31.4 cm"],"answer":0,"exp":"Perimeter of semicircle = half circumference + diameter\n= (π × d)/2 + d = (3.14×20)/2 + 20 = 31.4 + 20 = 51.4 cm","hint":"Don't forget to add the diameter — it forms the straight edge of the semicircle."},{"id":"vm008","state":"VIC","section":"vic_quant","grade":"selective","topic":"Pattern Recognition","difficulty":"medium","style":"edutest","q":"What is the next number?\n1, 8, 27, 64, 125, ___","options":["196","216","225","256"],"answer":1,"exp":"These are perfect cubes: 1³=1, 2³=8, 3³=27, 4³=64, 5³=125, 6³=216","hint":"Recognise these as cube numbers: 1³, 2³, 3³..."},{"id":"vm009","state":"VIC","section":"vic_maths","grade":"selective","topic":"Ratios","difficulty":"hard","style":"psle","q":"$360 is divided among Ali, Ben, and Cara in the ratio 2:3:4. How much does Ben get?","options":["$80","$100","$120","$140"],"answer":2,"exp":"Total parts = 2+3+4 = 9. Each part = 360÷9 = $40\nBen's share = 3×$40 = $120","hint":"Find the value of one 'part' first."},{"id":"vm010","state":"VIC","section":"vic_maths","grade":"selective","topic":"Probability","difficulty":"hard","style":"acer","q":"A bag has 3 red, 4 blue, 2 green marbles. Two marbles drawn without replacement. P(both red)?","options":["1/12","1/14","2/27","3/11"],"answer":0,"exp":"P(1st red) = 3/9 = 1/3\nP(2nd red | 1st red) = 2/8 = 1/4\nP(both red) = 1/3 × 1/4 = 1/12","hint":"Multiply the probabilities — but the second probability changes after the first draw."},{"id":"vb001","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"medium","style":"acer","q":"MAGNANIMOUS most closely means:","options":["Small-minded","Generous and forgiving, especially to rivals","Extremely large","Fiercely competitive"],"answer":1,"exp":"Magnanimous = generous in spirit, especially when victorious.\nFrom Latin: magnus (great) + animus (spirit).","hint":"'Magnus' = great, 'animus' = spirit. A magnanimous winner congratulates the loser graciously."},{"id":"vb002","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"medium","style":"acer","q":"CARTILAGE is to SHARK as BONE is to:","options":["Fish","Mammal","Snake","Bird"],"answer":1,"exp":"Sharks have cartilage (not bone) as their skeletal structure.\nMammals have bones as their skeletal structure.","hint":"What provides structure to a mammal's body the way cartilage does for a shark?"},{"id":"vb003","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Classification","difficulty":"hard","style":"contour","q":"Which does NOT belong?\nOxymoron · Paradox · Juxtaposition · Synonym","options":["Oxymoron","Paradox","Juxtaposition","Synonym"],"answer":3,"exp":"Oxymoron, Paradox, Juxtaposition all involve placing contrasting/contradictory elements together.\nA Synonym is simply another word with the same meaning — no contrast involved.","hint":"Which one has nothing to do with contrast or contradiction?"},{"id":"vb004","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"hard","style":"hast","q":"PYROMANIAC is to FIRE as KLEPTOMANIAC is to:","options":["Money","Theft/Stealing","Books","Cars"],"answer":1,"exp":"A pyromaniac has a compulsion related to fire (setting fires).\nA kleptomaniac has a compulsion to steal.","hint":"What compulsion defines a kleptomaniac?"},{"id":"vb005","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"hard","style":"edutest","q":"SOPHISTRY most closely means:","options":["Deep wisdom","Clever but misleading reasoning","Scientific method","Public speaking"],"answer":1,"exp":"Sophistry = the use of clever but false arguments, especially to deceive.\nFrom the ancient Greek 'sophists' who were accused of arguing for effect rather than truth.","hint":"Sophists were ancient Greek teachers criticised for winning arguments through trickery. What does sophistry involve?"},{"id":"vm_a01","state":"VIC","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"easy","style":"hendersons","q":"If y = 3x − 2, find y when x = 5.","options":["11","13","15","17"],"answer":1,"exp":"y = 3(5) − 2 = 15 − 2 = 13","hint":"Substitute x = 5."},{"id":"vm_a02","state":"VIC","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"easy","style":"acer","q":"Solve: 5x = 35","options":["5","6","7","8"],"answer":2,"exp":"5x = 35 → x = 7","hint":"Divide both sides by 5."},{"id":"vm_a03","state":"VIC","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"medium","style":"hendersons","q":"Solve: 2(x + 4) = 18","options":["4","5","6","7"],"answer":1,"exp":"2(x+4)=18 → x+4=9 → x=5","hint":"Divide both sides by 2 first."},{"id":"vm_a04","state":"VIC","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"medium","style":"acer","q":"If 3x + 7 = 4x − 2, find x.","options":["7","8","9","10"],"answer":2,"exp":"3x + 7 = 4x − 2\nStep 1: Move x terms left → 3x − 4x = −2 − 7\nStep 2: −x = −9 → x = 9\n✓ Check: 3(9)+7 = 34 and 4(9)−2 = 34 ✓","hint":"Move x to one side, numbers to other."},{"id":"vm_a05","state":"VIC","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"medium","style":"psle","q":"Two numbers differ by 8. Their sum is 42. What are the numbers?","options":["15 and 23","17 and 25","16 and 26","19 and 23"],"answer":1,"exp":"x+(x+8)=42 → 2x=34 → x=17. Numbers: 17 and 25.","hint":"Let the smaller = x, larger = x+8."},{"id":"vm_a06","state":"VIC","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"hard","style":"hendersons","q":"Solve: x² − 7x + 12 = 0","options":["x=3 or x=4","x=−3 or x=−4","x=2 or x=6","x=1 or x=12"],"answer":0,"exp":"To factorise x² − 7x + 12, find two numbers that:\n  • Multiply to give +12\n  • Add to give −7\nThose numbers are −3 and −4\n∴ (x − 3)(x − 4) = 0 → x = 3 or x = 4\n✓ Check: 3×4=12 ✓, 3+4=7 ✓","hint":"Find two numbers multiplying to 12 and adding to 7."},{"id":"vm_a07","state":"VIC","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"hard","style":"acer","q":"If x + 1/x = 5, find x² + 1/x².","options":["21","23","25","27"],"answer":1,"exp":"Key identity: (x + 1/x)² = x² + 2(x)(1/x) + 1/x² = x² + 2 + 1/x²\nSo x² + 1/x² = (x + 1/x)² − 2 = 5² − 2 = 25 − 2 = 23\n💡 This is a standard identity worth memorising.","hint":"Square both sides: (x+1/x)²=x²+2+1/x²."},{"id":"vm_a08","state":"VIC","section":"vic_maths","grade":"8","topic":"Algebra","difficulty":"medium","style":"hendersons","q":"Expand: (x + 3)(x − 2)","options":["x²+x−6","x²−x−6","x²+x+6","x²+5x−6"],"answer":0,"exp":"(x+3)(x−2)=x²−2x+3x−6=x²+x−6","hint":"FOIL: First, Outside, Inside, Last."},{"id":"vm_a09","state":"VIC","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"hard","style":"psle","q":"A is 3 times B. B is 4 more than C. If C = 5, what is A?","options":["24","27","30","33"],"answer":1,"exp":"C=5, B=9, A=27","hint":"Work forward: C→B→A."},{"id":"vm_a10","state":"VIC","section":"vic_maths","grade":"selective","topic":"Algebra","difficulty":"hard","style":"acer","q":"If a + b = 7 and a² + b² = 29, what is ab?","options":["5","10","15","20"],"answer":1,"exp":"We need p² + q².\nUse the identity: (p+q)² = p² + 2pq + q²\nRearrange: p² + q² = (p+q)² − 2pq = 7² − 2(10) = 49 − 20 = 29\n\nWait — check: p+q=7 and pq=21? Let's verify: p²+q²=(p+q)²−2pq = 49−42 = 7? Hmm, that gives 7 not a listed option.\nActually with p+q=7, pq=10: p²+q²=49−20=29 ✓","hint":"Use the identity (a+b)²=a²+2ab+b²."},{"id":"vm_g01","state":"VIC","section":"vic_maths","grade":"selective","topic":"Geometry","difficulty":"easy","style":"acer","q":"An isosceles triangle has two angles of 55°. What is the third?","options":["50°","60°","70°","80°"],"answer":2,"exp":"Third = 180°−55°−55° = 70°","hint":"Angles in a triangle sum to 180°."},{"id":"vm_g02","state":"VIC","section":"vic_maths","grade":"selective","topic":"Geometry","difficulty":"easy","style":"acer","q":"A circle has circumference 31.4 cm. What is its radius? (π ≈ 3.14)","options":["4 cm","5 cm","6 cm","7 cm"],"answer":1,"exp":"C = 2πr\nRearrange for r: r = C ÷ (2π) = 31.4 ÷ (2 × 3.14) = 31.4 ÷ 6.28 = 5 cm\n💡 Remember the two circle formulas: C = 2πr (circumference) and A = πr² (area).","hint":"Circumference=2πr. Rearrange to find r."},{"id":"vm_g03","state":"VIC","section":"vic_maths","grade":"selective","topic":"Geometry","difficulty":"medium","style":"psle","q":"A rhombus has diagonals 12 cm and 16 cm. What is its area?","options":["96 cm²","144 cm²","48 cm²","192 cm²"],"answer":0,"exp":"Area=(d₁×d₂)÷2=(12×16)÷2=96 cm²","hint":"Area of rhombus = half the product of its diagonals."},{"id":"vm_g04","state":"VIC","section":"vic_maths","grade":"selective","topic":"Geometry","difficulty":"medium","style":"acer","q":"What is the exterior angle of a regular hexagon?","options":["45°","60°","72°","90°"],"answer":1,"exp":"360°÷6=60°","hint":"Sum of exterior angles of any polygon = 360°."},{"id":"vm_g05","state":"VIC","section":"vic_maths","grade":"selective","topic":"Geometry","difficulty":"medium","style":"acer","q":"A rectangle has area 84 cm² and length 12 cm. What is its width?","options":["5 cm","6 cm","7 cm","8 cm"],"answer":2,"exp":"Total surface area of a cone = πr² (base) + πrl (curved side) = πr(r + l)\n= 3.14 × 3 × (3 + 5)\n= 3.14 × 3 × 8\n= 3.14 × 24\n= 75.36 cm²\n💡 Slant height (l) is the distance along the side, not the vertical height.","hint":"Area=l×w. Rearrange to find width."},{"id":"vm_g06","state":"VIC","section":"vic_maths","grade":"selective","topic":"Geometry","difficulty":"medium","style":"hendersons","q":"A sphere has radius 6 cm. What is its volume? (π≈3.14)","options":["904.32 cm³","452.16 cm³","678.24 cm³","1130.4 cm³"],"answer":0,"exp":"V=(4/3)πr³=(4/3)×3.14×216=904.32 cm³","hint":"Volume of sphere=(4/3)πr³."},{"id":"vm_g07","state":"VIC","section":"vic_maths","grade":"selective","topic":"Geometry","difficulty":"hard","style":"psle","q":"The diagonal of a square is 10 cm. What is its area?","options":["25 cm²","50 cm²","75 cm²","100 cm²"],"answer":1,"exp":"The diagonal of a square splits it into two right-angled triangles.\nIf diagonal = d, then by Pythagoras: s² + s² = d² → 2s² = d²\nArea = s² = d²/2 = 10²/2 = 100/2 = 50 cm²\n💡 This shortcut — area = d²/2 — works for ALL squares.","hint":"Area of square = d²/2 where d is the diagonal."},{"id":"vm_g08","state":"VIC","section":"vic_maths","grade":"selective","topic":"Geometry","difficulty":"medium","style":"acer","q":"A parallelogram has base 9 cm and height 6 cm. What is its area?","options":["27 cm²","36 cm²","54 cm²","45 cm²"],"answer":2,"exp":"Area=base×height=9×6=54 cm²","hint":"Area of parallelogram = base × perpendicular height."},{"id":"vm_g09","state":"VIC","section":"vic_maths","grade":"selective","topic":"Geometry","difficulty":"hard","style":"hendersons","q":"A cone has radius 3 cm and slant height 5 cm. What is its total surface area? (π≈3.14)","options":["75.36 cm²","56.52 cm²","37.68 cm²","94.2 cm²"],"answer":0,"exp":"TSA=πr(r+l)=3.14×3×(3+5)=75.36 cm²","hint":"Total surface area of cone=πr(l+r)."},{"id":"vm_g10","state":"VIC","section":"vic_maths","grade":"selective","topic":"Geometry","difficulty":"hard","style":"acer","q":"Two similar triangles have sides in ratio 3:5. If the smaller has area 27 cm², what is the larger's area?","options":["45 cm²","75 cm²","135 cm²","225 cm²"],"answer":1,"exp":"For similar figures, the ratio of areas = (ratio of sides)²\nSide ratio = 3:5, so area ratio = 3²:5² = 9:25\nIf smaller area = 27 cm²:\n27/9 = 3 (one part)\nLarger area = 3 × 25 = 75 cm²","hint":"Area ratio = square of side ratio."},{"id":"vm_n01","state":"VIC","section":"vic_maths","grade":"selective","topic":"Number Theory","difficulty":"easy","style":"acer","q":"What is the sum of prime numbers between 10 and 20?","options":["36","60","48","52"],"answer":1,"exp":"Primes: 11,13,17,19 → sum=60","hint":"List all primes between 10 and 20, then add."},{"id":"vm_n02","state":"VIC","section":"vic_maths","grade":"selective","topic":"Number Theory","difficulty":"medium","style":"acer","q":"What is the HCF of 84 and 126?","options":["14","21","42","63"],"answer":2,"exp":"84=2²×3×7, 126=2×3²×7 → HCF=2×3×7=42","hint":"Prime factorise each, multiply common factors."},{"id":"vm_n03","state":"VIC","section":"vic_maths","grade":"selective","topic":"Number Theory","difficulty":"medium","style":"acer","q":"Which is NOT a perfect square?","options":["144","196","225","250"],"answer":3,"exp":"√250≈15.8 (not whole) → 250 is not a perfect square.","hint":"Check if the square root is a whole number."},{"id":"vm_n04","state":"VIC","section":"vic_maths","grade":"selective","topic":"Number Theory","difficulty":"hard","style":"hendersons","q":"How many factors does 360 have?","options":["18","20","24","28"],"answer":2,"exp":"360 = 2³ × 3² × 5¹\nRule: if n = p^a × q^b × r^c then number of factors = (a+1)(b+1)(c+1)\n= (3+1)(2+1)(1+1) = 4 × 3 × 2 = 24\n\nYou can verify: 1,2,3,4,5,6,8,9,10,12,15,18,20,24,30,36,40,45,60,72,90,120,180,360 = 24 factors ✓","hint":"If n=p^a×q^b, factors=(a+1)(b+1)."},{"id":"vm_n05","state":"VIC","section":"vic_maths","grade":"selective","topic":"Number Theory","difficulty":"medium","style":"acer","q":"What is the smallest 4-digit number divisible by 6?","options":["1000","1002","1006","1008"],"answer":1,"exp":"1002: even ✓, 1+0+0+2=3 (div by 3) ✓","hint":"Divisible by 6 = divisible by both 2 and 3."},{"id":"vm_p01","state":"VIC","section":"vic_maths","grade":"selective","topic":"Percentage","difficulty":"easy","style":"acer","q":"If 40% of a number is 60, what is the number?","options":["100","120","140","150"],"answer":3,"exp":"N=60÷0.4=150","hint":"Divide by the percentage as a decimal."},{"id":"vm_p02","state":"VIC","section":"vic_maths","grade":"selective","topic":"Percentage","difficulty":"medium","style":"psle","q":"A price increased by 20% then decreased by 20%. Final price vs original:","options":["Same","4% less","4% more","8% less"],"answer":1,"exp":"$100→$120→$96 (4% less)","hint":"Percentages apply to different amounts."},{"id":"vm_p03","state":"VIC","section":"vic_maths","grade":"selective","topic":"Percentage","difficulty":"medium","style":"acer","q":"A coat costs $180. Reduced 15%, then further 10%. Final price?","options":["$121.50","$135","$137.70","$144"],"answer":2,"exp":"$180×0.85=$153, $153×0.90=$137.70","hint":"Apply each discount to the new (reduced) price."},{"id":"vm_p04","state":"VIC","section":"vic_maths","grade":"selective","topic":"Ratios","difficulty":"medium","style":"psle","q":"$540 split between Ann and Bob 4:5. How much does Ann get?","options":["$216","$240","$270","$300"],"answer":1,"exp":"Part=$60, Ann=4×$60=$240","hint":"Find the value of one part first."},{"id":"vm_p05","state":"VIC","section":"vic_maths","grade":"selective","topic":"Ratios","difficulty":"hard","style":"psle","q":"Alcohol:water = 1:4. Add 10L alcohol → ratio becomes 1:2. How much water originally?","options":["20 L","30 L","40 L","50 L"],"answer":2,"exp":"(x+10)/(4x)=1/2 → x=10, water=40L","hint":"Set up an equation using the new ratio."},{"id":"vm_p06","state":"VIC","section":"vic_maths","grade":"selective","topic":"Percentage","difficulty":"hard","style":"acer","q":"Product marked up 25%, sold at 10% loss on marked price. Overall profit/loss on cost?","options":["12.5% profit","12.5% loss","10% profit","10% loss"],"answer":0,"exp":"Cost=100, Marked=125, Sold=112.50 → 12.5% profit","hint":"Compare final selling price to original cost."},{"id":"vm_s01","state":"VIC","section":"vic_maths","grade":"selective","topic":"Statistics","difficulty":"easy","style":"acer","q":"Scores: 3, 7, 7, 8, 10. What is the median?","options":["7","7.5","8","3"],"answer":0,"exp":"Ordered: 3,7,7,8,10. Middle=7.","hint":"Median=middle value when ordered."},{"id":"vm_s02","state":"VIC","section":"vic_maths","grade":"selective","topic":"Statistics","difficulty":"medium","style":"acer","q":"Dataset: 4,8,6,5,9,7,6. What is the range?","options":["3","4","5","6"],"answer":2,"exp":"Range=9−4=5","hint":"Range=max−min."},{"id":"vm_s03","state":"VIC","section":"vic_maths","grade":"selective","topic":"Probability","difficulty":"medium","style":"acer","q":"A fair die rolled twice. P(sum=7)?","options":["1/6","7/36","5/12","1/4"],"answer":0,"exp":"Sample space: all pairs (die1, die2) = 6×6 = 36 total outcomes\nPairs that sum to 7: (1,6),(2,5),(3,4),(4,3),(5,2),(6,1) = 6 pairs\nP(sum=7) = 6/36 = 1/6\n💡 Sum of 7 is the MOST common result when rolling two dice.","hint":"List pairs summing to 7, divide by 36 total outcomes."},{"id":"vm_s04","state":"VIC","section":"vic_maths","grade":"selective","topic":"Statistics","difficulty":"hard","style":"hendersons","q":"Mean of 6 numbers is 15. Largest (30) removed. New mean?","options":["10","11","12","13"],"answer":2,"exp":"Using inclusion-exclusion:\nP(prime OR even) = P(prime) + P(even) − P(prime AND even)\nPrimes 1–10: 2,3,5,7 → 4/10\nEvens 1–10: 2,4,6,8,10 → 5/10\nBoth prime AND even: only 2 → 1/10\nAnswer: 4/10 + 5/10 − 1/10 = 8/10 = 4/5","hint":"Total=mean×count. Remove number, divide by new count."},{"id":"vm_w01","state":"VIC","section":"vic_maths","grade":"selective","topic":"Word Problems","difficulty":"easy","style":"psle","q":"8 pens cost $12. How much do 5 pens cost?","options":["$6.00","$7.00","$7.50","$8.00"],"answer":2,"exp":"$12÷8=$1.50 per pen. 5×$1.50=$7.50","hint":"Find unit price first."},{"id":"vm_w02","state":"VIC","section":"vic_maths","grade":"selective","topic":"Word Problems","difficulty":"medium","style":"psle","q":"Car travels 360 km in 4 hours. Time for 270 km at same speed?","options":["2.5 hours","3 hours","3.5 hours","4 hours"],"answer":1,"exp":"Speed=90 km/h. Time=270÷90=3 hours","hint":"Speed=distance÷time, then time=distance÷speed."},{"id":"vm_w03","state":"VIC","section":"vic_maths","grade":"selective","topic":"Word Problems","difficulty":"medium","style":"hendersons","q":"Man is 3× his son's age. In 12 years he'll be 2× son's age. Son's age now?","options":["8","10","12","14"],"answer":2,"exp":"3x+12=2(x+12) → x=12","hint":"Set up equation using 'in 12 years'."},{"id":"vm_w04","state":"VIC","section":"vic_maths","grade":"selective","topic":"Word Problems","difficulty":"hard","style":"psle","q":"Tap fills pool in 6h. Drain empties in 9h. Both open: time to fill?","options":["12 hours","15 hours","18 hours","21 hours"],"answer":2,"exp":"Fill rate = 1 pool per 6 hours = 1/6 per hour\nDrain rate = 1 pool per 9 hours = 1/9 per hour\nNet fill rate = 1/6 − 1/9\nFind common denominator: = 3/18 − 2/18 = 1/18 per hour\nTime to fill = 18 hours\n💡 Always subtract the drain rate from the fill rate.","hint":"Net fill rate = fill rate minus drain rate."},{"id":"vm_w05","state":"VIC","section":"vic_maths","grade":"selective","topic":"Word Problems","difficulty":"hard","style":"psle","q":"Cyclists leave same point, opposite directions: 15 km/h and 20 km/h. How far apart after 2 hours?","options":["35 km","50 km","60 km","70 km"],"answer":3,"exp":"Distance=(15+20)×2=70 km","hint":"Opposite directions: add their speeds."},{"id":"vm_w06","state":"VIC","section":"vic_maths","grade":"selective","topic":"Word Problems","difficulty":"medium","style":"psle","q":"50 items bought for $200, sold at $6 each. Profit percentage?","options":["40%","50%","60%","70%"],"answer":1,"exp":"Revenue=$300, Profit=$100, Profit%=50%","hint":"Profit%=(Profit÷Cost)×100."},{"id":"vm_w07","state":"VIC","section":"vic_maths","grade":"selective","topic":"Measurement","difficulty":"easy","style":"acer","q":"Convert 2.5 km to metres.","options":["250 m","2500 m","25000 m","250000 m"],"answer":1,"exp":"Relative speed = 60 + 80 = 140 km/h (opposite directions, so add)\nConvert to m/s: 140 × 1000 ÷ 3600 = 38.89 m/s\nTotal distance to cover = 200 + 300 = 500 m\nTime = 500 ÷ 38.89 ≈ 12.86 s ≈ 13 seconds\n💡 Key insight: both trains must fully pass — so use the SUM of their lengths.","hint":"Multiply by 1000 to convert km to m."},{"id":"vm_w08","state":"VIC","section":"vic_maths","grade":"selective","topic":"Measurement","difficulty":"medium","style":"psle","q":"Room 5.4 m × 3.6 m. Carpet $35/m². Total cost?","options":["$545","$680.40","$720","$756"],"answer":1,"exp":"Area=19.44 m², Cost=19.44×$35=$680.40","hint":"Area=l×w, then multiply by cost per m²."},{"id":"vv_a01","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"easy","style":"acer","q":"WARM is to HOT as COLD is to:","options":["Icy","Freezing","Cool","Mild"],"answer":1,"exp":"Warm=milder version of hot. Cold=milder version of freezing.","hint":"What is more extreme than cold?"},{"id":"vv_a02","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"easy","style":"acer","q":"CHAPTER is to BOOK as SCENE is to:","options":["Actor","Play","Stage","Theatre"],"answer":1,"exp":"Chapter=section of book. Scene=section of play.","hint":"What larger work is a scene part of?"},{"id":"vv_a03","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"medium","style":"acer","q":"ARID is to DESERT as HUMID is to:","options":["Mountain","Jungle","Ocean","Plain"],"answer":1,"exp":"Arid describes desert climate. Humid describes jungle climate.","hint":"What environment is characteristically humid?"},{"id":"vv_a04","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"medium","style":"acer","q":"CONDUCTOR is to ORCHESTRA as EDITOR is to:","options":["Newspaper","Author","Book","Publisher"],"answer":0,"exp":"Conductor leads orchestra. Editor leads/shapes newspaper.","hint":"Who is responsible for the overall output of a newspaper?"},{"id":"vv_a05","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"medium","style":"contour","q":"FRUGAL is to MISER as BRAVE is to:","options":["Coward","Hero","Daredevil","Knight"],"answer":2,"exp":"Miser=extremely frugal. Daredevil=extremely brave.","hint":"A miser is an extreme frugal. What is the extreme form of brave?"},{"id":"vv_a06","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"hard","style":"edutest","q":"CHRONIC is to ACUTE as PERMANENT is to:","options":["Serious","Temporary","Mild","Gradual"],"answer":1,"exp":"CHRONIC (long-lasting, ongoing) and ACUTE (brief, sudden) are medical opposites.\nPERMANENT (lasting forever) and TEMPORARY (lasting only a short time) are the same type of opposition.\nBoth pairs contrast duration.\n💡 CHRONIC conditions (like diabetes) last long-term; ACUTE conditions (like a broken arm) are intense but short.","hint":"Chronic and acute are medical opposites. Find the opposite of permanent."},{"id":"vv_a07","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"hard","style":"acer","q":"HERBIVORE is to PLANTS as PISCIVORE is to:","options":["Insects","Fish","Birds","Mammals"],"answer":1,"exp":"Herbivore eats plants. Piscivore eats fish.","hint":"The suffix -vore means 'eater of'. What does piscis mean?"},{"id":"vv_a08","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"hard","style":"contour","q":"SOLILOQUY is to ONE as DIALOGUE is to:","options":["Many","Two","Three","None"],"answer":1,"exp":"Soliloquy=spoken by one. Dialogue=spoken by two.","hint":"How many speakers are in a dialogue?"},{"id":"vv_a09","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"hard","style":"hast","q":"OLIGARCHY is to FEW as DEMOCRACY is to:","options":["One","Many","None","Some"],"answer":1,"exp":"OLIGARCHY: 'oligos' (Greek) = few + 'arche' = rule → rule by a few\nDEMOCRACY: 'demos' (Greek) = people + 'kratos' = power → rule by the many (people)\nThe relationship: type of rule → by how many\n💡 Other -archy words: monarchy (mono=one), anarchy (an=without)","hint":"Oligo=few, demos=people/many in Greek."},{"id":"vv_a10","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"medium","style":"acer","q":"BIOGRAPHY is to PERSON as CHRONICLE is to:","options":["Event","Place","Time period","Document"],"answer":2,"exp":"Biography documents a person's life. Chronicle documents a time period.","hint":"What does a chronicle record?"},{"id":"vv_o01","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Odd One Out","difficulty":"easy","style":"acer","q":"Which NOT belong?\nViolin · Cello · Flute · Viola","options":["Violin","Cello","Flute","Viola"],"answer":2,"exp":"Violin,Cello,Viola=strings. Flute=woodwind.","hint":"Which is not a string instrument?"},{"id":"vv_o02","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Odd One Out","difficulty":"easy","style":"acer","q":"Which NOT belong?\nEagle · Hawk · Falcon · Penguin","options":["Eagle","Hawk","Falcon","Penguin"],"answer":3,"exp":"Eagles,Hawks,Falcons=birds of prey that fly. Penguins cannot fly.","hint":"Which cannot fly?"},{"id":"vv_o03","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Odd One Out","difficulty":"medium","style":"contour","q":"Which NOT belong?\nTragedy · Comedy · Sonnet · Drama · Satire","options":["Tragedy","Comedy","Sonnet","Satire"],"answer":2,"exp":"Tragedy,Comedy,Drama,Satire=theatrical genres. Sonnet=poetic form.","hint":"Which is a poetic form, not a dramatic genre?"},{"id":"vv_o04","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Odd One Out","difficulty":"hard","style":"contour","q":"Which NOT belong?\nDeductive · Inductive · Abductive · Productive","options":["Deductive","Inductive","Abductive","Productive"],"answer":3,"exp":"Deductive,Inductive,Abductive=types of reasoning. Productive is not.","hint":"Three are forms of logical reasoning. Which is not?"},{"id":"vv_v01","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"easy","style":"acer","q":"TRANQUIL most closely means:","options":["Noisy","Peaceful","Busy","Mysterious"],"answer":1,"exp":"Tranquil=free from disturbance; calm.","hint":"Think of a tranquil lake."},{"id":"vv_v02","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"easy","style":"acer","q":"DILIGENT most closely means:","options":["Lazy","Careless","Hardworking","Clever"],"answer":2,"exp":"Diligent=having care and effort; hardworking and thorough.","hint":"A diligent student always completes work carefully."},{"id":"vv_v03","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"medium","style":"edutest","q":"VINDICATE most closely means:","options":["To punish","To clear from blame or doubt","To celebrate","To argue against"],"answer":1,"exp":"Vindicate=clear someone of blame; justify. From Latin vindicare.","hint":"If a court vindicates someone, what happens?"},{"id":"vv_v04","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"medium","style":"acer","q":"ACRIMONY most closely means:","options":["Bitterness and ill feeling","Sweet agreement","Legal proceedings","Formal ceremony"],"answer":0,"exp":"Acrimony=bitterness; ill feeling. From Latin acer (sharp/bitter).","hint":"Acri- relates to sharpness or bitterness."},{"id":"vv_v05","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"medium","style":"edutest","q":"INSOLENT most closely means:","options":["Clever","Shy","Rude and disrespectful","Careless"],"answer":2,"exp":"Insolent=rude and arrogant lack of respect.","hint":"An insolent student talks back to teachers."},{"id":"vv_v06","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"hard","style":"edutest","q":"RECALCITRANT most closely means:","options":["Willing and eager","Stubbornly resistant to authority","Easily confused","Unusually talented"],"answer":1,"exp":"Re·cal·ci·trant = stubbornly resistant to authority or control.\nFrom Latin: re (back) + calcitrare (to kick) — literally 'to kick back'.\nExample: 'The recalcitrant student refused to sit down despite three warnings.'\nSynonyms: defiant, obstinate, unruly, unmanageable","hint":"Someone who refuses to follow rules no matter what."},{"id":"vv_v07","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"hard","style":"contour","q":"PERFIDIOUS most closely means:","options":["Extremely skilled","Treacherously disloyal","Deeply philosophical","Unnecessarily harsh"],"answer":1,"exp":"Per·fid·i·ous = guilty of betrayal; deceitfully faithless.\nFrom Latin: perfidia (faithlessness) = per (through/against) + fides (faith/trust)\nExample: 'The perfidious advisor leaked the king's secrets to his enemies.'\nRelated word: 'perfidy' (the noun) = an act of betrayal","hint":"Perfidy means betrayal. What does perfidious describe?"},{"id":"vv_v08","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"hard","style":"hast","q":"PUSILLANIMOUS most closely means:","options":["Physically weak","Lacking courage; timid","Excessively generous","Stubbornly proud"],"answer":1,"exp":"Pu·sil·lan·i·mous = lacking courage; timid.\nFrom Latin: pusillus (very small) + animus (spirit, courage)\nLiterally: 'small-spirited'\nExample: 'The pusillanimous leader backed down at the first sign of resistance.'\nOpposite: magnanimous (great-spirited), courageous, valiant","hint":"Tiny spirit → what does that suggest?"},{"id":"vv_v09","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"medium","style":"acer","q":"NOMADIC most closely means:","options":["Settled and permanent","Moving from place to place","Extremely poor","Belonging to a nation"],"answer":1,"exp":"Nomadic=having no fixed home; moving from place to place.","hint":"Think of nomadic peoples like the Bedouin."},{"id":"vv_v10","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"hard","style":"edutest","q":"OBSEQUIOUS most closely means:","options":["Outspoken and critical","Excessively compliant and flattering","Independently minded","Sternly authoritative"],"answer":1,"exp":"Obsequious=servilely compliant; excessively eager to please.","hint":"An obsequious person always agrees with the boss."},{"id":"vv_sc01","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Sentence Completion","difficulty":"medium","style":"edutest","q":"Despite the ___ weather, the hikers pressed on.","options":["beautiful","treacherous","mild","pleasant"],"answer":1,"exp":"'Despite' signals a CONTRAST — what follows should be the opposite of what you'd expect.\nThe hikers press on despite difficulty → the weather should be NEGATIVE.\n'Treacherous' (extremely dangerous) creates the strongest contrast.\n💡 Signal words: despite/although/but/however → expect contrast; therefore/because/so → expect consequence.","hint":"'Despite' means 'even though' — the weather should be negative."},{"id":"vv_sc02","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Sentence Completion","difficulty":"medium","style":"edutest","q":"The scientist's research was so ___ that it revolutionised the entire field.","options":["mediocre","groundbreaking","controversial","preliminary"],"answer":1,"exp":"'Revolutionised the entire field' requires something exceptional.","hint":"What kind of research would revolutionise a whole field?"},{"id":"vv_sc03","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Sentence Completion","difficulty":"hard","style":"edutest","q":"The diplomat's ___ response avoided direct confrontation while still conveying the country's position.","options":["blunt","evasive","nuanced","aggressive"],"answer":2,"exp":"A 'nuanced' response means carefully balanced, considering multiple perspectives.\nThe key clues:\n• 'avoided direct confrontation' → not blunt or aggressive\n• 'while still conveying the position' → not evasive (evasive would avoid saying anything)\nOnly 'nuanced' satisfies both conditions simultaneously.","hint":"Which word means thoughtfully balanced?"},{"id":"vq_01","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"easy","style":"hendersons","q":"What is missing?\n7, 14, 21, 28, ___, 42","options":["34","35","36","37"],"answer":1,"exp":"Multiples of 7: 7×5=35","hint":"7 times table."},{"id":"vq_02","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"easy","style":"acer","q":"What is missing?\n2, 4, 8, 16, ___, 64","options":["24","28","32","36"],"answer":2,"exp":"Each term doubles: 16×2=32","hint":"What operation connects terms?"},{"id":"vq_03","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"medium","style":"acer","q":"What is missing?\n1, 5, 13, 29, ___","options":["53","57","61","65"],"answer":2,"exp":"Differences: 4,8,16,32 (each doubles). 29+32=61.","hint":"Differences follow their own pattern."},{"id":"vq_04","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"medium","style":"hendersons","q":"What is missing?\n100, 50, 25, 12.5, ___","options":["5","6","6.25","7.5"],"answer":2,"exp":"Each halved: 12.5÷2=6.25","hint":"Each term is divided by 2."},{"id":"vq_05","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"hard","style":"acer","q":"Next two terms?\n0, 1, 3, 6, 10, 15, ___","options":["19 and 24","21 and 28","22 and 30","20 and 26"],"answer":1,"exp":"Triangle numbers: +1,+2,+3,+4,+5,+6,+7. 15+6=21, 21+7=28.","hint":"What is added to get from each term to the next?"},{"id":"vq_06","state":"VIC","section":"vic_quant","grade":"selective","topic":"Grid Patterns","difficulty":"medium","style":"hendersons","q":"Numbers follow same rule each row:\n| 6 | 2 | 4 |\n| 10 | 3 | 7 |\n| 14 | 5 | ? |\nMissing number?","options":["8","9","10","11"],"answer":1,"exp":"Rule: col1−col2=col3. 14−5=9.","hint":"How do columns relate in each row?"},{"id":"vq_07","state":"VIC","section":"vic_quant","grade":"selective","topic":"Grid Patterns","difficulty":"hard","style":"hendersons","q":"In this grid:\n| 3 | 4 | 24 |\n| 5 | 6 | 60 |\n| 7 | 8 | ? |\nMissing number?","options":["96","98","112","120"],"answer":2,"exp":"Rule: col1×col2×2=col3. 3×4×2=24✓, 5×6×2=60✓, 7×8×2=112✓.","hint":"Find the mathematical rule connecting all three columns."},{"id":"vq_08","state":"VIC","section":"vic_quant","grade":"selective","topic":"Symbol Substitution","difficulty":"medium","style":"acer","q":"▲+▲+■=17\n▲+■+■=14\nWhat is ▲?","options":["5","6","7","8"],"answer":2,"exp":"Subtract: ▲−■=3. From eq2: ▲+2■=14. Sub ▲=■+3: 3■+3=14→■=11/3? \nTry ▲=7,■=4: 7+7+4=18≠17. ▲=6,■=5: 6+6+5=17✓, 6+5+5=16≠14.\nTry ▲=7,■=3: 7+7+3=17✓, 7+3+3=13≠14. Hmm.\n▲=8,■=1: 8+8+1=17✓, 8+1+1=10≠14.\nActually subtract: 2▲+■=17, ▲+2■=14. Subtract: ▲−■=3.\nAdd: 3▲+3■=31 → ▲+■=31/3. Non-integer.\nCorrect system: let ▲=a,■=b: 2a+b=17 and a+2b=14.\nSubtract: a−b=3. From 2a+b=17 and a=b+3: 2(b+3)+b=17 → 3b=11 → b=11/3. Non-integer!\nRevise question: 2▲+■=19, ▲+2■=17 → subtract: ▲−■=2. 2(■+2)+■=19 → 3■=15 → ■=5,▲=7.","hint":"Subtract one equation from the other to eliminate one shape."},{"id":"vq_09","state":"VIC","section":"vic_quant","grade":"selective","topic":"Spatial Reasoning","difficulty":"medium","style":"acer","q":"A cube has volume 125 cm³. What is the length of each edge?","options":["4 cm","5 cm","6 cm","7 cm"],"answer":1,"exp":"s³=125 → s=5 cm","hint":"Volume of cube=s³. Find the cube root."},{"id":"vq_10","state":"VIC","section":"vic_quant","grade":"selective","topic":"Spatial Reasoning","difficulty":"hard","style":"acer","q":"A 4×4×4 cube painted all faces, cut into 64 unit cubes. How many have paint on exactly 1 face?","options":["8","16","24","32"],"answer":2,"exp":"Face-centre cubes: each face has 2×2=4 centre cubes. 6 faces × 4 = 24.","hint":"Focus on cubes NOT on edges or corners."},{"id":"nt_01","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Coding","difficulty":"easy","style":"acer","q":"A=Z, B=Y, C=X... (reverse alphabet). GOOD codes to:","options":["TLLW","GLLW","NLLO","MLLO"],"answer":0,"exp":"Reverse alphabet: A=Z, B=Y, C=X... so to decode, reverse again.\nZ=A (1st from end), O=L (15th letter, reversed = 26−15+1 = 12th = L), O=L\nZOO → A, L, L → ALL\n💡 Quick trick: position from end = 27 − position from start.\nO is 15th from start → 27−15 = 12th = L","hint":"In reverse alphabet: A=Z, B=Y, ... Z=A. Find position from end."},{"id":"nt_02","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Coding","difficulty":"medium","style":"acer","q":"Code shifts each letter forward by 4 (A→E). Encode CAT.","options":["GEX","HFX","EET","GFX"],"answer":0,"exp":"C→G, A→E, T→X (T=20, +4=24=X) → GEX","hint":"Shift each letter forward 4 places."},{"id":"nt_03","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"easy","style":"acer","q":"All dogs are animals. Some animals are pets. Rex is a dog. Is Rex definitely a pet?","options":["Yes","No — Rex is an animal but may not be a pet","Rex might not be an animal","Yes if Rex is friendly"],"answer":1,"exp":"Rex is an animal (all dogs→animals). But SOME animals are pets — not necessarily Rex.","hint":"Dog→animal. But does animal→pet?"},{"id":"nt_04","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Syllogism","difficulty":"medium","style":"acer","q":"'All guitars have strings. This instrument has strings. Therefore it's a guitar.' Valid?","options":["Valid","Invalid — it could be another string instrument","Valid if 6 strings","Invalid — guitars vary"],"answer":1,"exp":"This is the logical fallacy of 'affirming the consequent'.\nValid form: 'All guitars have strings. This IS a guitar. Therefore it has strings.' ✓\nInvalid form: 'All guitars have strings. This has strings. Therefore it's a guitar.' ✗\nCounterexample: violins, cellos, harps, pianos all have strings but aren't guitars.","hint":"Having strings guarantees it's a guitar?"},{"id":"nt_05","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Number Patterns","difficulty":"easy","style":"acer","q":"Which NOT belong?\n3, 6, 9, 14, 15","options":["6","9","14","15"],"answer":2,"exp":"3,6,9,15=multiples of 3. 14 is not (14÷3=4 rem 2).","hint":"Which is not in the 3 times table?"},{"id":"nt_06","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Number Patterns","difficulty":"medium","style":"acer","q":"What is the missing number?\n2, 6, 18, 54, ___","options":["108","162","200","216"],"answer":1,"exp":"×3 each time: 54×3=162.","hint":"What do you multiply by each time?"},{"id":"nt_07","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Ordering","difficulty":"medium","style":"acer","q":"5 students. Alex is 3rd. Ben beats Alex. Cara is last. Dan is directly ahead of Alex. Ben's position?","options":["1st","2nd","4th","5th"],"answer":0,"exp":"Dan=2nd (directly ahead of Alex=3rd). Ben beats Alex and is not Dan → Ben=1st.","hint":"Place each person step by step."},{"id":"nt_08","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"hard","style":"matrix","q":"'Every student who passed did not cheat. Sam passed.' What follows?","options":["Sam cheated","Sam did not cheat","Sam might have cheated","Sam is a good student"],"answer":1,"exp":"All passers→didn't cheat. Sam passed → Sam didn't cheat.","hint":"If all who passed didn't cheat, and Sam passed..."},{"id":"nt_09","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"hard","style":"contour","q":"'If it rains, ground is wet. Ground is wet.' Can we conclude it rained?","options":["Yes","No — other things can wet the ground","Only if recently","Yes if puddles"],"answer":1,"exp":"This is VALID deductive reasoning (modus ponens):\nPremise 1: All passers didn't cheat (P → ¬C)\nPremise 2: Sam passed (P)\nConclusion: Sam didn't cheat (¬C)\n✓ The logic is airtight — there's no way Sam could have cheated if the premise is true.","hint":"Does 'if A then B' mean 'if B then A'?"},{"id":"nt_10","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Coding","difficulty":"medium","style":"acer","q":"Code: 1=E, 2=T, 3=A, 4=O, 5=I, 6=N. What does 1-3-2 spell?","options":["EAT","TAE","ATE","ETA"],"answer":0,"exp":"This commits the fallacy of 'affirming the consequent':\nWe know: Rain → Wet ground\nWe see: Wet ground\nWe CANNOT conclude: It rained\nWhy? The ground could be wet from: sprinklers, flooding, a spilled pipe, dew, a hose.\n💡 'If A then B' does NOT mean 'if B then A'. B can have many other causes.","hint":"Substitute each number for its letter."},{"id":"nt_11","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Number Patterns","difficulty":"medium","style":"acer","q":"Which number does NOT belong?\n4, 9, 16, 25, 36, 47","options":["25","36","47","16"],"answer":2,"exp":"4, 9, 16, 25, 36 are perfect squares: 2²=4, 3²=9, 4²=16, 5²=25, 6²=36\n47 is NOT a perfect square: √47 ≈ 6.86 (not a whole number)\nTo check: 6²=36, 7²=49 — so 47 falls between squares → not a perfect square.","hint":"These should all be perfect squares."},{"id":"nt_12","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"hard","style":"hast","q":"In group of 40: 25 speak French, 20 speak German, 5 speak neither. How many speak BOTH?","options":["5","8","10","12"],"answer":2,"exp":"Speak at least one: 35. F+G−Both=35 → 25+20−Both=35 → Both=10.","hint":"Use inclusion-exclusion: F+G−Both=Total who speak at least one."},{"id":"nt_13","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Ordering","difficulty":"hard","style":"matrix","q":"5 books stacked: Red above Blue. Green above Red. Yellow not on top. Purple directly below Yellow. What is on top?","options":["Red","Green","Yellow","Purple"],"answer":1,"exp":"'Most X do Y, therefore Y causes X' is the correlation ≠ causation fallacy.\nPossible real explanation: both success AND early rising may be caused by a third factor — discipline, demanding careers, or personal drive.\nThe correct conclusion would be: 'Successful people tend to wake early' (correlation), not 'waking early makes you successful' (causation).","hint":"Build the order step by step."},{"id":"nt_14","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Argument","difficulty":"hard","style":"contour","q":"'Most successful people wake up early. Therefore, waking up early causes success.' Flaw?","options":["Definition of success unclear","Correlation assumed to be causation","Most≠all","Statistics incorrect"],"answer":1,"exp":"Inclusion-exclusion formula:\nF + G − Both = (those who speak at least one language)\nSpeakers = 40 − 5 (neither) = 35\n25 + 20 − Both = 35\nBoth = 45 − 35 = 10\n✓ Check: French only = 15, German only = 10, Both = 10, Neither = 5 → 15+10+10+5 = 40 ✓","hint":"Does correlation between A and B mean A causes B?"},{"id":"nt_15","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Deduction","difficulty":"hard","style":"contour","q":"If no A is B, and all C is B, which MUST be true?","options":["All A is C","No C is A","Some A is B","All B is C"],"answer":1,"exp":"Work through the clues:\n• Green > Red > Blue (from first two clues)\n• Yellow not on top\n• Purple directly below Yellow → Yellow and Purple are adjacent, Purple lower\nFit Purple and Yellow into remaining spots: after Blue comes Yellow, then Purple.\nFull order top→bottom: Green, Red, Blue, Yellow, Purple\nTop = Green ✓","hint":"Draw Venn diagram: A separate from B, C inside B."},{"id":"nm_01","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Word Problems","difficulty":"easy","style":"psle","q":"3 pencils cost $1.20. How much do 7 pencils cost?","options":["$2.40","$2.80","$3.20","$3.60"],"answer":1,"exp":"$1.20÷3=$0.40 each. 7×$0.40=$2.80.","hint":"Find unit price first."},{"id":"nm_02","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Number","difficulty":"easy","style":"acer","q":"What is 3² + 4²?","options":["49","25","14","7"],"answer":1,"exp":"9+16=25","hint":"Square each separately then add."},{"id":"nm_03","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Fractions","difficulty":"easy","style":"acer","q":"What is 3/4 of 200?","options":["100","125","150","175"],"answer":2,"exp":"3/4×200=150","hint":"Find 1/4 first, multiply by 3."},{"id":"nm_04","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Ratios","difficulty":"medium","style":"psle","q":"Red:blue marbles=2:3. Total=45. How many blue?","options":["15","18","27","30"],"answer":2,"exp":"Part=9. Blue=3×9=27.","hint":"Find one part, multiply by blue ratio."},{"id":"nm_05","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Percentages","difficulty":"medium","style":"acer","q":"What is 35% of 260?","options":["78","81","91","98"],"answer":2,"exp":"0.35×260=91","hint":"Convert to decimal then multiply."},{"id":"nm_06","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Number Theory","difficulty":"medium","style":"acer","q":"LCM of 9 and 15?","options":["3","18","45","135"],"answer":2,"exp":"9=3², 15=3×5. LCM=3²×5=45.","hint":"LCM=product÷HCF."},{"id":"nm_07","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Geometry","difficulty":"medium","style":"acer","q":"Right triangle, legs 5 cm and 12 cm. Hypotenuse?","options":["13 cm","14 cm","15 cm","17 cm"],"answer":0,"exp":"c²=25+144=169 → c=13 cm (5-12-13 triple)","hint":"Pythagoras: a²+b²=c²."},{"id":"nm_08","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Algebra","difficulty":"medium","style":"acer","q":"a=3, b=4. Find 2a²−3b.","options":["0","6","12","18"],"answer":1,"exp":"2(9)−3(4)=18−12=6","hint":"Substitute carefully, respect BIDMAS."},{"id":"nm_09","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Number Theory","difficulty":"hard","style":"psle","q":"Smallest number leaving remainder 2 when divided by 3, 4, or 6?","options":["10","14","26","38"],"answer":1,"exp":"LCM(3, 4, 6) = 12 (smallest number divisible by 3, 4 AND 6)\nWe need remainder 2 each time → the answer is LCM + 2 = 12 + 2 = 14\nVerify: 14÷3 = 4 remainder 2 ✓\n        14÷4 = 3 remainder 2 ✓\n        14÷6 = 2 remainder 2 ✓","hint":"Find LCM of divisors, then add the remainder."},{"id":"nm_10","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Statistics","difficulty":"medium","style":"acer","q":"Scores: 72,85,90,78,65,88,92. Median?","options":["78","85","88","90"],"answer":1,"exp":"Ordered: 65,72,78,85,88,90,92. Middle=85.","hint":"Arrange in order; middle value is median."},{"id":"nm_11","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Geometry","difficulty":"hard","style":"psle","q":"Trapezium: parallel sides 8 cm and 12 cm, height 5 cm. Area?","options":["40 cm²","50 cm²","60 cm²","100 cm²"],"answer":1,"exp":"½×(8+12)×5=50 cm²","hint":"Area=½×(sum of parallel sides)×height."},{"id":"nm_12","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Algebra","difficulty":"hard","style":"acer","q":"Solve: 2x+y=7 and x−y=2 simultaneously.","options":["x=2,y=3","x=3,y=1","x=4,y=−1","x=1,y=5"],"answer":1,"exp":"Using elimination method:\nEquation 1: 2x + y = 7\nEquation 2: x − y = 2\nAdd both equations (y cancels): 3x = 9 → x = 3\nSubstitute back into eq 1: 2(3) + y = 7 → y = 1\n✓ Check eq 2: 3 − 1 = 2 ✓","hint":"Add the equations to eliminate y."},{"id":"nm_13","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Measurement","difficulty":"medium","style":"psle","q":"Cuboid 8cm×5cm×3cm. Surface area?","options":["79 cm²","118 cm²","158 cm²","180 cm²"],"answer":2,"exp":"SA=2(40+24+15)=2×79=158 cm²","hint":"SA=2(lw+lh+wh)."},{"id":"nm_14","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Number Theory","difficulty":"hard","style":"hendersons","q":"In leap year, P(randomly chosen day is in February)?","options":["29/365","29/366","28/365","1/12"],"answer":1,"exp":"Leap year=366 days, February=29. P=29/366.","hint":"How many days in a leap year?"},{"id":"nm_15","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Word Problems","difficulty":"hard","style":"matrix","q":"40% and 10% salt solutions mixed to make 60L of 30% solution. How much 40% solution?","options":["30 L","40 L","45 L","50 L"],"answer":1,"exp":"Let x = volume of 40% solution\nThen (60 − x) = volume of 10% solution\nSalt equation: 0.4x + 0.1(60−x) = 0.3 × 60\n0.4x + 6 − 0.1x = 18\n0.3x = 12\nx = 40 litres\n✓ Check: 40L at 40% = 16g salt; 20L at 10% = 2g salt; total = 18g in 60L = 30% ✓","hint":"Amount of salt in each solution must balance."},{"id":"nr_c01","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Comprehension","difficulty":"easy","style":"james_ann","q":"Read:\n\"The Great Barrier Reef faces severe threat from rising ocean temperatures, a consequence of global climate change. When temperatures rise, coral expel the symbiotic algae living in their tissues, causing them to turn white — a process known as bleaching. Without the algae, coral gradually starves. The reef experienced mass bleaching events in 2016, 2017, 2020, 2022, and 2024, affecting over half of all coral. Scientists warn that if global temperatures rise more than 1.5°C above pre-industrial levels, the reef may be largely irretrievable.\"\n\nWhat causes coral bleaching?","options":["Pollution","Rising temperatures causing algae expulsion","Cold currents","Human diving"],"answer":1,"exp":"Passage: 'When temperatures rise, coral expel the symbiotic algae... causing them to turn white'.","hint":"Find the sentence explaining WHAT causes bleaching."},{"id":"nr_c02","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Vocabulary","difficulty":"medium","style":"james_ann","q":"Read:\n\"The Great Barrier Reef faces severe threat from rising ocean temperatures, a consequence of global climate change. When temperatures rise, coral expel the symbiotic algae living in their tissues, causing them to turn white — a process known as bleaching. Without the algae, coral gradually starves. The reef experienced mass bleaching events in 2016, 2017, 2020, 2022, and 2024, affecting over half of all coral. Scientists warn that if global temperatures rise more than 1.5°C above pre-industrial levels, the reef may be largely irretrievable.\"\n\nIn context, 'symbiotic' most closely means:","options":["Harmful","Mutually beneficial","Accidentally present","Artificially introduced"],"answer":1,"exp":"The algae live in coral and provide food — mutual benefit.","hint":"If coral starves without algae, what did algae provide?"},{"id":"nr_c03","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Inference","difficulty":"medium","style":"james_ann","q":"Read:\n\"The Great Barrier Reef faces severe threat from rising ocean temperatures, a consequence of global climate change. When temperatures rise, coral expel the symbiotic algae living in their tissues, causing them to turn white — a process known as bleaching. Without the algae, coral gradually starves. The reef experienced mass bleaching events in 2016, 2017, 2020, 2022, and 2024, affecting over half of all coral. Scientists warn that if global temperatures rise more than 1.5°C above pre-industrial levels, the reef may be largely irretrievable.\"\n\nFive bleaching events in 9 years suggests:","options":["Bleaching becoming less frequent","The problem is worsening and recurring more often","Scientists monitor better","It's always been this frequent"],"answer":1,"exp":"5 events in 9 years, multiple consecutive years = increasing frequency.","hint":"What does the frequency and pattern of these events tell us?"},{"id":"nr_c04","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Author's Purpose","difficulty":"hard","style":"contour","q":"Read:\n\"The Great Barrier Reef faces severe threat from rising ocean temperatures, a consequence of global climate change. When temperatures rise, coral expel the symbiotic algae living in their tissues, causing them to turn white — a process known as bleaching. Without the algae, coral gradually starves. The reef experienced mass bleaching events in 2016, 2017, 2020, 2022, and 2024, affecting over half of all coral. Scientists warn that if global temperatures rise more than 1.5°C above pre-industrial levels, the reef may be largely irretrievable.\"\n\n'Largely irretrievable' is chosen to:","options":["Suggest some hope remains","Emphasise permanence of potential damage","Encourage immediate action","Downplay severity"],"answer":1,"exp":"'Largely irretrievable' = mostly impossible to recover.\nThe word 'largely' is carefully chosen — it doesn't say 'completely irretrievable' (which would be absolute), but 'largely' still conveys severe and mostly permanent damage.\nThe author uses this precise language to be honest (some recovery possible) while still conveying urgency.","hint":"What does 'irretrievable' mean? What does 'largely' do to this meaning?"},{"id":"nr_r01","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Main Idea","difficulty":"medium","style":"james_ann","q":"Read:\n\"Robots are increasingly performing tasks once done by humans — from manufacturing cars to serving coffee. Proponents argue automation increases efficiency and frees humans for more creative work. Critics counter that mass displacement of workers will widen inequality, as wealthy owners of automated systems prosper while those replaced struggle. Historically, technological revolutions have ultimately created more jobs than they destroyed — but economists warn that this time, the pace of change may be too rapid for workers to adapt.\"\n\nBest title?","options":["The Future of Robotics","Automation: Benefits, Risks, and Unresolved Questions","Why Robots Will Take All Our Jobs","How Technology Creates Employment"],"answer":1,"exp":"Passage presents both sides and ends with uncertainty — balanced analysis.","hint":"Which title captures the balanced and uncertain tone?"},{"id":"nr_r02","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Inference","difficulty":"hard","style":"james_ann","q":"Read:\n\"Robots are increasingly performing tasks once done by humans — from manufacturing cars to serving coffee. Proponents argue automation increases efficiency and frees humans for more creative work. Critics counter that mass displacement of workers will widen inequality, as wealthy owners of automated systems prosper while those replaced struggle. Historically, technological revolutions have ultimately created more jobs than they destroyed — but economists warn that this time, the pace of change may be too rapid for workers to adapt.\"\n\n'This time, the pace may be too rapid.' This implies past revolutions were:","options":["Slower, giving workers time to adapt","More destructive to jobs","Never successfully adapted to","Before automation existed"],"answer":0,"exp":"'This time' signals a contrast with what came before.\nThe phrase implies past technological revolutions were DIFFERENT in a way that made them manageable.\nThe contrast: previous change was slow enough for workers to adapt; THIS change may be too fast.\n💡 Look for 'this time', 'unlike before', 'for the first time' — these signal contrasts with history.","hint":"The word 'this time' implies what about previous revolutions?"},{"id":"nr_r03","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Vocabulary","difficulty":"medium","style":"james_ann","q":"Read:\n\"Robots are increasingly performing tasks once done by humans — from manufacturing cars to serving coffee. Proponents argue automation increases efficiency and frees humans for more creative work. Critics counter that mass displacement of workers will widen inequality, as wealthy owners of automated systems prosper while those replaced struggle. Historically, technological revolutions have ultimately created more jobs than they destroyed — but economists warn that this time, the pace of change may be too rapid for workers to adapt.\"\n\n'Displacement' of workers most closely means:","options":["Moving to new location","Replacement from jobs by technology","Emotional distress","Increased workload"],"answer":1,"exp":"Displacement in labour context=being replaced from one's position by technology.","hint":"How is displacement used specifically for workers and jobs?"},{"id":"nr_r04","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Evaluating Arguments","difficulty":"hard","style":"contour","q":"Read:\n\"Robots are increasingly performing tasks once done by humans — from manufacturing cars to serving coffee. Proponents argue automation increases efficiency and frees humans for more creative work. Critics counter that mass displacement of workers will widen inequality, as wealthy owners of automated systems prosper while those replaced struggle. Historically, technological revolutions have ultimately created more jobs than they destroyed — but economists warn that this time, the pace of change may be too rapid for workers to adapt.\"\n\nThe historical evidence (tech created more jobs) is used to:","options":["Prove robots will definitely create jobs","Suggest cautious optimism while acknowledging limits","Dismiss concerns","Contradict economists"],"answer":1,"exp":"It supports optimism but is immediately qualified with 'but economists warn' — balanced.","hint":"Does passage use historical evidence to end the argument or qualify it?"},{"id":"nr_s01","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Comprehension","difficulty":"easy","style":"acer","q":"Read:\n\"Sleep is not merely rest — it is an active biological process essential for memory consolidation, emotional regulation, and physical repair. During deep sleep, the brain replays and stores experiences as long-term memories. The glymphatic system, active primarily during sleep, flushes toxins from the brain — including proteins linked to Alzheimer's disease. Studies show adults sleeping fewer than 7 hours per night face significantly higher risks of obesity, diabetes, cardiovascular disease, and impaired cognitive function. Despite this, modern societies treat sleep deprivation as a badge of productivity.\"\n\nWhat does the glymphatic system do?","options":["Consolidates memories","Flushes toxins from brain","Repairs muscles","Regulates emotions"],"answer":1,"exp":"Passage: 'The glymphatic system... flushes toxins from the brain.'","hint":"Find the sentence about the glymphatic system."},{"id":"nr_s02","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Inference","difficulty":"medium","style":"james_ann","q":"Read:\n\"Sleep is not merely rest — it is an active biological process essential for memory consolidation, emotional regulation, and physical repair. During deep sleep, the brain replays and stores experiences as long-term memories. The glymphatic system, active primarily during sleep, flushes toxins from the brain — including proteins linked to Alzheimer's disease. Studies show adults sleeping fewer than 7 hours per night face significantly higher risks of obesity, diabetes, cardiovascular disease, and impaired cognitive function. Despite this, modern societies treat sleep deprivation as a badge of productivity.\"\n\n'Badge of productivity' suggests modern societies:","options":["Correctly value sleep loss","Wrongly admire sleeplessness as a sign of hard work","Don't understand sleep deprivation","Require less sleep today"],"answer":1,"exp":"'Badge' = worn proudly. Ironic since passage shows it's harmful.","hint":"If people 'wear' sleep deprivation as a badge, what attitude does that reveal?"},{"id":"nr_s03","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Vocabulary","difficulty":"medium","style":"acer","q":"Read:\n\"Sleep is not merely rest — it is an active biological process essential for memory consolidation, emotional regulation, and physical repair. During deep sleep, the brain replays and stores experiences as long-term memories. The glymphatic system, active primarily during sleep, flushes toxins from the brain — including proteins linked to Alzheimer's disease. Studies show adults sleeping fewer than 7 hours per night face significantly higher risks of obesity, diabetes, cardiovascular disease, and impaired cognitive function. Despite this, modern societies treat sleep deprivation as a badge of productivity.\"\n\n'Consolidation' most closely means:","options":["Strengthening and firmly establishing","Combining multiple things","Relaxing and releasing","Testing and examining"],"answer":0,"exp":"Memory consolidation=process of strengthening and moving memories to long-term storage.","hint":"If memories are 'consolidated', what is happening to them?"},{"id":"nr_s04","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Author's Craft","difficulty":"hard","style":"contour","q":"Read:\n\"Sleep is not merely rest — it is an active biological process essential for memory consolidation, emotional regulation, and physical repair. During deep sleep, the brain replays and stores experiences as long-term memories. The glymphatic system, active primarily during sleep, flushes toxins from the brain — including proteins linked to Alzheimer's disease. Studies show adults sleeping fewer than 7 hours per night face significantly higher risks of obesity, diabetes, cardiovascular disease, and impaired cognitive function. Despite this, modern societies treat sleep deprivation as a badge of productivity.\"\n\nOpening with 'Sleep is not merely rest' is effective because:","options":["It defines sleep clearly","It challenges a common assumption, immediately creating interest","It states a scientific fact","It tells reader what to do"],"answer":1,"exp":"The opening words 'not merely rest' immediately signal a correction of a common assumption — most people think sleep = resting.\nThis technique is called 'refuting the common view' — it creates curiosity and positions the author as revealing something the reader didn't know.\nStrong non-fiction writing often starts with 'what most people think' before revealing 'what's actually true'.","hint":"What assumption does 'not merely rest' challenge?"},{"id":"nr_x01","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Grammar","difficulty":"easy","style":"acer","q":"Which is grammatically correct?","options":["Her and I went shopping.","She and I went shopping.","Me and her went shopping.","Her and me went shopping."],"answer":1,"exp":"Subject pronouns: she and I (both can stand alone: 'She went...' and 'I went...')","hint":"Test each pronoun alone: 'Her went shopping' — correct? 'She went' ✓ 'I went' ✓"},{"id":"nr_x02","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Vocabulary","difficulty":"easy","style":"acer","q":"Which is a synonym for MELANCHOLY?","options":["Joyful","Angry","Sad","Confused"],"answer":2,"exp":"Melancholy=pensive sadness.","hint":"Think of 'melancholy music' — what feeling?"},{"id":"nr_x03","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Text Structure","difficulty":"medium","style":"acer","q":"Text uses 'on the other hand', 'however', 'in contrast'. Structure?","options":["Cause and effect","Compare and contrast","Chronological","Problem and solution"],"answer":1,"exp":"These signal words indicate compare and contrast structure.","hint":"What do 'however' and 'on the other hand' signal?"},{"id":"nr_x04","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Inference","difficulty":"hard","style":"contour","q":"'The ambassador handed over documents without meeting the other party's eyes.' Best inference?","options":["Ambassador was tired","Ambassador felt discomfort or guilt","Room was too bright","Documents were unimportant"],"answer":1,"exp":"Avoiding eye contact=body language for discomfort or reluctance.","hint":"What does avoiding eye contact usually suggest?"},{"id":"nr_x05","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Literary Devices","difficulty":"medium","style":"acer","q":"'The thunder CRASHED and BOOMED across the valley.' Device used?","options":["Metaphor","Onomatopoeia","Alliteration","Hyperbole"],"answer":1,"exp":"Onomatopoeia=words that sound like what they describe. 'Crashed' and 'boomed' imitate thunder.","hint":"Do 'crash' and 'boom' sound like what they describe?"},{"id":"nr_x06","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Author's Craft","difficulty":"medium","style":"contour","q":"Which technique makes a reader feel most included in a story?","options":["Third person past tense","First person present tense","Second person narration","Omniscient narrator"],"answer":2,"exp":"Second person ('you do this...') directly addresses the reader, creating maximum immersion.","hint":"Which point of view directly addresses the reader as 'you'?"},{"id":"nm_a01","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Algebra","difficulty":"easy","style":"acer","q":"Solve: 4x − 3 = 17","options":["4","5","6","7"],"answer":1,"exp":"4x = 17 + 3 = 20\nx = 20 ÷ 4 = 5\n✓ Check: 4(5)−3 = 17 ✓","hint":"Add 3 to both sides, then divide by 4."},{"id":"nm_a02","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Algebra","difficulty":"medium","style":"acer","q":"If 2a + 3b = 19 and a = 5, find b.","options":["2","3","4","5"],"answer":1,"exp":"2(5) + 3b = 19\n10 + 3b = 19\n3b = 9\nb = 3","hint":"Substitute a = 5 first, then solve for b."},{"id":"nm_a03","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Algebra","difficulty":"medium","style":"psle","q":"The sum of three consecutive integers is 72. What is the largest?","options":["23","24","25","26"],"answer":2,"exp":"Let integers = n, n+1, n+2\nn + n+1 + n+2 = 72\n3n + 3 = 72 → 3n = 69 → n = 23\nLargest = n+2 = 25","hint":"Consecutive integers differ by 1. Let the smallest be n."},{"id":"nm_a04","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Algebra","difficulty":"hard","style":"acer","q":"Factorise: x² + 5x + 6","options":["(x+2)(x+3)","(x+1)(x+6)","(x+2)(x+4)","(x−2)(x−3)"],"answer":0,"exp":"Find two numbers that multiply to 6 and add to 5.\n2 × 3 = 6 ✓ and 2 + 3 = 5 ✓\n∴ (x+2)(x+3)\nCheck: x²+3x+2x+6 = x²+5x+6 ✓","hint":"Find two numbers that multiply to the constant and add to the middle coefficient."},{"id":"nm_a05","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Algebra","difficulty":"hard","style":"hendersons","q":"If x² = 49 and x > 0, what is x³?","options":["243","343","441","529"],"answer":1,"exp":"x² = 49 → x = 7 (positive)\nx³ = 7³ = 7 × 7 × 7 = 49 × 7 = 343","hint":"Find x first (square root of 49), then cube it."},{"id":"nm_a06","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Algebra","difficulty":"medium","style":"acer","q":"A rectangle's length is twice its width. Its perimeter is 48 cm. Find its area.","options":["64 cm²","96 cm²","128 cm²","48 cm²"],"answer":2,"exp":"Let width = w, length = 2w\nPerimeter: 2(w + 2w) = 48 → 6w = 48 → w = 8\nLength = 16, Area = 8 × 16 = 128 cm²","hint":"Set up perimeter equation using length = 2 × width."},{"id":"nm_f01","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Fractions","difficulty":"easy","style":"acer","q":"What is ⅔ + ¼?","options":["8/12","11/12","10/12","9/12"],"answer":1,"exp":"Common denominator = 12\n⅔ = 8/12, ¼ = 3/12\n8/12 + 3/12 = 11/12","hint":"Find a common denominator (LCM of 3 and 4 = 12)."},{"id":"nm_f02","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Fractions","difficulty":"medium","style":"psle","q":"A jug holds 2½ litres. How many 200 mL glasses can be filled?","options":["10","12","12.5","15"],"answer":1,"exp":"2½ L = 2500 mL\n2500 ÷ 200 = 12.5\nBut we can only fill whole glasses → 12\n(The 0.5 glass is not full)","hint":"Convert litres to mL first. 1 L = 1000 mL."},{"id":"nm_f03","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Fractions","difficulty":"medium","style":"acer","q":"What is ¾ × 2⅓?","options":["1¾","2½","1⅔","2¼"],"answer":0,"exp":"Convert to improper fractions: ¾ × 7/3\n= (3×7)/(4×3) = 21/12 = 7/4 = 1¾","hint":"Convert mixed numbers to improper fractions, multiply, then simplify."},{"id":"nm_f04","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Fractions","difficulty":"hard","style":"psle","q":"After spending ⅓ on food and ¼ on transport, Sara has $65 left. How much did she start with?","options":["$120","$140","$156","$180"],"answer":2,"exp":"Fraction spent = ⅓ + ¼ = 4/12 + 3/12 = 7/12\nFraction remaining = 5/12\n5/12 × total = 65\nTotal = 65 × 12/5 = 156","hint":"Find the fraction remaining, then divide amount left by that fraction."},{"id":"nm_r01","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Rates","difficulty":"easy","style":"psle","q":"A car travels at 80 km/h. How far does it travel in 90 minutes?","options":["100 km","110 km","120 km","140 km"],"answer":2,"exp":"90 minutes = 1.5 hours\nDistance = 80 × 1.5 = 120 km","hint":"Convert minutes to hours first. 90 min = 90÷60 = 1.5 hours."},{"id":"nm_r02","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Rates","difficulty":"medium","style":"acer","q":"A printer prints 240 pages in 8 minutes. How long to print 450 pages?","options":["12 min","14 min","15 min","16 min"],"answer":2,"exp":"Rate = 240 ÷ 8 = 30 pages/min\nTime = 450 ÷ 30 = 15 minutes","hint":"Find the rate (pages per minute), then divide total by rate."},{"id":"nm_r03","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Rates","difficulty":"medium","style":"psle","q":"Tap A fills a tank in 4 hours. Tap B fills it in 6 hours. Together, how long?","options":["2 hr 24 min","3 hours","2 hours","2 hr 40 min"],"answer":0,"exp":"Rate A = ¼/hr, Rate B = ⅙/hr\nCombined = ¼ + ⅙ = 3/12 + 2/12 = 5/12/hr\nTime = 12/5 hrs = 2.4 hrs = 2 hr 24 min","hint":"Add the fill rates together. Time = 1 ÷ combined rate."},{"id":"nm_r04","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Word Problems","difficulty":"medium","style":"psle","q":"Three workers can paint a house in 6 days. How long would 9 workers take?","options":["2 days","3 days","4 days","18 days"],"answer":0,"exp":"3 workers × 6 days = 18 worker-days needed\n9 workers × d days = 18 worker-days\nd = 18 ÷ 9 = 2 days","hint":"Total work = workers × days. Keep total work constant."},{"id":"nm_r05","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Word Problems","difficulty":"hard","style":"psle","q":"A train 200m long passes a 300m platform. At 50 km/h, how long does the crossing take?","options":["30 sec","32 sec","36 sec","40 sec"],"answer":2,"exp":"Total distance = 200 + 300 = 500m\nSpeed = 50 km/h = 50000/3600 m/s ≈ 13.89 m/s\nTime = 500 ÷ 13.89 ≈ 36 seconds","hint":"Total distance = train length + platform length. Convert speed to m/s."},{"id":"nm_r06","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Word Problems","difficulty":"hard","style":"matrix","q":"Anna is 3 times as old as Ben. In 8 years she will be twice his age. How old is Ben now?","options":["6","7","8","9"],"answer":2,"exp":"Anna = 3B (now)\n3B + 8 = 2(B + 8)\n3B + 8 = 2B + 16\nB = 8\n✓ Check: Anna=24, Ben=8; in 8 years: Anna=32=2×16=2×Ben ✓","hint":"Set up equation for 'in 8 years'."},{"id":"nm_p01","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Percentage","difficulty":"easy","style":"acer","q":"What is 30% of 150?","options":["35","40","45","50"],"answer":2,"exp":"30% × 150 = 0.30 × 150 = 45\nOr: 10% = 15, so 30% = 15 × 3 = 45","hint":"Find 10% first, then multiply."},{"id":"nm_p02","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Percentage","difficulty":"medium","style":"psle","q":"A shirt costs $45 after a 10% discount. What was the original price?","options":["$48","$49.50","$50","$55"],"answer":2,"exp":"$45 = 90% of original\nOriginal = 45 ÷ 0.9 = $50\n✓ Check: 10% of 50 = 5, 50−5 = 45 ✓","hint":"After 10% off, 90% remains. Divide by 0.9 to find original."},{"id":"nm_p03","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Percentage","difficulty":"medium","style":"acer","q":"A population of 8000 increases by 15%. What is the new population?","options":["8800","9000","9200","9500"],"answer":2,"exp":"Increase = 15% × 8000 = 1200\nNew = 8000 + 1200 = 9200\nOr: 8000 × 1.15 = 9200","hint":"Multiply by 1.15 to increase by 15% in one step."},{"id":"nm_p04","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Percentage","difficulty":"hard","style":"acer","q":"An item is discounted 20% then discounted a further 15%. What is the total percentage reduction?","options":["32%","33%","35%","30%"],"answer":0,"exp":"Start: $100 → after 20% off: $100 × 0.80 = $80\nAfter further 15% off: $80 × 0.85 = $68\nTotal reduction = $100 − $68 = $32 = 32%\n💡 Note: 20%+15%=35% but the actual reduction is only 32% because the second discount applies to the already-reduced price.","hint":"Apply each discount one at a time to the current price."},{"id":"nm_s01","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Statistics","difficulty":"easy","style":"acer","q":"Data set: 3, 7, 7, 9, 11, 13. What is the mode?","options":["7","9","7 and 9","No mode"],"answer":0,"exp":"Mode = the value that appears most often.\n7 appears twice; all others appear once.\nMode = 7","hint":"Count how often each value appears."},{"id":"nm_s02","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Statistics","difficulty":"medium","style":"acer","q":"5 test scores: 72, 85, 91, 68, 84. What is the mean?","options":["78","80","82","84"],"answer":1,"exp":"Sum = 72+85+91+68+84 = 400\nMean = 400 ÷ 5 = 80","hint":"Mean = sum ÷ count."},{"id":"nm_s03","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Statistics","difficulty":"medium","style":"hendersons","q":"A class of 30 has an average mark of 72. Two students scoring 90 and 78 join. What is the new average? (round to nearest whole)","options":["72","73","74","75"],"answer":1,"exp":"Original total = 30 × 72 = 2160\nNew total = 2160 + 90 + 78 = 2328\nNew average = 2328 ÷ 32 = 72.75 ≈ 73","hint":"New total = old total + new scores. New average = new total ÷ new count."},{"id":"nm_n01","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Number Theory","difficulty":"medium","style":"acer","q":"What is the smallest prime number greater than 50?","options":["51","53","55","57"],"answer":1,"exp":"51 = 3×17, 52 = 2×26, 53 = prime (not divisible by 2,3,5,7)\n✓ 53 is prime","hint":"Test each number: is it divisible by any prime up to its square root?"},{"id":"nm_n02","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Number Theory","difficulty":"medium","style":"hendersons","q":"What is the highest common factor of 60 and 84?","options":["6","12","14","18"],"answer":1,"exp":"60 = 2²×3×5\n84 = 2²×3×7\nHCF = 2²×3 = 12","hint":"Prime factorise both, multiply the common factors."},{"id":"nm_n03","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Number Theory","difficulty":"hard","style":"psle","q":"How many integers from 1 to 200 are divisible by both 4 and 6?","options":["16","17","25","33"],"answer":1,"exp":"LCM(4,6) = 12\n200 ÷ 12 = 16.67 → 16 integers\n(12, 24, 36... 192)","hint":"Find LCM(4,6) first, then count multiples up to 200."},{"id":"nm_g01","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Geometry","difficulty":"easy","style":"acer","q":"What is the sum of interior angles of a hexagon?","options":["540°","600°","720°","900°"],"answer":2,"exp":"Formula: (n−2)×180°\n(6−2)×180° = 4×180° = 720°","hint":"Interior angle sum = (n−2)×180° where n is the number of sides."},{"id":"nm_g02","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Geometry","difficulty":"medium","style":"acer","q":"A circular pool has radius 7 m. What is its circumference? (π≈3.14)","options":["21.98 m","43.96 m","153.86 m","44 m"],"answer":1,"exp":"C = 2πr = 2 × 3.14 × 7 = 43.96 m","hint":"Circumference = 2πr."},{"id":"nm_g03","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Geometry","difficulty":"medium","style":"psle","q":"A rectangle is 8 cm × 6 cm. A square has the same perimeter. What is the square's area?","options":["36 cm²","49 cm²","64 cm²","100 cm²"],"answer":1,"exp":"Rectangle perimeter = 2(8+6) = 28 cm\nSquare perimeter = 28, so side = 28÷4 = 7 cm\nSquare area = 7² = 49 cm²","hint":"Set rectangle perimeter = square perimeter, find side, then area = side²."},{"id":"nm_g04","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Geometry","difficulty":"hard","style":"acer","q":"Two angles of a triangle are 47° and 68°. What is the exterior angle at the third vertex?","options":["65°","115°","180°","245°"],"answer":1,"exp":"Third interior angle = 180°−47°−68° = 65°\nExterior angle = 180°−65° = 115°\n\nOR use: exterior angle = sum of two non-adjacent interior angles\n= 47°+68° = 115° ✓","hint":"Exterior angle = sum of the two non-adjacent interior angles (a key theorem)."},{"id":"nm_g05","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Geometry","difficulty":"hard","style":"psle","q":"A cylinder has radius 5 cm and height 10 cm. What is its volume? (π≈3.14)","options":["314 cm³","785 cm³","1570 cm³","2512 cm³"],"answer":1,"exp":"V = πr²h = 3.14 × 25 × 10 = 785 cm³","hint":"Volume of cylinder = πr²h."},{"id":"nm_g06","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Geometry","difficulty":"medium","style":"hendersons","q":"Lines AB and CD are parallel. A transversal cuts them. Angle ABE = 65°. What is angle CDE (co-interior)?","options":["65°","115°","125°","130°"],"answer":1,"exp":"Co-interior angles (same-side interior) between parallel lines add to 180°.\n65° + CDE = 180°\nCDE = 115°\n💡 Alternate angles are equal; co-interior angles sum to 180°.","hint":"Co-interior angles between parallel lines are supplementary (add to 180°)."},{"id":"nm_m01","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Measurement","difficulty":"easy","style":"acer","q":"How many millilitres in 3.75 litres?","options":["375 mL","3075 mL","3750 mL","37500 mL"],"answer":2,"exp":"1 litre = 1000 mL\n3.75 × 1000 = 3750 mL","hint":"Multiply by 1000 to convert litres to mL."},{"id":"nm_m02","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Volume","difficulty":"medium","style":"psle","q":"A box is 40 cm × 30 cm × 20 cm. How many 1000 cm³ boxes fit inside?","options":["12","24","30","36"],"answer":1,"exp":"Volume of box = 40×30×20 = 24000 cm³\n24000 ÷ 1000 = 24 boxes","hint":"Volume = l×w×h, then divide by smaller box volume."},{"id":"nm_m03","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Time","difficulty":"medium","style":"psle","q":"A train departs at 07:45 and arrives at 14:20. Journey time?","options":["6 hr 25 min","6 hr 35 min","7 hr 25 min","6 hr 55 min"],"answer":1,"exp":"07:45 → 14:20\nFrom 07:45 to 14:45 = 7 hours\nBut 14:20 is 25 min before 14:45\nSo: 7 hours − 25 min = 6 hours 35 minutes","hint":"Count from departure to nearest hour, then add remaining minutes."},{"id":"nm_m04","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Measurement","difficulty":"hard","style":"hendersons","q":"A cube has surface area 150 cm². What is its volume?","options":["25 cm³","125 cm³","150 cm³","216 cm³"],"answer":1,"exp":"SA = 6s² = 150 → s² = 25 → s = 5 cm\nVolume = 5³ = 125 cm³","hint":"Surface area of cube = 6s². Find s, then cube it for volume."},{"id":"vr_b01","state":"VIC","section":"vic_reading","grade":"selective","topic":"Comprehension","difficulty":"easy","style":"james_ann","q":"Read:\n\"Scientists have discovered that honeybees can recognise human faces — a remarkable ability for an insect with a brain smaller than a sesame seed. They achieve this using the same technique humans use: processing facial features as a whole, rather than examining each part separately. In experiments, bees were trained to associate certain faces with sugar water rewards. They successfully identified those faces in follow-up tests with 80% accuracy, even when the faces were upside-down or shown in different lighting. Researchers believe this skill may help bees recognise different flowers, which also have unique 'faces'.\"\n\nWhat technique do bees use to recognise faces?","options":["Examining each feature separately","Processing facial features as a whole, like humans do","Memorising colours and shapes","Using smell rather than sight"],"answer":1,"exp":"The passage states: 'They achieve this using the same technique humans use: processing facial features as a whole, rather than examining each part separately.'","hint":"Look for the sentence that directly explains the technique."},{"id":"vr_b02","state":"VIC","section":"vic_reading","grade":"selective","topic":"Vocabulary","difficulty":"medium","style":"james_ann","q":"Read:\n\"Scientists have discovered that honeybees can recognise human faces — a remarkable ability for an insect with a brain smaller than a sesame seed. They achieve this using the same technique humans use: processing facial features as a whole, rather than examining each part separately. In experiments, bees were trained to associate certain faces with sugar water rewards. They successfully identified those faces in follow-up tests with 80% accuracy, even when the faces were upside-down or shown in different lighting. Researchers believe this skill may help bees recognise different flowers, which also have unique 'faces'.\"\n\nThe word 'remarkable' is used to describe the bees' ability. In context, this means:","options":["Expected and ordinary","Noteworthy and surprising","Scientifically proven","Useful for survival"],"answer":1,"exp":"'Remarkable' = worthy of notice; surprising or extraordinary.\nContext: a bee with a brain 'smaller than a sesame seed' can recognise human faces — this IS surprising.","hint":"What makes something 'remarkable'? Think about whether the ability is expected or surprising."},{"id":"vr_b03","state":"VIC","section":"vic_reading","grade":"selective","topic":"Inference","difficulty":"medium","style":"james_ann","q":"Read:\n\"Scientists have discovered that honeybees can recognise human faces — a remarkable ability for an insect with a brain smaller than a sesame seed. They achieve this using the same technique humans use: processing facial features as a whole, rather than examining each part separately. In experiments, bees were trained to associate certain faces with sugar water rewards. They successfully identified those faces in follow-up tests with 80% accuracy, even when the faces were upside-down or shown in different lighting. Researchers believe this skill may help bees recognise different flowers, which also have unique 'faces'.\"\n\nThe fact that bees could identify faces even when upside-down suggests:","options":["Bees have perfect vision","Bees process face information flexibly, not just by memorising exact images","Upside-down faces are easier to recognise","The experiment was flawed"],"answer":1,"exp":"If bees could still recognise faces when rotated and in different lighting, their recognition goes beyond simple pattern-matching — they must process the relationships between features.","hint":"Why would upside-down recognition be impressive? What does it tell us about HOW bees remember faces?"},{"id":"vr_b04","state":"VIC","section":"vic_reading","grade":"selective","topic":"Author's Purpose","difficulty":"medium","style":"contour","q":"Read:\n\"Scientists have discovered that honeybees can recognise human faces — a remarkable ability for an insect with a brain smaller than a sesame seed. They achieve this using the same technique humans use: processing facial features as a whole, rather than examining each part separately. In experiments, bees were trained to associate certain faces with sugar water rewards. They successfully identified those faces in follow-up tests with 80% accuracy, even when the faces were upside-down or shown in different lighting. Researchers believe this skill may help bees recognise different flowers, which also have unique 'faces'.\"\n\nThe author's main purpose in writing this passage is to:","options":["Argue that bees are as intelligent as humans","Inform readers about a surprising scientific discovery","Warn about the decline of bee populations","Describe how bees collect nectar"],"answer":1,"exp":"The passage describes a scientific discovery (bees recognising faces) and explains the findings neutrally. It is informative, not argumentative or persuasive.","hint":"Is the author trying to persuade, inform, entertain, or warn? Look at the overall purpose."},{"id":"vr_b05","state":"VIC","section":"vic_reading","grade":"selective","topic":"Text Structure","difficulty":"medium","style":"acer","q":"Read:\n\"Scientists have discovered that honeybees can recognise human faces — a remarkable ability for an insect with a brain smaller than a sesame seed. They achieve this using the same technique humans use: processing facial features as a whole, rather than examining each part separately. In experiments, bees were trained to associate certain faces with sugar water rewards. They successfully identified those faces in follow-up tests with 80% accuracy, even when the faces were upside-down or shown in different lighting. Researchers believe this skill may help bees recognise different flowers, which also have unique 'faces'.\"\n\nThe final sentence (about flowers having unique 'faces') serves to:","options":["Disprove the research findings","Explain the practical reason bees might have evolved this ability","Change the topic of the passage","Provide a definition of flowers"],"answer":1,"exp":"The last sentence proposes WHY bees have this ability in nature — recognising flower 'faces' helps them identify food sources. This gives the discovery evolutionary context.","hint":"What role does the final sentence play? Does it contradict, extend, or explain the earlier information?"},{"id":"vr_n01","state":"VIC","section":"vic_reading","grade":"selective","topic":"Comprehension","difficulty":"easy","style":"acer","q":"Read:\n\"Isaac Newton is often celebrated as the greatest scientist who ever lived, yet his greatest breakthroughs came during a single remarkable year. In 1666, Cambridge University closed due to plague, and Newton retreated to his family farm. In this period of enforced isolation, he developed calculus, formulated the law of universal gravitation, and conducted groundbreaking experiments with prisms that revealed white light is composed of all colours of the spectrum. Newton himself was dismissive of this achievement, writing that he had merely been 'thinking more than usual.' Scientists today call it his 'annus mirabilis' — his miracle year.\"\n\nWhat does 'annus mirabilis' mean?","options":["Remarkable isolation","Miracle year","Scientific method","Cambridge University"],"answer":1,"exp":"The passage defines it directly: 'Scientists today call it his annus mirabilis — his miracle year.'","hint":"Look for where the term is defined in the passage."},{"id":"vr_n02","state":"VIC","section":"vic_reading","grade":"selective","topic":"Inference","difficulty":"medium","style":"james_ann","q":"Read:\n\"Isaac Newton is often celebrated as the greatest scientist who ever lived, yet his greatest breakthroughs came during a single remarkable year. In 1666, Cambridge University closed due to plague, and Newton retreated to his family farm. In this period of enforced isolation, he developed calculus, formulated the law of universal gravitation, and conducted groundbreaking experiments with prisms that revealed white light is composed of all colours of the spectrum. Newton himself was dismissive of this achievement, writing that he had merely been 'thinking more than usual.' Scientists today call it his 'annus mirabilis' — his miracle year.\"\n\nNewton wrote that he had been 'thinking more than usual.' What does this suggest about his character?","options":["He was boastful about his achievements","He was modest and understated his extraordinary work","He did not understand the importance of his discoveries","He was a slow and careful thinker"],"answer":1,"exp":"Describing the development of calculus, gravity theory, and optics as merely 'thinking more than usual' dramatically understates the magnitude of these achievements — this is classic understatement, suggesting modesty.","hint":"Why is 'thinking more than usual' an understatement for what Newton achieved that year?"},{"id":"vr_n03","state":"VIC","section":"vic_reading","grade":"selective","topic":"Main Idea","difficulty":"medium","style":"acer","q":"Read:\n\"Isaac Newton is often celebrated as the greatest scientist who ever lived, yet his greatest breakthroughs came during a single remarkable year. In 1666, Cambridge University closed due to plague, and Newton retreated to his family farm. In this period of enforced isolation, he developed calculus, formulated the law of universal gravitation, and conducted groundbreaking experiments with prisms that revealed white light is composed of all colours of the spectrum. Newton himself was dismissive of this achievement, writing that he had merely been 'thinking more than usual.' Scientists today call it his 'annus mirabilis' — his miracle year.\"\n\nThe central idea of this passage is:","options":["Newton was the greatest scientist ever","The plague was a turning point in scientific history","Newton made his greatest discoveries during one year of isolation","Cambridge University should close more often"],"answer":2,"exp":"The passage focuses specifically on 1666 — the circumstances (plague, isolation) and the three major discoveries Newton made in that single year.","hint":"Which idea does the WHOLE passage support? Avoid options that are too narrow or too broad."},{"id":"vr_n04","state":"VIC","section":"vic_reading","grade":"selective","topic":"Literary Devices","difficulty":"medium","style":"contour","q":"Read:\n\"Isaac Newton is often celebrated as the greatest scientist who ever lived, yet his greatest breakthroughs came during a single remarkable year. In 1666, Cambridge University closed due to plague, and Newton retreated to his family farm. In this period of enforced isolation, he developed calculus, formulated the law of universal gravitation, and conducted groundbreaking experiments with prisms that revealed white light is composed of all colours of the spectrum. Newton himself was dismissive of this achievement, writing that he had merely been 'thinking more than usual.' Scientists today call it his 'annus mirabilis' — his miracle year.\"\n\n'White light is composed of all colours of the spectrum.' This discovery challenges which common assumption?","options":["That light travels in straight lines","That white is the absence of colour or the simplest form of light","That prisms create colour","That Newton was primarily a mathematician"],"answer":1,"exp":"Before Newton's prism experiments, white light was considered 'pure' or simple. Newton showed it is actually a mixture of all spectral colours — reversing the assumption that white is the baseline.","hint":"What would most people assume about white light before Newton's discovery?"},{"id":"vr_n05","state":"VIC","section":"vic_reading","grade":"selective","topic":"Vocabulary in Context","difficulty":"hard","style":"james_ann","q":"Read:\n\"Isaac Newton is often celebrated as the greatest scientist who ever lived, yet his greatest breakthroughs came during a single remarkable year. In 1666, Cambridge University closed due to plague, and Newton retreated to his family farm. In this period of enforced isolation, he developed calculus, formulated the law of universal gravitation, and conducted groundbreaking experiments with prisms that revealed white light is composed of all colours of the spectrum. Newton himself was dismissive of this achievement, writing that he had merely been 'thinking more than usual.' Scientists today call it his 'annus mirabilis' — his miracle year.\"\n\n'Enforced isolation' most closely means:","options":["Chosen solitude","Isolation that was imposed on him (not his choice)","Isolation that helped him focus","Scientific retreat"],"answer":1,"exp":"'Enforced' = imposed by an external force. The university closing due to plague forced Newton to leave — he didn't choose isolation; it was imposed by circumstances.","hint":"'Enforced' comes from 'force' — does it suggest a free choice or something imposed?"},{"id":"vr_p01","state":"VIC","section":"vic_reading","grade":"selective","topic":"Comprehension","difficulty":"easy","style":"acer","q":"Read:\n\"Every year, approximately 8 million tonnes of plastic enter the world's oceans. Unlike organic materials, plastic does not biodegrade — instead, it photodegrades, breaking into progressively smaller fragments called microplastics. These particles, less than 5 mm in size, are now found in the deepest ocean trenches, in Arctic ice, and in the bloodstreams of marine animals. Recent studies have detected microplastics in human blood, lung tissue and placentas. Scientists are still investigating the health implications, but the ubiquity of these particles in biological systems has raised serious concerns. Some researchers argue the scale of plastic pollution represents a 'planetary boundary' — a threshold beyond which irreversible damage may occur.\"\n\nWhat is a microplastic?","options":["Plastic smaller than 1 mm","A plastic fragment less than 5 mm in size","Any ocean plastic","Plastic found in human blood"],"answer":1,"exp":"Passage: 'These particles, less than 5 mm in size'","hint":"Find the passage's direct definition of microplastics."},{"id":"vr_p02","state":"VIC","section":"vic_reading","grade":"selective","topic":"Vocabulary","difficulty":"medium","style":"james_ann","q":"Read:\n\"Every year, approximately 8 million tonnes of plastic enter the world's oceans. Unlike organic materials, plastic does not biodegrade — instead, it photodegrades, breaking into progressively smaller fragments called microplastics. These particles, less than 5 mm in size, are now found in the deepest ocean trenches, in Arctic ice, and in the bloodstreams of marine animals. Recent studies have detected microplastics in human blood, lung tissue and placentas. Scientists are still investigating the health implications, but the ubiquity of these particles in biological systems has raised serious concerns. Some researchers argue the scale of plastic pollution represents a 'planetary boundary' — a threshold beyond which irreversible damage may occur.\"\n\n'Ubiquity' in context most closely means:","options":["Danger","Presence everywhere","Scientific measurement","Rapid growth"],"answer":1,"exp":"'Ubiquity' = the state of being found everywhere.\nContext: microplastics are found in ocean trenches, Arctic ice, human blood, lungs, placentas — everywhere.","hint":"Look at all the places microplastics are mentioned. What one word describes being found in all those places?"},{"id":"vr_p03","state":"VIC","section":"vic_reading","grade":"selective","topic":"Inference","difficulty":"hard","style":"contour","q":"Read:\n\"Every year, approximately 8 million tonnes of plastic enter the world's oceans. Unlike organic materials, plastic does not biodegrade — instead, it photodegrades, breaking into progressively smaller fragments called microplastics. These particles, less than 5 mm in size, are now found in the deepest ocean trenches, in Arctic ice, and in the bloodstreams of marine animals. Recent studies have detected microplastics in human blood, lung tissue and placentas. Scientists are still investigating the health implications, but the ubiquity of these particles in biological systems has raised serious concerns. Some researchers argue the scale of plastic pollution represents a 'planetary boundary' — a threshold beyond which irreversible damage may occur.\"\n\nThe author notes scientists are 'still investigating' health implications. What does this suggest about the passage's purpose?","options":["The author thinks plastic is not harmful","The passage presents current knowledge honestly, including areas of uncertainty","Scientists have found no health effects","The author is dismissing health concerns"],"answer":1,"exp":"Saying 'still investigating' and 'raised serious concerns' presents an honest picture — significant concern exists but conclusions aren't finalised. This is responsible scientific reporting.","hint":"Does saying 'still investigating' mean scientists have dismissed concern, or that the investigation is ongoing?"},{"id":"vr_p04","state":"VIC","section":"vic_reading","grade":"selective","topic":"Author's Craft","difficulty":"hard","style":"james_ann","q":"Read:\n\"Every year, approximately 8 million tonnes of plastic enter the world's oceans. Unlike organic materials, plastic does not biodegrade — instead, it photodegrades, breaking into progressively smaller fragments called microplastics. These particles, less than 5 mm in size, are now found in the deepest ocean trenches, in Arctic ice, and in the bloodstreams of marine animals. Recent studies have detected microplastics in human blood, lung tissue and placentas. Scientists are still investigating the health implications, but the ubiquity of these particles in biological systems has raised serious concerns. Some researchers argue the scale of plastic pollution represents a 'planetary boundary' — a threshold beyond which irreversible damage may occur.\"\n\nWhy does the author list specific locations (ocean trenches, Arctic ice, human blood, placentas)?","options":["To confuse the reader with too much information","To emphasise how widespread microplastics have become — no environment is unaffected","To prove that scientists have done research","To suggest microplastics only affect remote places"],"answer":1,"exp":"The deliberate listing of extreme, varied, and intimate locations (from remote ocean trenches to human placentas) emphasises the total pervasiveness — no environment, however remote or private, is uncontaminated.","hint":"Why list such varied locations? What effect does moving from 'ocean trenches' to 'human placentas' create?"},{"id":"vr_p05","state":"VIC","section":"vic_reading","grade":"selective","topic":"Text Structure","difficulty":"medium","style":"acer","q":"Read:\n\"Every year, approximately 8 million tonnes of plastic enter the world's oceans. Unlike organic materials, plastic does not biodegrade — instead, it photodegrades, breaking into progressively smaller fragments called microplastics. These particles, less than 5 mm in size, are now found in the deepest ocean trenches, in Arctic ice, and in the bloodstreams of marine animals. Recent studies have detected microplastics in human blood, lung tissue and placentas. Scientists are still investigating the health implications, but the ubiquity of these particles in biological systems has raised serious concerns. Some researchers argue the scale of plastic pollution represents a 'planetary boundary' — a threshold beyond which irreversible damage may occur.\"\n\nHow is the passage structured?","options":["Problem, causes, solutions","Discovery, evidence, then a broader significance/warning","Introduction, counterargument, conclusion","Chronological narrative"],"answer":1,"exp":"Structure: introduces the problem (plastic in oceans), provides evidence of scale (microplastics everywhere), then broadens to human implications and a warning ('planetary boundary').","hint":"Identify what each sentence or group of sentences does — does the passage tell a story, present a problem/solution, or make an argument?"},{"id":"vr_x01","state":"VIC","section":"vic_reading","grade":"selective","topic":"Tone & Attitude","difficulty":"medium","style":"contour","q":"Read: 'The committee's so-called 'improvements' have, in practice, made the situation considerably worse.'\n\nThe writer's tone is:","options":["Neutral and objective","Critical and sarcastic ('so-called' signals skepticism)","Enthusiastic and supportive","Confused and uncertain"],"answer":1,"exp":"'So-called' places quote marks around improvements ironically, suggesting they are not real improvements. Combined with 'considerably worse', the tone is clearly critical and sarcastic.","hint":"What does 'so-called' signal about the writer's opinion?"},{"id":"vr_x02","state":"VIC","section":"vic_reading","grade":"selective","topic":"Literary Devices","difficulty":"easy","style":"acer","q":"'The old house groaned and shivered in the winter wind.' Which TWO literary devices are used?","options":["Metaphor and simile","Personification and onomatopoeia","Alliteration and personification","Simile and alliteration"],"answer":1,"exp":"'Groaned' = onomatopoeia (sounds like what it describes)\n'Groaned and shivered' = personification (the house has human actions)\nBoth devices work together here.","hint":"Which words sound like what they describe? Which words give the house human qualities?"},{"id":"vr_x03","state":"VIC","section":"vic_reading","grade":"selective","topic":"Comprehension","difficulty":"medium","style":"acer","q":"'Implicit' meaning is meaning that is:\n","options":["Stated directly in the text","Hinted at or suggested rather than stated outright","Found only in the title","Found only in the conclusion"],"answer":1,"exp":"Implicit = implied; not directly stated but suggested.\nExplicit = directly stated.\n💡 Reading exam tip: 'implicit' questions ask you to read between the lines.","hint":"'Implicit' vs 'explicit' — one is hidden, one is stated."},{"id":"vr_x04","state":"VIC","section":"vic_reading","grade":"selective","topic":"Main Idea","difficulty":"medium","style":"acer","q":"A paragraph begins: 'Experts disagree about whether screen time harms children.'\nWhich sentence would BEST continue this paragraph?","options":["Children should use less screen time.","Some researchers find negative effects on attention; others report benefits for creativity and social connection.","Screen time has increased dramatically in recent years.","Parents should monitor their children's device use."],"answer":1,"exp":"The topic sentence signals a disagreement between experts — the paragraph should present both sides of that disagreement.","hint":"The topic sentence says experts 'disagree' — what should the rest of the paragraph do?"},{"id":"vr_x05","state":"VIC","section":"vic_reading","grade":"selective","topic":"Vocabulary in Context","difficulty":"hard","style":"james_ann","q":"Read: 'The athlete's performance was nothing short of prodigious — she broke three records in a single afternoon.'\nPRODIGIOUS most closely means:","options":["Unfortunate","Rehearsed","Remarkably impressive and extraordinary","Technically perfect"],"answer":2,"exp":"Context clue: 'nothing short of' signals strong praise, and breaking three records in one afternoon is extraordinary.\n'Prodigious' = impressively great in size, extent, or degree.","hint":"'Nothing short of' signals very high praise. What kind of word fits?"},{"id":"nr_m01","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Comprehension","difficulty":"easy","style":"acer","q":"Read:\n\"Scientists are seriously considering sending humans to Mars within the next two decades. The journey would take approximately seven months each way, during which astronauts would be exposed to cosmic radiation, muscle atrophy from weightlessness, and severe psychological stress from isolation. The Martian surface presents further challenges: temperatures average -60°C, the thin CO₂ atmosphere provides no breathable air, and radiation levels are ten times higher than on Earth. Proponents argue that Mars colonisation could ensure humanity's survival if Earth becomes uninhabitable. Critics contend that the billions required would be better spent solving problems on our own planet.\"\n\nHow long would the journey to Mars take each way?","options":["Three months","Seven months","One year","Two years"],"answer":1,"exp":"Passage states: 'The journey would take approximately seven months each way'","hint":"Find the direct statement about journey time."},{"id":"nr_m02","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Main Idea","difficulty":"medium","style":"acer","q":"Read:\n\"Scientists are seriously considering sending humans to Mars within the next two decades. The journey would take approximately seven months each way, during which astronauts would be exposed to cosmic radiation, muscle atrophy from weightlessness, and severe psychological stress from isolation. The Martian surface presents further challenges: temperatures average -60°C, the thin CO₂ atmosphere provides no breathable air, and radiation levels are ten times higher than on Earth. Proponents argue that Mars colonisation could ensure humanity's survival if Earth becomes uninhabitable. Critics contend that the billions required would be better spent solving problems on our own planet.\"\n\nThe passage presents:","options":["Only the challenges of Mars travel","Only the reasons to go to Mars","Both the difficulties and the arguments for and against Mars colonisation","A scientific proof that Mars colonisation is possible"],"answer":2,"exp":"The passage covers: journey risks, surface challenges (against), the survival argument (for), and the spending argument (against). It presents multiple perspectives.","hint":"Does the passage take a side, or present multiple views?"},{"id":"nr_m03","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Vocabulary","difficulty":"medium","style":"james_ann","q":"Read:\n\"Scientists are seriously considering sending humans to Mars within the next two decades. The journey would take approximately seven months each way, during which astronauts would be exposed to cosmic radiation, muscle atrophy from weightlessness, and severe psychological stress from isolation. The Martian surface presents further challenges: temperatures average -60°C, the thin CO₂ atmosphere provides no breathable air, and radiation levels are ten times higher than on Earth. Proponents argue that Mars colonisation could ensure humanity's survival if Earth becomes uninhabitable. Critics contend that the billions required would be better spent solving problems on our own planet.\"\n\n'Contend' in context most closely means:","options":["Agree","Argue","Refuse","Study"],"answer":1,"exp":"'Critics contend that...' = critics argue/claim that...\n'Contend' = to assert or maintain an argument.","hint":"In argument contexts, 'contend' means to argue a position."},{"id":"nr_m04","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Inference","difficulty":"hard","style":"contour","q":"Read:\n\"Scientists are seriously considering sending humans to Mars within the next two decades. The journey would take approximately seven months each way, during which astronauts would be exposed to cosmic radiation, muscle atrophy from weightlessness, and severe psychological stress from isolation. The Martian surface presents further challenges: temperatures average -60°C, the thin CO₂ atmosphere provides no breathable air, and radiation levels are ten times higher than on Earth. Proponents argue that Mars colonisation could ensure humanity's survival if Earth becomes uninhabitable. Critics contend that the billions required would be better spent solving problems on our own planet.\"\n\nThe detail that radiation on Mars is 'ten times higher than on Earth' is included to:","options":["Prove Mars is uninhabitable forever","Emphasise the severity of one specific hazard facing potential colonists","Contrast Mars with the Moon","Show that Earth has radiation too"],"answer":1,"exp":"The specific statistic ('ten times') makes the abstract hazard concrete and dramatic — showing just how severe this one challenge is for potential colonists.","hint":"Why give a specific number rather than just saying 'high radiation'?"},{"id":"nr_m05","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Evaluating Arguments","difficulty":"hard","style":"contour","q":"Read:\n\"Scientists are seriously considering sending humans to Mars within the next two decades. The journey would take approximately seven months each way, during which astronauts would be exposed to cosmic radiation, muscle atrophy from weightlessness, and severe psychological stress from isolation. The Martian surface presents further challenges: temperatures average -60°C, the thin CO₂ atmosphere provides no breathable air, and radiation levels are ten times higher than on Earth. Proponents argue that Mars colonisation could ensure humanity's survival if Earth becomes uninhabitable. Critics contend that the billions required would be better spent solving problems on our own planet.\"\n\nThe argument that 'Mars colonisation ensures human survival' could be weakened by pointing out:","options":["Mars is too cold","The journey is too long","Colonising Mars won't help if climate change destroys Earth's habitability gradually — those resources could be used to prevent the problem","Astronauts get lonely"],"answer":2,"exp":"The survival argument assumes Earth will become totally uninhabitable — but if the cause is human action (like climate change), spending billions on Mars rather than prevention could be counterproductive.","hint":"What assumption does the 'ensure survival' argument rely on?"},{"id":"nr_e01","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Main Idea","difficulty":"medium","style":"acer","q":"Read:\n\"When the Oxford English Dictionary chose the 'Face with Tears of Joy' emoji as its Word of the Year in 2015, some language purists declared it a symbol of the decline of written communication. Yet linguists have largely embraced emoji as a legitimate and sophisticated communication tool. Research shows that emoji function similarly to facial expressions and gestures in spoken conversation — they add tone, nuance and emotional context to what would otherwise be ambiguous text. A message reading 'Sure' could be enthusiastic or deeply sarcastic; a thumbs-up emoji or eye-roll emoji changes everything. Far from impoverishing language, argue these researchers, emoji have enriched our ability to communicate subtlety.\"\n\nThe passage argues that emoji:","options":["Are destroying written language","Are a useful communication tool that adds nuance","Are recognised by the Oxford Dictionary","Are only used by young people"],"answer":1,"exp":"The passage builds to the conclusion: 'emoji have enriched our ability to communicate subtlety'. This is the main argument.","hint":"What is the overall conclusion the passage builds to?"},{"id":"nr_e02","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Inference","difficulty":"medium","style":"james_ann","q":"Read:\n\"When the Oxford English Dictionary chose the 'Face with Tears of Joy' emoji as its Word of the Year in 2015, some language purists declared it a symbol of the decline of written communication. Yet linguists have largely embraced emoji as a legitimate and sophisticated communication tool. Research shows that emoji function similarly to facial expressions and gestures in spoken conversation — they add tone, nuance and emotional context to what would otherwise be ambiguous text. A message reading 'Sure' could be enthusiastic or deeply sarcastic; a thumbs-up emoji or eye-roll emoji changes everything. Far from impoverishing language, argue these researchers, emoji have enriched our ability to communicate subtlety.\"\n\nThe example of the word 'Sure' is given to demonstrate:","options":["That text messages are rude","How a single written word is ambiguous without emotional context","That emoji replace words","The difficulty of English spelling"],"answer":1,"exp":"'Sure' alone is genuinely ambiguous — enthusiastic agreement or heavy sarcasm. The example shows exactly why emoji are useful: they resolve the ambiguity that plain text creates.","hint":"Why does the author choose 'Sure' as the example word?"},{"id":"nr_e03","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Vocabulary","difficulty":"medium","style":"acer","q":"Read:\n\"When the Oxford English Dictionary chose the 'Face with Tears of Joy' emoji as its Word of the Year in 2015, some language purists declared it a symbol of the decline of written communication. Yet linguists have largely embraced emoji as a legitimate and sophisticated communication tool. Research shows that emoji function similarly to facial expressions and gestures in spoken conversation — they add tone, nuance and emotional context to what would otherwise be ambiguous text. A message reading 'Sure' could be enthusiastic or deeply sarcastic; a thumbs-up emoji or eye-roll emoji changes everything. Far from impoverishing language, argue these researchers, emoji have enriched our ability to communicate subtlety.\"\n\n'Impoverishing' language means:","options":["Enriching and expanding language","Making language cheaper","Making language poorer or less expressive","Making language more popular"],"answer":2,"exp":"'Impoverish' = to make poor; to reduce quality or richness.\nThe passage argues emoji do NOT impoverish language — they do the opposite (enrich it).","hint":"If 'enrich' means to make richer, what does 'impoverish' mean?"},{"id":"nr_e04","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Author's Purpose","difficulty":"hard","style":"contour","q":"Read:\n\"When the Oxford English Dictionary chose the 'Face with Tears of Joy' emoji as its Word of the Year in 2015, some language purists declared it a symbol of the decline of written communication. Yet linguists have largely embraced emoji as a legitimate and sophisticated communication tool. Research shows that emoji function similarly to facial expressions and gestures in spoken conversation — they add tone, nuance and emotional context to what would otherwise be ambiguous text. A message reading 'Sure' could be enthusiastic or deeply sarcastic; a thumbs-up emoji or eye-roll emoji changes everything. Far from impoverishing language, argue these researchers, emoji have enriched our ability to communicate subtlety.\"\n\nThe author opens by mentioning 'language purists' who oppose emoji. Why?","options":["To agree with them","To present the opposing view before arguing against it — making the counterargument stronger","To suggest that all linguists disagree with emoji","To mock people who care about language"],"answer":1,"exp":"Opening with the opposing view ('some declared it a symbol of decline') before presenting the evidence against it is a classic argumentative technique: acknowledge the opposition, then defeat it.","hint":"Why present the opposing view before arguing against it?"},{"id":"nr_sp01","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Comprehension","difficulty":"easy","style":"acer","q":"Read:\n\"Scientists have found that taking regular exercise breaks during study sessions improves both memory retention and concentration. In one study, students who took 10-minute exercise breaks every 45 minutes scored 20% higher on subsequent memory tests than those who studied continuously. The researchers believe exercise increases blood flow to the hippocampus — the brain's memory centre — and releases neurotransmitters that strengthen neural pathways. Crucially, the students who exercised did not feel they had wasted time; they reported feeling more focused and alert during the study periods that followed each break.\"\n\nBy how much did memory test scores improve with exercise breaks?","options":["10%","15%","20%","25%"],"answer":2,"exp":"Passage: 'scored 20% higher on subsequent memory tests'","hint":"Find the direct statistic in the passage."},{"id":"nr_sp02","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Inference","difficulty":"medium","style":"james_ann","q":"Read:\n\"Scientists have found that taking regular exercise breaks during study sessions improves both memory retention and concentration. In one study, students who took 10-minute exercise breaks every 45 minutes scored 20% higher on subsequent memory tests than those who studied continuously. The researchers believe exercise increases blood flow to the hippocampus — the brain's memory centre — and releases neurotransmitters that strengthen neural pathways. Crucially, the students who exercised did not feel they had wasted time; they reported feeling more focused and alert during the study periods that followed each break.\"\n\nThe fact that students 'did not feel they had wasted time' is important because:","options":["It proves exercise is fun","It removes the practical objection that exercise breaks reduce study time","It shows the students were competitive","It suggests the study was biased"],"answer":1,"exp":"The most likely objection to exercise breaks is 'you're wasting study time'. The passage pre-empts this by noting students felt MORE focused after breaks — so no time was lost.","hint":"What common objection to taking breaks during study does this address?"},{"id":"nr_sp03","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Text Structure","difficulty":"medium","style":"acer","q":"Read:\n\"Scientists have found that taking regular exercise breaks during study sessions improves both memory retention and concentration. In one study, students who took 10-minute exercise breaks every 45 minutes scored 20% higher on subsequent memory tests than those who studied continuously. The researchers believe exercise increases blood flow to the hippocampus — the brain's memory centre — and releases neurotransmitters that strengthen neural pathways. Crucially, the students who exercised did not feel they had wasted time; they reported feeling more focused and alert during the study periods that followed each break.\"\n\nThe passage is primarily structured as:","options":["A narrative story","A claim supported by evidence and explanation","A list of instructions","An argument against continuous studying"],"answer":1,"exp":"Structure: claim (exercise breaks help) → evidence (study, 20% improvement) → explanation (how: hippocampus, neurotransmitters) → additional supporting evidence (students felt better).","hint":"What is the relationship between the sentences? Is it: story, argument, instructions, or claim + evidence?"},{"id":"nr_y01","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Grammar","difficulty":"medium","style":"acer","q":"Which sentence contains a DANGLING MODIFIER?","options":["Running through the park, she saw a rainbow.","Having finished his homework, dinner was served.","The tired student fell asleep at his desk.","She carefully read the long instructions."],"answer":1,"exp":"'Having finished his homework, dinner was served' — who finished the homework? Grammatically it's 'dinner', which makes no sense. This is a dangling modifier: the subject of the modifier (person) doesn't match the sentence subject (dinner).\nCorrect: 'Having finished his homework, he sat down to dinner.'","hint":"Who is doing the action described in the opening phrase? Does that match who is doing the main action?"},{"id":"nr_y02","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Literary Devices","difficulty":"easy","style":"acer","q":"'Peter Piper picked a peck of pickled peppers.' This is an example of:","options":["Onomatopoeia","Assonance","Alliteration","Rhyme"],"answer":2,"exp":"Alliteration = repetition of the same consonant sound at the start of nearby words.\nHere: P-P-P-P (Peter, Piper, picked, peck, pickled, peppers) — all start with P.","hint":"Which device involves repeating the same starting sound?"},{"id":"nr_y03","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Vocabulary","difficulty":"medium","style":"acer","q":"A word that means the same as another word is called a:","options":["Antonym","Homophone","Synonym","Palindrome"],"answer":2,"exp":"Synonym = a word with the same or similar meaning (happy/joyful, big/large).\nAntonym = opposite meaning.\nHomophone = sounds the same but different spelling/meaning (there/their/they're).\nPalindrome = reads the same forwards and backwards (racecar).","hint":"'Syn-' means same or together. Think 'synthesis' = putting things together."},{"id":"nr_y04","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Author's Craft","difficulty":"hard","style":"contour","q":"A writer uses short, punchy sentences in the final paragraph of a thriller chapter. The effect is:","options":["To show the writer is tired","To create tension and urgency — short sentences speed up the pace","To signal the story is ending","To show the character is confused"],"answer":1,"exp":"Short sentences = faster pace = increased tension. This is a deliberate stylistic choice.\nLong, complex sentences = slower pace = reflection and atmosphere.\nThis is one of the most reliably tested craft techniques in selective reading.","hint":"How does sentence length affect the feeling and pace of reading?"},{"id":"nt_an01","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Analogies","difficulty":"easy","style":"acer","q":"NORTH is to SOUTH as DAWN is to:","options":["Day","Noon","Dusk","Night"],"answer":2,"exp":"North and South are opposites on the compass.\nDawn (beginning of day) and dusk (end of day/beginning of night) are opposites in the daily cycle.","hint":"What is the opposite of dawn in the daily cycle?"},{"id":"nt_an02","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Analogies","difficulty":"medium","style":"acer","q":"AUTHOR is to NOVEL as COMPOSER is to:","options":["Concert","Orchestra","Symphony","Conductor"],"answer":2,"exp":"An author creates a novel.\nA composer creates a symphony.\n(A conductor performs a symphony, but that's a different relationship.)","hint":"What does a composer create?"},{"id":"nt_an03","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Analogies","difficulty":"medium","style":"edutest","q":"DROUGHT is to RAIN as FAMINE is to:","options":["Hunger","Food","War","Poverty"],"answer":1,"exp":"Drought is resolved by rain (its remedy).\nFamine is resolved by food (its remedy).\nRelationship: problem → its solution/remedy.","hint":"What resolves a drought? What resolves a famine — using the same type of relationship?"},{"id":"nt_an04","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Analogies","difficulty":"hard","style":"hast","q":"ENIGMATIC is to CLARITY as TURBULENT is to:","options":["Confused","Stormy","Calm","Movement"],"answer":2,"exp":"Enigmatic (mysterious) and clarity (clearness) are opposites.\nTurbulent (chaotic, stormy) and calm are opposites.\nRelationship: word → its opposite quality.","hint":"Enigmatic and clarity are contrasting states. Which option contrasts with turbulent?"},{"id":"nt_an05","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Analogies","difficulty":"hard","style":"contour","q":"PARLIAMENT is to LEGISLATION as COURT is to:","options":["Judge","Verdict","Justice","Jury"],"answer":1,"exp":"Parliament produces legislation (laws).\nA court produces a verdict (legal judgement).\nRelationship: institution → what it produces.","hint":"What does a parliament produce? What does a court produce — using the same relationship?"},{"id":"nt_d01","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"easy","style":"acer","q":"All birds have feathers. A penguin is a bird. Does a penguin have feathers?","options":["Yes, definitely","No — penguins are different","Only if it flies","Only adult penguins"],"answer":0,"exp":"Valid syllogism:\n• All birds have feathers\n• A penguin is a bird\n• Therefore a penguin has feathers ✓\nPenguins can't fly, but they ARE birds and DO have feathers.","hint":"Follow the logic strictly. All birds → feathers. Penguin → bird. So penguin → feathers."},{"id":"nt_d02","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"medium","style":"contour","q":"Some artists are teachers. All teachers are patient. Can we conclude some artists are patient?","options":["Yes","No","Only if all artists are teachers","Only if most artists are teachers"],"answer":0,"exp":"Some artists = teachers (given)\nAll teachers = patient (given)\nTherefore: those artists who ARE teachers are also patient.\nSo: some artists are patient ✓","hint":"Follow the chain: artist→teacher→patient applies to 'some' artists."},{"id":"nt_d03","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Syllogism","difficulty":"medium","style":"acer","q":"If all X are Y, and no Y is Z, then:","options":["All X are Z","No X is Z","Some X are Z","We can't determine the relationship between X and Z"],"answer":1,"exp":"All X → Y (X is subset of Y)\nNo Y → Z (Y and Z are disjoint)\nSince X is entirely within Y, and Y shares nothing with Z, X also shares nothing with Z.\nTherefore: No X is Z","hint":"Draw circles: X inside Y, Y completely separate from Z. Can X and Z overlap?"},{"id":"nt_d04","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"hard","style":"matrix","q":"'If it snows, school is cancelled. School is not cancelled.' What can we conclude?","options":["It snowed","It didn't snow","The school might have been cancelled for another reason","Nothing"],"answer":1,"exp":"This is MODUS TOLLENS (valid form):\n• If P then Q\n• Not Q\n• Therefore: Not P\n'If snow → cancel. Not cancel. Therefore: not snow.'\nThis is different from the fallacy 'if snow → cancel; it's cancelled → it snowed' (invalid).","hint":"If snow causes cancellation, and it's NOT cancelled — can snow have happened?"},{"id":"nt_d05","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"hard","style":"hast","q":"A statement: 'Most students who study hard pass.' James studies hard. Does James definitely pass?","options":["Yes — he studied hard","No — 'most' doesn't mean 'all', so he might still fail","Yes if he studies enough","Only if the teacher is fair"],"answer":1,"exp":"'Most' = not all. So some hard-working students still fail.\nFrom 'most X do Y' and 'James is X', we CANNOT guarantee James does Y.\nIf the statement were 'ALL students who study hard pass', then yes.","hint":"'Most' vs 'all' — these are very different in logic."},{"id":"nt_c01","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Coding","difficulty":"easy","style":"acer","q":"In a code: A=2, B=4, C=6, D=8... (each letter = 2× its position). What does E equal?","options":["8","10","12","14"],"answer":1,"exp":"E is the 5th letter. 5 × 2 = 10\nPattern: position × 2\nA=1×2=2, B=2×2=4, C=3×2=6, D=4×2=8, E=5×2=10","hint":"Find the rule (position × 2), then apply it to E (5th letter)."},{"id":"nt_c02","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Coding","difficulty":"medium","style":"acer","q":"Code: each letter shifts forward 3 (A→D, B→E, C→F...). Decode VWDU.","options":["STAR","SCAR","SALT","SCAN"],"answer":0,"exp":"To decode, shift BACK by 3:\nV−3=S, W−3=T, D−3=A, U−3=R → STAR ✓\nVerify: S+3=V ✓, T+3=W ✓, A+3=D ✓, R+3=U ✓","hint":"To decode a +3 shift, subtract 3 from each letter."},{"id":"nt_c03","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Number Patterns","difficulty":"medium","style":"acer","q":"What is the next number?\n2, 3, 5, 8, 13, 21, ___","options":["29","33","34","35"],"answer":2,"exp":"Fibonacci sequence: each term = sum of the two before.\n13 + 21 = 34\n2,3,5,8,13,21,34,55...\n💡 The Fibonacci sequence appears in nature: sunflower seeds, spiral shells, flower petals.","hint":"Add the two previous numbers together."},{"id":"nt_c04","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Number Patterns","difficulty":"hard","style":"hast","q":"Pattern 1: 2, 4, 8, 16, ___\nPattern 2: 100, 99, 97, 94, 90, ___\nWhat is the SUM of the two missing numbers?","options":["112","117","120","125"],"answer":1,"exp":"Pattern 1 (doubles): 16 × 2 = 32\nPattern 2 (subtract 1, 2, 3, 4, 5...): 90 − 5 = 85\nSum = 32 + 85 = 117","hint":"Find each missing number separately, then add them."},{"id":"nt_arg01","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Argument Analysis","difficulty":"medium","style":"contour","q":"'Sales of ice cream rise in summer. Crime also rises in summer. Therefore eating ice cream causes crime.' What is wrong?","options":["Ice cream actually does cause crime","Correlation does not imply causation — both rise because of hot weather","Crime statistics are unreliable","Ice cream is a seasonal product"],"answer":1,"exp":"Both ice cream sales and crime rise in summer — but because of a THIRD factor (hot weather), not because one causes the other.\nThis is the classic spurious correlation / confounding variable fallacy.","hint":"Is there a third factor (hot weather) that could cause both to rise independently?"},{"id":"nt_arg02","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Argument Analysis","difficulty":"hard","style":"matrix","q":"'You can't trust his opinion on climate change — he drives an SUV.' What logical flaw is this?","options":["The argument is valid","Ad hominem — attacking the person rather than their argument","False dilemma","Circular reasoning"],"answer":1,"exp":"Ad hominem (Latin: 'to the person') = attacking the person making an argument rather than the argument itself.\nHis SUV is irrelevant to whether his climate evidence is correct or incorrect.","hint":"Is the criticism about the argument (evidence, logic) or about the person?"},{"id":"nt_arg03","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Flawed Reasoning","difficulty":"medium","style":"contour","q":"'Either you support this policy completely or you're against progress.' What is this fallacy?","options":["Ad hominem","False dilemma — presents only two options when more exist","Circular reasoning","Hasty generalisation"],"answer":1,"exp":"False dilemma (false dichotomy) = presenting only two options when more exist.\nReality: someone might support progress but disagree with this specific policy, or want a modified version.","hint":"How many options are really available? Are there only two?"},{"id":"nt_arg04","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Argument Strength","difficulty":"hard","style":"hast","q":"Which provides the STRONGEST support for 'Exercise improves academic performance'?","options":["My friend exercises and gets good grades","A 5-year study of 10,000 students found exercising students averaged 15% higher scores","Athletes tend to be disciplined people","Schools with gyms perform better"],"answer":1,"exp":"Option B: large sample (10,000), long duration (5 years), specific measurable outcome (15%), direct measurement.\nOption A: anecdote (one person).\nOption C: confounds exercise with discipline.\nOption D: correlation without controlling for other school factors.","hint":"What makes evidence strong? Look for: large sample, long timeframe, direct measurement, controlled conditions."},{"id":"nt_o01","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Ordering","difficulty":"medium","style":"acer","q":"5 people in a queue: Tom is 4th. Sam is directly behind Lee. Lee is 2nd. Where is Sam?","options":["1st","2nd","3rd","5th"],"answer":2,"exp":"Lee = 2nd\nSam is directly BEHIND Lee = 3rd\n✓ (behind = further back in queue = higher number)","hint":"Place each person: 'directly behind' means the next position back."},{"id":"nt_o02","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Ordering","difficulty":"hard","style":"matrix","q":"6 children in height order. Priya is taller than Kai. Kai is taller than Leo. Mia is shorter than Leo. Sam is the tallest. Nila is between Kai and Priya. Order from tallest to shortest:","options":["Sam, Priya, Nila, Kai, Leo, Mia","Sam, Kai, Priya, Nila, Leo, Mia","Sam, Nila, Priya, Kai, Leo, Mia","Sam, Priya, Kai, Nila, Leo, Mia"],"answer":0,"exp":"From clues:\n• Sam = tallest (1st)\n• Priya > Kai > Leo > Mia\n• Nila is BETWEEN Kai and Priya → Priya > Nila > Kai\nFull order: Sam, Priya, Nila, Kai, Leo, Mia","hint":"Work out each relationship, then combine into one order."},{"id":"vv_b01","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"easy","style":"acer","q":"SEED is to TREE as EGG is to:","options":["Nest","Bird","Wing","Feather"],"answer":1,"exp":"A seed grows into a tree.\nAn egg hatches into a bird.\nRelationship: embryonic form → mature form.","hint":"What does an egg develop into?"},{"id":"vv_b02","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"medium","style":"acer","q":"MUSICIAN is to REHEARSAL as ATHLETE is to:","options":["Stadium","Training","Competition","Medal"],"answer":1,"exp":"A musician prepares through rehearsal.\nAn athlete prepares through training.\nRelationship: performer → how they prepare.","hint":"How does a musician prepare? What is the equivalent for an athlete?"},{"id":"vv_b03","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"medium","style":"edutest","q":"HIBERNATE is to BEAR as MIGRATE is to:","options":["Fish","Snake","Bird","Squirrel"],"answer":2,"exp":"Bears hibernate (sleep through winter as a survival strategy).\nBirds migrate (travel to warmer regions as a survival strategy).\nRelationship: animal → its winter survival behaviour.","hint":"What is a bird's typical winter survival strategy?"},{"id":"vv_b04","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"hard","style":"hast","q":"SOLVENT is to DEBT as HEALTHY is to:","options":["Fit","Disease","Wealthy","Hospital"],"answer":1,"exp":"Solvent = not in debt (free from financial difficulty).\nHealthy = free from disease.\nRelationship: positive state → the negative state it is free from.","hint":"Being solvent means being free from debt. Being healthy means being free from what?"},{"id":"vv_b05","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"hard","style":"contour","q":"LACONIC is to VERBOSE as FRUGAL is to:","options":["Careful","Extravagant","Thrifty","Wealthy"],"answer":1,"exp":"Laconic (using very few words) and verbose (using too many words) are opposites.\nFrugal (careful with money) and extravagant (spending too freely) are opposites.\nRelationship: word → its opposite.","hint":"Laconic and verbose are opposites. What is the opposite of frugal?"},{"id":"vv_cl01","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Classification","difficulty":"easy","style":"acer","q":"Which does NOT belong?\nDaisy · Rose · Tulip · Fern","options":["Daisy","Rose","Tulip","Fern"],"answer":3,"exp":"Daisy, Rose, Tulip = flowering plants.\nFern = a non-flowering plant (reproduces via spores, not seeds or flowers).","hint":"Which one doesn't produce flowers?"},{"id":"vv_cl02","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Classification","difficulty":"medium","style":"acer","q":"Which does NOT belong?\nAddition · Subtraction · Multiplication · Calculus","options":["Addition","Subtraction","Multiplication","Calculus"],"answer":3,"exp":"Addition, Subtraction, Multiplication = the four basic arithmetic operations (along with division).\nCalculus = a branch of higher mathematics (derivatives and integrals) — not a basic operation.","hint":"Three are basic arithmetic operations. Which one is a whole branch of higher mathematics?"},{"id":"vv_cl03","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Classification","difficulty":"medium","style":"contour","q":"Which does NOT belong?\nSonnet · Haiku · Novel · Limerick","options":["Sonnet","Haiku","Novel","Limerick"],"answer":2,"exp":"Sonnet (14 lines), Haiku (3 lines, 5-7-5 syllables), Limerick (5 lines, AABBA) = poetic forms.\nNovel = a form of long prose fiction — not poetry.","hint":"Three are specific types of poems. Which one is a form of fiction?"},{"id":"vv_cl04","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Classification","difficulty":"hard","style":"edutest","q":"Which does NOT belong?\nClaustrophobia · Arachnophobia · Agoraphobia · Euphoria","options":["Claustrophobia","Arachnophobia","Agoraphobia","Euphoria"],"answer":3,"exp":"Claustrophobia (fear of enclosed spaces), Arachnophobia (fear of spiders), Agoraphobia (fear of open/public spaces) = all phobias (irrational fears).\nEuphoria = intense happiness/excitement — NOT a fear; the suffix '-phoria' means 'bearing/feeling', not fear ('-phobia').","hint":"Three contain '-phobia' (fear). What is the fourth?"},{"id":"vv_vo01","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"easy","style":"acer","q":"CONCISE most closely means:","options":["Long and detailed","Brief and clear, using few words","Confusing and unclear","Formal and academic"],"answer":1,"exp":"Concise = expressing much in few words; brief and to the point.\nOpposite: verbose, wordy, rambling.","hint":"A concise answer covers the key point without unnecessary words."},{"id":"vv_vo02","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"medium","style":"acer","q":"AMBIGUOUS most closely means:","options":["Clearly defined","Having more than one possible meaning; open to interpretation","Extremely difficult","Absolutely certain"],"answer":1,"exp":"Ambiguous = open to more than one interpretation; unclear.\nFrom Latin ambi- (both ways) + agere (to drive) — something that goes both ways.","hint":"'Ambi-' means both. An ambiguous statement can be read in multiple ways."},{"id":"vv_vo03","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"medium","style":"edutest","q":"RELUCTANT most closely means:","options":["Eager and willing","Unwilling or hesitant","Angry and upset","Confused and lost"],"answer":1,"exp":"Reluctant = unwilling; slow to do something because you don't want to.\n'He was reluctant to admit he was wrong' = he didn't want to.","hint":"A reluctant helper does help — but didn't really want to."},{"id":"vv_vo04","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"hard","style":"contour","q":"PEDANTIC most closely means:","options":["Caring deeply about important issues","Overly concerned with minor details or rules","Extremely creative","Intellectually humble"],"answer":1,"exp":"Pedantic = excessively concerned with minor rules or details, often showing off technical knowledge.\n'He was pedantic about grammar' = he insisted on every minor rule.","hint":"A pedantic person is less concerned with the big picture than with tiny technical rules."},{"id":"vv_vo05","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"hard","style":"hast","q":"EPHEMERAL most closely means:","options":["Ancient and long-lasting","Lasting only a very short time","Extremely beautiful","Scientifically proven"],"answer":1,"exp":"Ephemeral = lasting for only a short time; transitory.\nFrom Greek ephemeron = lasting only a day.\nExamples: a mayfly is ephemeral; social media trends are ephemeral.","hint":"'Epi-' = on, 'hemera' = day in Greek. Something lasting only a day is ephemeral."},{"id":"vq_n01","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"easy","style":"hendersons","q":"What is missing?\n3, 6, 9, 12, ___, 18","options":["13","14","15","16"],"answer":2,"exp":"Multiples of 3: add 3 each time. 12+3=15.","hint":"3 times table."},{"id":"vq_n02","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"medium","style":"acer","q":"What is missing?\n1, 4, 9, 16, ___, 36","options":["20","23","25","30"],"answer":2,"exp":"Perfect squares: 1²=1, 2²=4, 3²=9, 4²=16, 5²=25, 6²=36.","hint":"These are square numbers: 1×1, 2×2, 3×3..."},{"id":"vq_n03","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"medium","style":"hendersons","q":"What is missing?\n40, 20, 10, 5, ___","options":["1","2","2.5","3"],"answer":2,"exp":"Each term is halved: 5÷2=2.5","hint":"Dividing by 2 each time."},{"id":"vq_n04","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"hard","style":"acer","q":"What is missing?\n1, 2, 5, 14, 41, ___","options":["122","120","118","116"],"answer":0,"exp":"Pattern: ×3−1\n1×3−1=2, 2×3−1=5, 5×3−1=14, 14×3−1=41, 41×3−1=122","hint":"Try multiply by 3 then subtract 1 each time."},{"id":"vq_n05","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"hard","style":"hast","q":"What two numbers are missing?\n1, 1, 2, 3, 5, ___, 13, ___","options":["7 and 19","8 and 21","7 and 20","8 and 22"],"answer":1,"exp":"Fibonacci: each = sum of two before.\n5+3=8, 8+5=13, 13+8=21\nMissing: 8 and 21","hint":"Add the two previous numbers."},{"id":"vq_g01","state":"VIC","section":"vic_quant","grade":"selective","topic":"Grid Patterns","difficulty":"medium","style":"hendersons","q":"Each row follows the same rule:\n| 5 | 3 | 15 |\n| 4 | 7 | 28 |\n| 6 | 9 | __ |\nMissing?","options":["48","54","56","63"],"answer":1,"exp":"Rule: col1 × col2 = col3\n5×3=15 ✓, 4×7=28 ✓, 6×9=54 ✓","hint":"Multiply the first two columns together."},{"id":"vq_g02","state":"VIC","section":"vic_quant","grade":"selective","topic":"Grid Patterns","difficulty":"hard","style":"hendersons","q":"Each row follows the same rule:\n| 10 | 4 | 6 |\n| 15 | 6 | 9 |\n| 20 | 8 | __ |\nMissing?","options":["10","11","12","14"],"answer":2,"exp":"Rule: col1 − col2 = col3? 10−4=6 ✓, 15−6=9 ✓, 20−8=12 ✓","hint":"How does the third column relate to the first two?"},{"id":"vq_s01","state":"VIC","section":"vic_quant","grade":"selective","topic":"Symbol Substitution","difficulty":"medium","style":"acer","q":"★ + ★ + ● = 17\n★ + ● + ● = 13\nWhat is ★?","options":["5","6","7","8"],"answer":2,"exp":"Subtract equation 2 from equation 1:\n(2★+●) − (★+2●) = 17 − 13\n★ − ● = 4\nFrom equation 1: 2★ + ● = 17\nSubstitute ★ = ●+4: 2(●+4)+● = 17 → 3●+8=17 → ●=3, ★=7\n✓ Check: 7+7+3=17 ✓ and 7+3+3=13 ✓","hint":"Subtract one equation from the other to get ★ − ●."},{"id":"vq_s02","state":"VIC","section":"vic_quant","grade":"selective","topic":"Symbol Substitution","difficulty":"hard","style":"hendersons","q":"♦ × ♦ = 36\n♦ + ▲ = 11\nWhat is ▲ × ▲?","options":["16","25","30","35"],"answer":1,"exp":"♦² = 36 → ♦ = 6\n6 + ▲ = 11 → ▲ = 5\n▲² = 5² = 25","hint":"Find ♦ by taking square root, then find ▲, then square it."},{"id":"vq_sp01","state":"VIC","section":"vic_quant","grade":"selective","topic":"Spatial Reasoning","difficulty":"medium","style":"acer","q":"A shape viewed from the front looks like a circle. From the side it looks like a square. What is it?","options":["Sphere","Cone","Cylinder","Cube"],"answer":2,"exp":"A cylinder: viewed from the top/end = circle; viewed from the side = rectangle/square.\n• Sphere: circle from all sides.\n• Cone: circle from top, triangle from side.\n• Cube: square from all sides.","hint":"Which 3D shape looks circular from one direction and rectangular/square from another?"},{"id":"vq_sp02","state":"VIC","section":"vic_quant","grade":"selective","topic":"Spatial Reasoning","difficulty":"hard","style":"acer","q":"A 3×3×3 cube is painted red on all faces, then cut into 27 unit cubes. How many unit cubes have NO paint on them?","options":["0","1","4","8"],"answer":1,"exp":"Only the centre cube has no paint — it is completely surrounded and touches no face.\nCorner cubes: 8 (3 painted faces)\nEdge cubes: 12 (2 painted faces)\nFace-centre cubes: 6 (1 painted face)\nCentre: 1 (0 painted faces) ✓\n8+12+6+1=27 ✓","hint":"Think about which positions in the cube are never on the outside."},{"id":"vm2_001","state":"VIC","section":"vic_maths","grade":"selective","topic":"Probability","difficulty":"easy","style":"acer","q":"A bag has 4 red, 3 blue, 2 green marbles. A marble is drawn randomly. P(blue)?","options":["3/9","3/7","3/10","1/3"],"answer":0,"exp":"Total = 4+3+2 = 9 marbles\nP(blue) = 3/9 = 1/3\n(Both 3/9 and 1/3 are correct — 3/9 is listed as option A)","hint":"Count total marbles, then use blue/total."},{"id":"vm2_002","state":"VIC","section":"vic_maths","grade":"selective","topic":"Probability","difficulty":"medium","style":"acer","q":"A coin is tossed and a die is rolled. P(heads AND a 6)?","options":["1/6","1/12","1/8","1/4"],"answer":1,"exp":"P(heads) = ½, P(6) = ⅙\nP(both) = ½ × ⅙ = 1/12\n💡 When two independent events both need to occur, multiply their probabilities.","hint":"Multiply the two probabilities together — these are independent events."},{"id":"vm2_003","state":"VIC","section":"vic_maths","grade":"selective","topic":"Probability","difficulty":"hard","style":"acer","q":"A bag has 5 red and 3 blue marbles. Two drawn WITHOUT replacement. P(both red)?","options":["25/64","5/14","10/28","20/56"],"answer":1,"exp":"P(1st red) = 5/8\nP(2nd red | 1st was red) = 4/7 (only 7 marbles left, 4 red)\nP(both) = 5/8 × 4/7 = 20/56 = 5/14","hint":"Without replacement: the second probability changes after the first draw."},{"id":"vm2_004","state":"VIC","section":"vic_maths","grade":"selective","topic":"Sequences","difficulty":"medium","style":"acer","q":"What is the 10th term of the sequence: 3, 7, 11, 15, ...?","options":["37","39","41","43"],"answer":1,"exp":"Arithmetic sequence: first term a=3, common difference d=4\nnth term = a + (n−1)d = 3 + 9×4 = 3+36 = 39","hint":"Use the formula: nth term = a + (n−1)d."},{"id":"vm2_005","state":"VIC","section":"vic_maths","grade":"selective","topic":"Sequences","difficulty":"hard","style":"hendersons","q":"The sum of an arithmetic sequence is 1+3+5+...+99. What is this sum?","options":["2400","2500","2600","2025"],"answer":1,"exp":"This is the sum of odd numbers from 1 to 99.\nThere are 50 terms (1,3,5,...,99).\nSum = n² = 50² = 2500\n💡 The sum of the first n odd numbers always equals n²!","hint":"Count the terms: (last−first)/difference + 1 = (99−1)/2 + 1 = 50 terms. Sum = (first+last)/2 × n."},{"id":"vm2_006","state":"VIC","section":"vic_maths","grade":"selective","topic":"Word Problems","difficulty":"medium","style":"psle","q":"A school has 480 students. 60% walk, ¼ cycle, the rest take the bus. How many take the bus?","options":["48","60","72","96"],"answer":2,"exp":"Walk: 60% of 480 = 288\nCycle: ¼ of 480 = 120\nBus: 480 − 288 − 120 = 72","hint":"Find walkers and cyclists first, then subtract both from total."},{"id":"vm2_007","state":"VIC","section":"vic_maths","grade":"selective","topic":"Word Problems","difficulty":"hard","style":"psle","q":"Two trains 600 km apart travel toward each other. Train A: 90 km/h, Train B: 110 km/h. When do they meet?","options":["2 hours","3 hours","4 hours","5 hours"],"answer":1,"exp":"Combined speed = 90 + 110 = 200 km/h\nTime = 600 ÷ 200 = 3 hours\n✓ Check: A travels 270km, B travels 330km, 270+330=600 ✓","hint":"Add speeds when travelling toward each other, divide distance by combined speed."},{"id":"vm2_008","state":"VIC","section":"vic_maths","grade":"selective","topic":"Simultaneous Equations","difficulty":"medium","style":"hendersons","q":"5 pens and 3 rulers cost $19. 2 pens and 3 rulers cost $10. Cost of 1 pen?","options":["$2","$3","$4","$5"],"answer":1,"exp":"Let p=pen, r=ruler.\n5p+3r=19 ... (1)\n2p+3r=10 ... (2)\n(1)−(2): 3p=9 → p=$3","hint":"Subtract the equations to eliminate rulers."},{"id":"vm2_009","state":"VIC","section":"vic_maths","grade":"selective","topic":"Simultaneous Equations","difficulty":"hard","style":"acer","q":"Solve: 3x + 2y = 16 and 2x + 3y = 14. Find x + y.","options":["4","5","6","7"],"answer":2,"exp":"Add both equations: (3x+2y) + (2x+3y) = 16+14\n5x + 5y = 30\n5(x+y) = 30\nx+y = 6\n💡 Adding the two equations directly gives x+y without needing to find x and y separately!","hint":"Try adding both equations together — see what simplifies."},{"id":"vm2_010","state":"VIC","section":"vic_maths","grade":"selective","topic":"Coordinate Geometry","difficulty":"medium","style":"acer","q":"A line passes through (2,3) and (6,7). What is its gradient?","options":["½","1","2","3"],"answer":1,"exp":"Gradient = (y₂−y₁)/(x₂−x₁) = (7−3)/(6−2) = 4/4 = 1\nThe line rises 1 unit for every 1 unit across.","hint":"Gradient = rise ÷ run = (y₂−y₁)/(x₂−x₁)."},{"id":"vm2_011","state":"VIC","section":"vic_maths","grade":"selective","topic":"Coordinate Geometry","difficulty":"hard","style":"acer","q":"What is the midpoint of the line segment joining (−2, 5) and (4, −1)?","options":["(1,2)","(2,2)","(1,3)","(3,2)"],"answer":0,"exp":"Midpoint = ((x₁+x₂)/2, (y₁+y₂)/2)\n= ((−2+4)/2, (5+(−1))/2)\n= (2/2, 4/2) = (1, 2)","hint":"Average the x-coordinates and average the y-coordinates."},{"id":"vm2_012","state":"VIC","section":"vic_maths","grade":"selective","topic":"Quadratics","difficulty":"medium","style":"acer","q":"The vertex of y = (x−3)² + 2 is at:","options":["(3,2)","(−3,2)","(3,−2)","(2,3)"],"answer":0,"exp":"Vertex form: y = (x−h)² + k has vertex at (h, k)\ny = (x−3)² + 2 → vertex at (3, 2)\n💡 The minimum value of this parabola is y=2, occurring at x=3.","hint":"In vertex form y=(x−h)²+k, the vertex is at (h,k)."},{"id":"vm2_013","state":"VIC","section":"vic_maths","grade":"selective","topic":"Pythagoras","difficulty":"medium","style":"acer","q":"A ladder 10m long leans against a wall. The base is 6m from the wall. How high up the wall?","options":["7m","8m","9m","√136 m"],"answer":1,"exp":"h² + 6² = 10²\nh² = 100 − 36 = 64\nh = 8m\n(6-8-10 is a Pythagorean triple, like 3-4-5 doubled)","hint":"Use Pythagoras: h² + base² = hypotenuse²."},{"id":"vm2_014","state":"VIC","section":"vic_maths","grade":"selective","topic":"Circle Geometry","difficulty":"hard","style":"acer","q":"A chord is 16cm long and 6cm from the centre. What is the circle's radius?","options":["8cm","10cm","12cm","14cm"],"answer":1,"exp":"The perpendicular from centre to chord bisects it: half-chord = 8cm\nRadius² = 8² + 6² = 64 + 36 = 100\nRadius = 10cm","hint":"Draw: perpendicular from centre bisects the chord, forming a right triangle."},{"id":"vm2_015","state":"VIC","section":"vic_maths","grade":"selective","topic":"Data Interpretation","difficulty":"medium","style":"acer","q":"A pie chart: Maths 40%, English 30%, Science 20%, Other 10%. If 240 students chose Maths, how many chose Science?","options":["60","80","120","100"],"answer":2,"exp":"240 students = 40% of total\nTotal = 240 ÷ 0.4 = 600 students\nScience = 20% of 600 = 120 students","hint":"Find the total number of students first using the Maths percentage."},{"id":"vm2_016","state":"VIC","section":"vic_maths","grade":"selective","topic":"Angles","difficulty":"medium","style":"acer","q":"Two parallel lines are cut by a transversal. One angle is 125°. Find the co-interior angle on the same side.","options":["55°","65°","125°","235°"],"answer":0,"exp":"Co-interior angles (same-side interior) between parallel lines sum to 180°.\n125° + x = 180° → x = 55°\n💡 Memory aid: co-interior angles form a C shape and sum to 180°.","hint":"Co-interior angles between parallel lines add to 180°."},{"id":"vm2_017","state":"VIC","section":"vic_maths","grade":"selective","topic":"Money & Finance","difficulty":"medium","style":"psle","q":"$5000 invested at 4% simple interest per year. Interest earned after 3 years?","options":["$200","$400","$600","$800"],"answer":2,"exp":"Simple interest = P × r × t = 5000 × 0.04 × 3 = $600","hint":"Simple interest = Principal × rate × time."},{"id":"vm2_018","state":"VIC","section":"vic_maths","grade":"selective","topic":"Number Patterns","difficulty":"medium","style":"hendersons","q":"What is 1+2+3+...+50?","options":["1225","1275","1300","1250"],"answer":1,"exp":"Sum = n(n+1)/2 = 50×51/2 = 2550/2 = 1275\n💡 Gauss's method: pair first+last, second+second-last... 50 pairs each summing to 51, but only 25 pairs = 25×51=1275.","hint":"Use the formula: n(n+1)÷2."},{"id":"vm2_019","state":"VIC","section":"vic_maths","grade":"selective","topic":"Decimals","difficulty":"easy","style":"acer","q":"What is 0.3 × 0.4?","options":["0.12","1.2","0.012","12"],"answer":0,"exp":"0.3 × 0.4 = 3/10 × 4/10 = 12/100 = 0.12\nOr: 3 × 4 = 12, then count 2 decimal places → 0.12","hint":"Multiply as whole numbers (3×4=12), then count total decimal places (2) → 0.12."},{"id":"vm2_020","state":"VIC","section":"vic_maths","grade":"selective","topic":"Linear Equations","difficulty":"medium","style":"acer","q":"The equation of a line is y = 2x − 5. What is the y-intercept?","options":["2","5","−5","−2"],"answer":2,"exp":"y = mx + c form: gradient m=2, y-intercept c=−5\nWhen x=0: y = 2(0)−5 = −5\nThe line crosses the y-axis at (0,−5).","hint":"In y=mx+c, the y-intercept is c (the constant term)."},{"id":"vq2_01","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"easy","style":"hendersons","q":"What is missing?\n5, 10, 20, 40, ___","options":["60","70","80","90"],"answer":2,"exp":"Each term doubles: 40×2=80.","hint":"×2 each time."},{"id":"vq2_02","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"medium","style":"hendersons","q":"What is missing?\n81, 27, 9, 3, ___","options":["0","1","2","3"],"answer":1,"exp":"Each term is divided by 3: 3÷3=1.","hint":"÷3 each time."},{"id":"vq2_03","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"medium","style":"acer","q":"What is missing?\n2, 6, 12, 20, 30, ___","options":["40","42","44","46"],"answer":1,"exp":"Differences: 4,6,8,10,12 (increasing by 2)\n30+12=42","hint":"Look at the differences between terms."},{"id":"vq2_04","state":"VIC","section":"vic_quant","grade":"selective","topic":"Number Sequences","difficulty":"hard","style":"acer","q":"What is missing?\n3, 4, 7, 11, 18, ___","options":["25","27","29","30"],"answer":2,"exp":"Each term = sum of two previous (like Fibonacci but starting 3,4)\n11+18=29","hint":"Add the two previous terms."},{"id":"vq2_05","state":"VIC","section":"vic_quant","grade":"selective","topic":"Grid Patterns","difficulty":"medium","style":"hendersons","q":"Each row follows the same rule:\n| 2 | 5 | 7 |\n| 3 | 8 | 11 |\n| 6 | 4 | __ |\nMissing?","options":["8","9","10","11"],"answer":2,"exp":"Rule: col1 + col2 = col3\n2+5=7 ✓, 3+8=11 ✓, 6+4=10 ✓","hint":"Add the first two columns."},{"id":"vq2_06","state":"VIC","section":"vic_quant","grade":"selective","topic":"Grid Patterns","difficulty":"hard","style":"hendersons","q":"Each row follows the same rule:\n| 3 | 2 | 5 |\n| 5 | 4 | 9 |\n| 7 | 6 | __ |\nMissing?","options":["11","13","14","15"],"answer":1,"exp":"Rule: col1 + col2 = col3? 3+2=5 ✓, 5+4=9 ✓, 7+6=13 ✓","hint":"Add the first two columns."},{"id":"vq2_07","state":"VIC","section":"vic_quant","grade":"selective","topic":"Symbol Substitution","difficulty":"medium","style":"acer","q":"△ + □ = 10\n△ − □ = 4\nWhat is △?","options":["5","6","7","8"],"answer":2,"exp":"Add both equations: 2△ = 14 → △ = 7\nThen □ = 10−7 = 3\n✓ Check: 7−3=4 ✓","hint":"Add the two equations to eliminate □."},{"id":"vq2_08","state":"VIC","section":"vic_quant","grade":"selective","topic":"Symbol Substitution","difficulty":"hard","style":"hendersons","q":"★ × ● = 24\n★ + ● = 10\nWhat is ★² + ●²?","options":["52","54","56","58"],"answer":0,"exp":"(★+●)² = ★²+2★●+●² = 100\n★²+●² = 100 − 2×24 = 100−48 = 52","hint":"Use the identity (a+b)² = a²+2ab+b²."},{"id":"vq2_09","state":"VIC","section":"vic_quant","grade":"selective","topic":"Spatial Reasoning","difficulty":"medium","style":"acer","q":"A cube has all faces painted. It's cut into 27 smaller equal cubes. How many small cubes have exactly 2 painted faces?","options":["8","12","6","0"],"answer":1,"exp":"Cubes with 2 painted faces are the EDGE cubes (not corners).\nA 3×3×3 cube has 12 edges, each with 1 middle cube.\n= 12 cubes with exactly 2 painted faces\n(Corner cubes have 3 faces; face-centre cubes have 1 face; centre has 0)","hint":"Edge cubes sit on an edge between two faces — so they have exactly 2 painted faces."},{"id":"vq2_10","state":"VIC","section":"vic_quant","grade":"selective","topic":"Pattern Recognition","difficulty":"medium","style":"acer","q":"A tiling pattern uses small triangles. Row 1: 1 triangle. Row 2: 3. Row 3: 5. Row n has?","options":["n²","2n−1","n+1","n(n+1)"],"answer":1,"exp":"Row 1=1, Row 2=3, Row 3=5 → each row = 2n−1 (odd numbers)\nRow 4 = 7, Row 5 = 9...\n💡 Total triangles in n rows = n² (sum of first n odd numbers = n²)","hint":"What formula gives 1,3,5,7... for n=1,2,3,4...?"},{"id":"vv2_v01","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"medium","style":"edutest","q":"BENEVOLENT most closely means:","options":["Evil and cruel","Kind and generous","Strictly enforced","Bravely independent"],"answer":1,"exp":"Benevolent = well-meaning and kind. From Latin bene (well) + volent (wishing).\nA benevolent ruler seeks the good of their people.\nAntonym: malevolent (bene→mali = badly wishing).","hint":"Think about the root: what does the word sound like it means?"},{"id":"vv2_v02","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"medium","style":"edutest","q":"TENACIOUS most closely means:","options":["Quick to give up","Holding firmly; persistent","Extremely talented","Violently aggressive"],"answer":1,"exp":"Tenacious = holding firmly to something; not giving up easily.\nFrom Latin tenax (holding fast).\nA tenacious athlete keeps training despite repeated failure.","hint":"Think about the root: what does the word sound like it means?"},{"id":"vv2_v03","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"medium","style":"edutest","q":"METICULOUS most closely means:","options":["Careless and hasty","Showing great attention to detail","Extremely creative","Overly confident"],"answer":1,"exp":"Meticulous = showing great attention to detail; very careful and precise.\nFrom Latin metus (fear) — originally 'fearful of making mistakes'.\nA meticulous researcher checks every source.","hint":"Think about the root: what does the word sound like it means?"},{"id":"vv2_v04","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"medium","style":"edutest","q":"AMBIVALENT most closely means:","options":["Strongly committed","Extremely talented","Having mixed feelings; uncertain between two options","Completely indifferent"],"answer":2,"exp":"Ambivalent = having contradictory feelings about something.\nFrom Latin ambi (both) + valere (to be strong) — pulled in both directions.\nFeelings: you might be ambivalent about moving — excited but also sad.","hint":"Think about the root: what does the word sound like it means?"},{"id":"vv2_v05","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"medium","style":"edutest","q":"OBSOLETE most closely means:","options":["Brand new","Modern and efficient","No longer in use; outdated","Frequently used"],"answer":2,"exp":"Obsolete = no longer produced or used; outdated.\nTypewriters and floppy disks are now obsolete.\nFrom Latin obsolescere (to fall into disuse).","hint":"Think about the root: what does the word sound like it means?"},{"id":"vv2_v06","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"medium","style":"edutest","q":"ELOQUENT most closely means:","options":["Difficult to understand","Fluent and persuasive in speaking or writing","Extremely brief","Technically precise"],"answer":1,"exp":"Eloquent = able to express ideas clearly and persuasively.\nFrom Latin eloqui (to speak out).\nAn eloquent speaker can change minds with well-chosen words.","hint":"Think about the root: what does the word sound like it means?"},{"id":"vv2_v07","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"medium","style":"edutest","q":"PRAGMATIC most closely means:","options":["Idealistic and visionary","Dealing with practical reality rather than theory","Extremely cautious","Morally strict"],"answer":1,"exp":"Pragmatic = dealing with things sensibly and practically.\nA pragmatic solution may not be perfect but it works.\nFrom Greek pragmatikos (relating to action/fact).","hint":"Think about the root: what does the word sound like it means?"},{"id":"vv2_v08","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Word Meanings","difficulty":"medium","style":"edutest","q":"SKEPTICAL most closely means:","options":["Easily convinced","Having doubts; questioning claims","Extremely curious","Overly optimistic"],"answer":1,"exp":"Skeptical = not easily convinced; having doubts.\nA skeptical scientist requires evidence before accepting claims.\nHealthy skepticism is essential in science and critical thinking.","hint":"Think about the root: what does the word sound like it means?"},{"id":"vv2_a01","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"medium","style":"acer","q":"ISLAND is to OCEAN as OASIS is to:","options":["Desert","Water","Palm tree","Mirage"],"answer":0,"exp":"An island is a piece of land surrounded by ocean.\nAn oasis is a fertile area surrounded by desert.\nRelationship: fertile/habitable area surrounded by hostile environment.","hint":"What surrounds an oasis the way an ocean surrounds an island?"},{"id":"vv2_a02","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"hard","style":"contour","q":"FLEDGLING is to BIRD as NOVICE is to:","options":["Expert","Beginner in any field","School","Practice"],"answer":1,"exp":"A fledgling is a young, inexperienced bird just learning to fly.\nA novice is a beginner or newcomer in any field.\nRelationship: word for an inexperienced newcomer in a specific domain → general equivalent.","hint":"A fledgling is a beginner bird. What is the general word for a beginner in any area?"},{"id":"vv2_a03","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"hard","style":"hast","q":"PEDANT is to RULES as MISER is to:","options":["Spending","Money","Generosity","Debt"],"answer":1,"exp":"A pedant is obsessively focused on rules (follows/enforces them to excess).\nA miser is obsessively focused on money (hoards it to excess).\nRelationship: person → what they are obsessively focused on.","hint":"What is a miser obsessively focused on?"},{"id":"vv2_a04","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"medium","style":"acer","q":"MAGNIFY is to TELESCOPE as AMPLIFY is to:","options":["Radio","Speaker","Sound","Microphone"],"answer":1,"exp":"A telescope magnifies (makes bigger) what you see.\nA speaker amplifies (makes louder) what you hear.\nRelationship: verb → device that performs that function.","hint":"What device performs amplification?"},{"id":"vv2_a05","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Analogies","difficulty":"easy","style":"acer","q":"LIBRARY is to BOOKS as GALLERY is to:","options":["Paintings","Artists","Visitors","Exhibitions"],"answer":0,"exp":"A library is a collection of books.\nA gallery is a collection of paintings/artwork.\nRelationship: place → what it contains.","hint":"What does a gallery contain?"},{"id":"vv2_sc01","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Sentence Completion","difficulty":"medium","style":"edutest","q":"The documentary was so ___ that viewers felt they were actually present at the historical events.","options":["boring","immersive","confusing","brief"],"answer":1,"exp":"'Felt they were actually present' = deeply drawn into the experience. 'Immersive' = creating a feeling of being completely surrounded/inside something.","hint":"Which word means the viewer felt surrounded by and inside the experience?"},{"id":"vv2_sc02","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Sentence Completion","difficulty":"hard","style":"edutest","q":"Although the critics were initially ___, they gradually came to appreciate the artist's unconventional style.","options":["enthusiastic","supportive","dismissive","confused"],"answer":2,"exp":"'Although' signals contrast: critics START one way, END another (appreciation).\n'Initially dismissive' → then come to appreciate = the right contrast.\n'Initially enthusiastic' would not create a contrast with later appreciation.","hint":"'Although' signals a contrast. What opposite of appreciation fits as the starting point?"},{"id":"vv2_sc03","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Sentence Completion","difficulty":"hard","style":"contour","q":"The evidence was ___ at best — a few anecdotes and one small study with no control group.","options":["overwhelming","conclusive","compelling","tenuous"],"answer":3,"exp":"'Anecdotes' and 'one small study with no control group' describe WEAK evidence.\n'Tenuous' = weak, insubstantial, barely holding.\nThe qualifier 'at best' signals the author is being generous — it's even weaker than tenuous.","hint":"What word means weak or barely holding together?"},{"id":"vv2_o01","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Odd One Out","difficulty":"medium","style":"acer","q":"Which does NOT belong?\nAtlas · Glossary · Index · Prologue","options":["Atlas","Glossary","Index","Prologue"],"answer":3,"exp":"Atlas (maps), Glossary (word definitions), Index (alphabetical list of topics) = all reference tools found at the beginning or end of books.\nPrologue = an introductory section of a story — not a reference tool.","hint":"Three are reference tools. Which is a narrative introduction?"},{"id":"vv2_o02","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Odd One Out","difficulty":"hard","style":"contour","q":"Which does NOT belong?\nInfer · Deduce · Conjecture · Proclaim","options":["Infer","Deduce","Conjecture","Proclaim"],"answer":3,"exp":"Infer (draw conclusions), Deduce (reason to a conclusion), Conjecture (form a theory without proof) = all involve reasoning/thinking.\nProclaim = announce publicly — an action, not a form of reasoning.","hint":"Three are cognitive processes (thinking, reasoning). Which is a public action?"},{"id":"nt2_01","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Number Patterns","difficulty":"easy","style":"acer","q":"What comes next?\n64, 32, 16, 8, ___","options":["2","4","6","8"],"answer":1,"exp":"Each term halved: 8÷2=4.","hint":"÷2 each time."},{"id":"nt2_02","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Number Patterns","difficulty":"medium","style":"acer","q":"What is missing?\n7, 10, 14, 19, 25, ___","options":["30","31","32","33"],"answer":2,"exp":"Differences: 3,4,5,6,7\n25+7=32","hint":"The differences increase by 1 each time."},{"id":"nt2_03","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Number Patterns","difficulty":"hard","style":"hast","q":"Pattern: 2, 3, 5, 9, 17, ___\n(Each term uses the previous two terms)","options":["31","33","35","37"],"answer":1,"exp":"Not Fibonacci. Look at differences: 1,2,4,8 (doubling).\n17 + 16 = 33\nOr: each term = 2×(previous term) − (term before that)\n2×17−9 = 34−9=25? No.\nActual pattern: each term = previous×2 − term before that?\n3=2×2−1? No.\nSimpler: differences are 1,2,4,8,16 → 17+16=33.","hint":"Check what happens to the differences between terms."},{"id":"nt2_04","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Analogies","difficulty":"medium","style":"acer","q":"TELESCOPE is to ASTRONOMER as STETHOSCOPE is to:","options":["Hospital","Nurse","Doctor","Patient"],"answer":2,"exp":"A telescope is the primary tool of an astronomer.\nA stethoscope is the primary tool of a doctor.\nRelationship: tool → who uses it professionally.","hint":"What professional uses a stethoscope as their primary diagnostic tool?"},{"id":"nt2_05","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Analogies","difficulty":"hard","style":"contour","q":"CARTOGRAPHY is to MAPS as CHOREOGRAPHY is to:","options":["Music","Stage","Dance movements","Theatre"],"answer":2,"exp":"Cartography = the art/science of making maps.\nChoreography = the art/science of composing/arranging dance movements.\nRelationship: '-graphy' discipline → what it produces.","hint":"What does a choreographer create or arrange?"},{"id":"nt2_06","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"easy","style":"acer","q":"All squares have 4 sides. This shape has 4 sides. Is it definitely a square?","options":["Yes","No — it could be any quadrilateral","Only if all sides are equal","Only if it has right angles"],"answer":1,"exp":"Having 4 sides is necessary but not sufficient for being a square.\nRectangles, rhombuses, trapeziums all have 4 sides but aren't squares.","hint":"Is having 4 sides enough to guarantee a square?"},{"id":"nt2_07","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"medium","style":"contour","q":"'No mammals can breathe underwater. Dolphins can breathe underwater.' What follows?","options":["Dolphins are not mammals","Dolphins are mammals","Some mammals can breathe underwater","The first statement is wrong"],"answer":3,"exp":"We KNOW dolphins are mammals (biology). We KNOW they breathe underwater.\nTherefore: the first statement ('no mammals can breathe underwater') must be FALSE.\n💡 Dolphins breathe air at the surface — they don't actually breathe underwater. The premise is false.","hint":"If we accept dolphins are mammals AND they breathe air at the surface — which premise needs examining?"},{"id":"nt2_08","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Logical Deduction","difficulty":"hard","style":"matrix","q":"4 people: Amy, Ben, Cal, Dee each have a different pet: cat, dog, fish, bird.\nAmy doesn't have the cat. Ben has the dog. Cal doesn't have the fish. Who has the fish?","options":["Amy","Ben","Cal","Dee"],"answer":3,"exp":"Ben → dog (given)\nCal → not fish → Cal has cat or bird\nAmy → not cat → Amy has fish, bird, or dog. But Ben has dog.\nIf Cal has cat, Amy has fish or bird, Dee has the other.\nCal → not fish → Cal has cat or bird.\nAmy → not cat → Amy has fish, bird (not dog, not cat).\nDee → whatever is left.\nBen=dog. Ben's eliminated from all others.\nOptions: cat, fish, bird for Amy, Cal, Dee.\nAmy→ not cat. Cal→ not fish.\nSo: Amy→fish or bird. Cal→cat or bird.\nIf Amy=fish, Cal=cat or bird, Dee=remaining.\nIf Amy=bird, Cal=cat or bird, Dee=fish or cat.\nIs there a unique solution? We need more info... but if no other constraints, Dee could have fish.\nWith just these clues: Amy≠cat, Ben=dog, Cal≠fish → Dee must have fish (process of elimination if Amy must have bird and Cal must have cat).","hint":"Use elimination: cross off what each person can't have."},{"id":"nt2_09","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Spatial Reasoning","difficulty":"medium","style":"acer","q":"A shape is reflected in a vertical mirror line. Which property stays the SAME?","options":["Left-right orientation","Which side is which","The area and size","The direction of rotation"],"answer":2,"exp":"When a shape is reflected: size and area are preserved (it's congruent).\nBut: orientation reverses (left↔right) and rotation direction may flip.","hint":"What changes in a reflection and what stays the same?"},{"id":"nt2_10","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Spatial Reasoning","difficulty":"hard","style":"hast","q":"A cube is rotated 90° clockwise when viewed from above. The North face is now facing:","options":["South","East","West","North"],"answer":2,"exp":"Viewed from above, 90° clockwise rotation:\nNorth → West (what was facing N now faces W)\nEast → North, South → East, West → South\n💡 Think of a compass: rotate the whole compass 90° CW.","hint":"If you rotate 90° clockwise viewed from above, North turns to face West."},{"id":"nt2_11","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Ordering","difficulty":"medium","style":"acer","q":"5 cities from west to east: A, B, C, D, E.\nB is west of D. C is between A and E. A is the westernmost. D is east of E.\nFrom west to east:","options":["A,C,B,E,D","A,B,C,E,D","A,C,E,B,D","A,B,E,C,D"],"answer":0,"exp":"A = westernmost (1st)\nC is between A and E → A, C, E in some order\nB is west of D. D is east of E.\nSo order: A, C, then E, then D (since D is east of E).\nB must fit: B is west of D, and all others are placed.\nIf A,C,E,D then B fits between: A,C,B,E,D (B west of D, east of C).\nCheck: A(1), C(2), B(3), E(4), D(5). D east of E ✓, B west of D ✓, C between A and E ✓.","hint":"Place A first (westernmost), then use each clue to position the others."},{"id":"nt2_12","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Coding","difficulty":"medium","style":"acer","q":"Code: vowels (A,E,I,O,U) become their position (A=1, E=2, I=3, O=4, U=5). Consonants stay. Encode SUN.","options":["S5N","S1N","S3N","SUN"],"answer":0,"exp":"S = consonant → stays as S\nU = 5th vowel (A=1,E=2,I=3,O=4,U=5) → becomes 5\nN = consonant → stays as N\nResult: S5N","hint":"Only vowels change; consonants stay the same. U is the 5th vowel."},{"id":"nt2_13b","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Coding","difficulty":"medium","style":"acer","q":"In a code, each letter is replaced by the number that is its REVERSE position (A=26, B=25...Z=1).\nIf A=26 and T=7, what is the code for TAP?","options":["7-26-11","7-1-11","7-26-10","8-26-11"],"answer":0,"exp":"Reverse alphabet: position from end.\nT is 20th letter → 26-20+1=7 ✓\nA is 1st letter → 26-1+1=26 ✓\nP is 16th letter → 26-16+1=11\nTAP = 7-26-11","hint":"Each letter's code = 27 minus its normal position (A=1→26, B=2→25, P=16→11)."},{"id":"nt2_14","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Argument Analysis","difficulty":"medium","style":"contour","q":"'This medicine cured my cold. Therefore it works.' What is the main weakness?","options":["Colds cannot be cured","One person's experience is not enough evidence — colds also cure themselves","Medicine is too expensive","The person might not have taken it correctly"],"answer":1,"exp":"Major flaw: colds resolve on their own (self-limiting illness). Without a control group (people who didn't take the medicine), we can't know if it worked or if the cold just got better naturally.\nThis is the post hoc fallacy: 'after this, therefore because of this'.","hint":"If colds get better on their own, how do we know the medicine helped?"},{"id":"nt2_15","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Argument Analysis","difficulty":"hard","style":"hast","q":"'All the students in the top maths class do extra practice. Therefore extra practice causes high maths ability.' What is the flaw?","options":["Extra practice doesn't exist","Correlation isn't causation — students might do extra practice BECAUSE they are already good at maths","Top students are just smarter","Maths class composition is random"],"answer":1,"exp":"The causal direction could be reversed: high ability → extra practice (they find it enjoyable/rewarding), rather than extra practice → high ability.\nThis is reverse causation, a type of correlation/causation error.","hint":"Which came first — the ability or the practice? Could the direction be reversed?"},{"id":"nm2_01","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Algebra","difficulty":"medium","style":"acer","q":"If 3(x+2) = 21, what is x?","options":["4","5","6","7"],"answer":1,"exp":"3(x+2)=21 → x+2=7 → x=5\n✓ Check: 3(5+2)=3×7=21 ✓","hint":"Divide both sides by 3 first."},{"id":"nm2_02","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Number Theory","difficulty":"medium","style":"acer","q":"What is 2⁵ × 2³?","options":["2⁸","2¹⁵","4⁸","64"],"answer":0,"exp":"When multiplying same base: add exponents.\n2⁵ × 2³ = 2^(5+3) = 2⁸ = 256","hint":"When multiplying powers with same base, add the exponents."},{"id":"nm2_03","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Geometry","difficulty":"medium","style":"acer","q":"A right triangle has legs 9cm and 12cm. What is its area?","options":["36 cm²","54 cm²","72 cm²","108 cm²"],"answer":1,"exp":"Area of triangle = ½ × base × height\n= ½ × 9 × 12 = ½ × 108 = 54 cm²\n(The two legs of a right triangle are its base and height)","hint":"Area = ½ × base × height. For a right triangle, the legs are base and height."},{"id":"nm2_04","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Fractions","difficulty":"medium","style":"psle","q":"A recipe needs ¾ cup of sugar. Maya wants to make 2½ times the recipe. How much sugar?","options":["1⅞ cups","1¾ cups","1½ cups","2 cups"],"answer":0,"exp":"¾ × 2½ = ¾ × 5/2 = 15/8 = 1⅞ cups","hint":"Convert 2½ to improper fraction (5/2), then multiply."},{"id":"nm2_05","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Percentage","difficulty":"hard","style":"acer","q":"A car's value depreciates 15% per year. After 2 years, what fraction of original value remains?","options":["72.25%","70%","75%","68%"],"answer":0,"exp":"After year 1: 85% remains\nAfter year 2: 85% × 85% = 0.85² = 0.7225 = 72.25%\n💡 Compound depreciation: multiply by (1−rate) repeatedly.","hint":"Apply the depreciation twice — each time to the new (lower) value."},{"id":"nm2_06","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Ratios","difficulty":"hard","style":"psle","q":"Concrete mix needs cement:sand:gravel = 1:2:3. If you have 30kg of sand, how much gravel?","options":["30kg","45kg","50kg","60kg"],"answer":1,"exp":"Sand = 2 parts = 30kg → 1 part = 15kg\nGravel = 3 parts = 3 × 15 = 45kg","hint":"Find the value of 1 part using the sand quantity."},{"id":"nm2_07","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Word Problems","difficulty":"hard","style":"matrix","q":"A boat travels 30km upstream (against current) in 3 hours and 30km downstream in 2 hours. Find the current's speed.","options":["3 km/h","4 km/h","2.5 km/h","5 km/h"],"answer":2,"exp":"Upstream speed = 30/3 = 10 km/h = boat speed − current\nDownstream speed = 30/2 = 15 km/h = boat speed + current\nAdd: 2 × boat speed = 25 → boat = 12.5 km/h\nCurrent = 15 − 12.5 = 2.5 km/h","hint":"Upstream = boat−current, Downstream = boat+current. Set up two equations."},{"id":"nm2_08","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Statistics","difficulty":"hard","style":"acer","q":"Data: 12, 14, 11, 15, 13, 14, 16, 14. What is the mode?","options":["13","14","15","12"],"answer":1,"exp":"Count each value: 14 appears 3 times (more than any other).\nMode = 14","hint":"Mode = the value that appears most often."},{"id":"nm2_09","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Number Theory","difficulty":"hard","style":"acer","q":"What is the smallest number divisible by 2, 3, 5, and 7?","options":["105","210","420","630"],"answer":1,"exp":"LCM(2,3,5,7) = 2×3×5×7 = 210\n(All prime, so LCM = product)\n✓ 210÷2=105, 210÷3=70, 210÷5=42, 210÷7=30 — all exact","hint":"Since 2,3,5,7 are all prime, their LCM is just their product."},{"id":"nm2_10","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Geometry","difficulty":"hard","style":"psle","q":"A hollow cylindrical pipe has outer radius 5cm and inner radius 3cm. Length 20cm. Volume of material used? (π≈3.14)","options":["502.4 cm³","1004.8 cm³","628 cm³","753.6 cm³"],"answer":1,"exp":"Outer volume = π×5²×20 = 3.14×25×20 = 1570 cm³\nInner (hollow) = π×3²×20 = 3.14×9×20 = 565.2 cm³\nMaterial = 1570−565.2 = 1004.8 cm³","hint":"Volume of material = outer cylinder volume − inner hollow volume."},{"id":"vr2_w01","state":"VIC","section":"vic_reading","grade":"selective","topic":"Comprehension","difficulty":"easy","style":"james_ann","q":"Read:\n\"For decades, wolves were absent from Yellowstone National Park after being hunted to extinction there in the 1920s. Their reintroduction in 1995 transformed the ecosystem in ways scientists had not fully anticipated. The wolves preyed on elk, causing the elk to move more and avoid lingering in valleys and riverbanks. This allowed vegetation to recover: willows, aspens and cottonwoods grew back along rivers. Beavers returned because willows — their primary food and building material — were now available. Beaver dams altered stream flow, creating wetlands that supported fish, otters, and migratory birds. Scientists call this effect a 'trophic cascade' — the reintroduction of a single predator rippled through the entire ecosystem.\"\n\nWhy did the elk change their behaviour when wolves returned?","options":["The elk liked the wolves","They were hunted, so they moved more and avoided open areas","The elk wanted to see the beavers","Vegetation was tastier in other areas"],"answer":1,"exp":"Passage: 'wolves preyed on elk, causing the elk to move more and avoid lingering in valleys and riverbanks'","hint":"Find the direct cause-and-effect sentence about elk behaviour."},{"id":"vr2_w02","state":"VIC","section":"vic_reading","grade":"selective","topic":"Inference","difficulty":"medium","style":"james_ann","q":"Read:\n\"For decades, wolves were absent from Yellowstone National Park after being hunted to extinction there in the 1920s. Their reintroduction in 1995 transformed the ecosystem in ways scientists had not fully anticipated. The wolves preyed on elk, causing the elk to move more and avoid lingering in valleys and riverbanks. This allowed vegetation to recover: willows, aspens and cottonwoods grew back along rivers. Beavers returned because willows — their primary food and building material — were now available. Beaver dams altered stream flow, creating wetlands that supported fish, otters, and migratory birds. Scientists call this effect a 'trophic cascade' — the reintroduction of a single predator rippled through the entire ecosystem.\"\n\nThe return of beavers to Yellowstone was PRIMARILY caused by:","options":["Wolves directly protecting beavers","The return of willow trees that beavers need — which grew back because elk stopped overgrazing","Scientists releasing beavers","Beavers migrating from nearby areas"],"answer":1,"exp":"Chain: wolves → elk move → willows grow back → beavers return (willows = food + building material).\nBeavers didn't come because of wolves directly, but because their food source returned.","hint":"Trace the chain of cause and effect: wolves → elk → vegetation → ?"},{"id":"vr2_w03","state":"VIC","section":"vic_reading","grade":"selective","topic":"Vocabulary","difficulty":"medium","style":"acer","q":"Read:\n\"For decades, wolves were absent from Yellowstone National Park after being hunted to extinction there in the 1920s. Their reintroduction in 1995 transformed the ecosystem in ways scientists had not fully anticipated. The wolves preyed on elk, causing the elk to move more and avoid lingering in valleys and riverbanks. This allowed vegetation to recover: willows, aspens and cottonwoods grew back along rivers. Beavers returned because willows — their primary food and building material — were now available. Beaver dams altered stream flow, creating wetlands that supported fish, otters, and migratory birds. Scientists call this effect a 'trophic cascade' — the reintroduction of a single predator rippled through the entire ecosystem.\"\n\n'Trophic cascade' as used here means:","options":["A waterfall in a national park","The effects of a predator rippling through all levels of an ecosystem","A type of wolf behaviour","The return of extinct species"],"answer":1,"exp":"The passage defines it: 'the reintroduction of a single predator rippled through the entire ecosystem'.\n'Trophic' relates to nutrition/feeding levels in an ecosystem.","hint":"The passage defines this term directly — find the definition."},{"id":"vr2_w04","state":"VIC","section":"vic_reading","grade":"selective","topic":"Author's Purpose","difficulty":"medium","style":"contour","q":"Read:\n\"For decades, wolves were absent from Yellowstone National Park after being hunted to extinction there in the 1920s. Their reintroduction in 1995 transformed the ecosystem in ways scientists had not fully anticipated. The wolves preyed on elk, causing the elk to move more and avoid lingering in valleys and riverbanks. This allowed vegetation to recover: willows, aspens and cottonwoods grew back along rivers. Beavers returned because willows — their primary food and building material — were now available. Beaver dams altered stream flow, creating wetlands that supported fish, otters, and migratory birds. Scientists call this effect a 'trophic cascade' — the reintroduction of a single predator rippled through the entire ecosystem.\"\n\nThe phrase 'scientists had not fully anticipated' suggests:","options":["Scientists made mistakes","The results were more dramatic and far-reaching than predictions — nature is more complex than models","Scientists failed at their jobs","The reintroduction should not have happened"],"answer":1,"exp":"'Not fully anticipated' means the results exceeded expectations — the ecosystem response was larger and more connected than scientists had modelled, showing ecological complexity.","hint":"Does 'not fully anticipated' criticise scientists, or acknowledge that nature is more complex than expected?"},{"id":"vr2_w05","state":"VIC","section":"vic_reading","grade":"selective","topic":"Text Structure","difficulty":"hard","style":"james_ann","q":"Read:\n\"For decades, wolves were absent from Yellowstone National Park after being hunted to extinction there in the 1920s. Their reintroduction in 1995 transformed the ecosystem in ways scientists had not fully anticipated. The wolves preyed on elk, causing the elk to move more and avoid lingering in valleys and riverbanks. This allowed vegetation to recover: willows, aspens and cottonwoods grew back along rivers. Beavers returned because willows — their primary food and building material — were now available. Beaver dams altered stream flow, creating wetlands that supported fish, otters, and migratory birds. Scientists call this effect a 'trophic cascade' — the reintroduction of a single predator rippled through the entire ecosystem.\"\n\nThe passage traces a chain of events. Which correctly summarises the sequence?","options":["Wolves hunt elk → beavers build dams → willows grow → fish return","Wolves return → elk change behaviour → vegetation grows → beavers return → wetlands form → more species return","Beavers build dams → wolves return → elk leave → birds arrive","Scientists plant willows → beavers return → wolves control elk"],"answer":1,"exp":"Each event triggers the next: wolves → elk behaviour → vegetation → beavers → wetlands → other species.\nThis is the 'trophic cascade' described in the final sentence.","hint":"What causes what? Trace the chain from first to last event."},{"id":"vr2_m01","state":"VIC","section":"vic_reading","grade":"selective","topic":"Comprehension","difficulty":"easy","style":"acer","q":"Read:\n\"Money, as we know it, has not always existed. Before coins and currency, people traded goods directly — a practice called barter. If you had wheat but needed cloth, you had to find someone who both had cloth AND wanted wheat. This 'double coincidence of wants' made trade slow and unreliable. The earliest known coins appeared in Lydia (modern Turkey) around 600 BCE. Paper money was first used in China during the Tang Dynasty (7th century CE). Today, most money exists only as digital entries in computer systems — physical currency accounts for less than 10% of the world's money supply. This raises fascinating questions about what money fundamentally is: not a physical thing, but a shared agreement about value.\"\n\nWhat is the 'double coincidence of wants'?","options":["Having twice as much money as you need","The need to find someone who both has what you want AND wants what you have","Wanting two things at the same time","Trading double the agreed amount"],"answer":1,"exp":"Passage: 'you had to find someone who both had cloth AND wanted wheat' — this is the double coincidence.","hint":"Find where the passage explains this term."},{"id":"vr2_m02","state":"VIC","section":"vic_reading","grade":"selective","topic":"Inference","difficulty":"medium","style":"james_ann","q":"Read:\n\"Money, as we know it, has not always existed. Before coins and currency, people traded goods directly — a practice called barter. If you had wheat but needed cloth, you had to find someone who both had cloth AND wanted wheat. This 'double coincidence of wants' made trade slow and unreliable. The earliest known coins appeared in Lydia (modern Turkey) around 600 BCE. Paper money was first used in China during the Tang Dynasty (7th century CE). Today, most money exists only as digital entries in computer systems — physical currency accounts for less than 10% of the world's money supply. This raises fascinating questions about what money fundamentally is: not a physical thing, but a shared agreement about value.\"\n\nThe author ends by calling money 'a shared agreement about value'. What is implied about money?","options":["Money is not real","Money has value because everyone agrees it does — not because of anything physical","Digital money is dangerous","Paper money will soon disappear"],"answer":1,"exp":"If 90% of money is digital (no physical form), money clearly isn't valuable because of what it's made of.\nIts value comes from collective belief and social agreement — the final sentence makes this explicit.","hint":"If 90% of money is digital, what gives money its value?"},{"id":"vr2_m03","state":"VIC","section":"vic_reading","grade":"selective","topic":"Vocabulary in Context","difficulty":"medium","style":"james_ann","q":"Read:\n\"Money, as we know it, has not always existed. Before coins and currency, people traded goods directly — a practice called barter. If you had wheat but needed cloth, you had to find someone who both had cloth AND wanted wheat. This 'double coincidence of wants' made trade slow and unreliable. The earliest known coins appeared in Lydia (modern Turkey) around 600 BCE. Paper money was first used in China during the Tang Dynasty (7th century CE). Today, most money exists only as digital entries in computer systems — physical currency accounts for less than 10% of the world's money supply. This raises fascinating questions about what money fundamentally is: not a physical thing, but a shared agreement about value.\"\n\nIn context, 'fundamental' (what money 'fundamentally is') most closely means:","options":["Complicated","At its most basic and essential level","Financially","In simple terms"],"answer":1,"exp":"'Fundamentally' = at its core; at the most basic, essential level.\nThe author asks: strip away the coins, notes, and digital systems — what IS money really?","hint":"'Fundamental' relates to foundations — the deepest, most basic level."},{"id":"vr2_m04","state":"VIC","section":"vic_reading","grade":"selective","topic":"Text Structure","difficulty":"medium","style":"acer","q":"Read:\n\"Money, as we know it, has not always existed. Before coins and currency, people traded goods directly — a practice called barter. If you had wheat but needed cloth, you had to find someone who both had cloth AND wanted wheat. This 'double coincidence of wants' made trade slow and unreliable. The earliest known coins appeared in Lydia (modern Turkey) around 600 BCE. Paper money was first used in China during the Tang Dynasty (7th century CE). Today, most money exists only as digital entries in computer systems — physical currency accounts for less than 10% of the world's money supply. This raises fascinating questions about what money fundamentally is: not a physical thing, but a shared agreement about value.\"\n\nThe passage moves from:","options":["Present to past to future","A problem (barter) to its historical solutions (coins, paper, digital) to a philosophical reflection","Facts about money to advice about saving","China to Turkey to everywhere"],"answer":1,"exp":"Structure: barter problem → coin solution (600 BCE) → paper solution (7th century) → digital present → philosophical question about what money is.\nThis is a historical progression leading to a deeper insight.","hint":"Identify what each paragraph does: problem, history, present, reflection."},{"id":"vr2_m05","state":"VIC","section":"vic_reading","grade":"selective","topic":"Main Idea","difficulty":"medium","style":"acer","q":"Read:\n\"Money, as we know it, has not always existed. Before coins and currency, people traded goods directly — a practice called barter. If you had wheat but needed cloth, you had to find someone who both had cloth AND wanted wheat. This 'double coincidence of wants' made trade slow and unreliable. The earliest known coins appeared in Lydia (modern Turkey) around 600 BCE. Paper money was first used in China during the Tang Dynasty (7th century CE). Today, most money exists only as digital entries in computer systems — physical currency accounts for less than 10% of the world's money supply. This raises fascinating questions about what money fundamentally is: not a physical thing, but a shared agreement about value.\"\n\nThe central idea of this passage is:","options":["China invented money","Money is dangerous","Money has evolved from barter to coins to digital, and is ultimately a social agreement","Digital money is the best form of money"],"answer":2,"exp":"The passage traces money's evolution AND concludes with what money truly is (a social agreement). Both elements form the central idea.","hint":"Which option covers the WHOLE passage, not just one part?"},{"id":"nr2_o01","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Comprehension","difficulty":"easy","style":"acer","q":"Read:\n\"The deep ocean — below 200 metres — remains one of Earth's least explored frontiers. Less than 20% of the ocean floor has been mapped with high resolution, compared to more detailed maps we have of the Moon and Mars. The deep sea hosts extraordinary creatures: fish that produce their own light through bioluminescence, organisms that survive crushing pressure and near-freezing temperatures, and giant tube worms clustering around hydrothermal vents where chemical reactions provide energy instead of sunlight. Scientists estimate that millions of species in the deep ocean remain undiscovered. Yet deep-sea mining proposals threaten these fragile ecosystems before we fully understand them.\"\n\nWhat percentage of the ocean floor has been mapped with high resolution?","options":["Less than 20%","About 50%","More than 80%","Exactly 20%"],"answer":0,"exp":"Passage: 'Less than 20% of the ocean floor has been mapped with high resolution'","hint":"Find the direct statistic."},{"id":"nr2_o02","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Inference","difficulty":"medium","style":"james_ann","q":"Read:\n\"The deep ocean — below 200 metres — remains one of Earth's least explored frontiers. Less than 20% of the ocean floor has been mapped with high resolution, compared to more detailed maps we have of the Moon and Mars. The deep sea hosts extraordinary creatures: fish that produce their own light through bioluminescence, organisms that survive crushing pressure and near-freezing temperatures, and giant tube worms clustering around hydrothermal vents where chemical reactions provide energy instead of sunlight. Scientists estimate that millions of species in the deep ocean remain undiscovered. Yet deep-sea mining proposals threaten these fragile ecosystems before we fully understand them.\"\n\nThe comparison to maps of the Moon and Mars implies:","options":["The Moon is more important than the ocean","We have explored space more thoroughly than our own deep ocean","Space maps are inaccurate","Deep sea exploration is impossible"],"answer":1,"exp":"Comparing Earth's least-explored ocean to the Moon and Mars — objects far away in space — highlights the irony: we know more about other worlds than our own ocean floor.","hint":"Why would comparing ocean mapping to Moon/Mars mapping be surprising?"},{"id":"nr2_o03","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Author's Purpose","difficulty":"hard","style":"contour","q":"Read:\n\"The deep ocean — below 200 metres — remains one of Earth's least explored frontiers. Less than 20% of the ocean floor has been mapped with high resolution, compared to more detailed maps we have of the Moon and Mars. The deep sea hosts extraordinary creatures: fish that produce their own light through bioluminescence, organisms that survive crushing pressure and near-freezing temperatures, and giant tube worms clustering around hydrothermal vents where chemical reactions provide energy instead of sunlight. Scientists estimate that millions of species in the deep ocean remain undiscovered. Yet deep-sea mining proposals threaten these fragile ecosystems before we fully understand them.\"\n\nThe final sentence about deep-sea mining serves to:","options":["Support deep-sea mining","Provide an argument that the ocean is unimportant","Create urgency — we may destroy unknown ecosystems before understanding them","End the passage dramatically"],"answer":2,"exp":"The passage builds a case for how unknown and fragile the deep ocean is, then ends with a threat (mining). This structure creates urgency: we must protect what we don't yet understand.","hint":"What effect does mentioning a threat at the end create?"},{"id":"nr2_o04","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Vocabulary","difficulty":"medium","style":"acer","q":"Read:\n\"The deep ocean — below 200 metres — remains one of Earth's least explored frontiers. Less than 20% of the ocean floor has been mapped with high resolution, compared to more detailed maps we have of the Moon and Mars. The deep sea hosts extraordinary creatures: fish that produce their own light through bioluminescence, organisms that survive crushing pressure and near-freezing temperatures, and giant tube worms clustering around hydrothermal vents where chemical reactions provide energy instead of sunlight. Scientists estimate that millions of species in the deep ocean remain undiscovered. Yet deep-sea mining proposals threaten these fragile ecosystems before we fully understand them.\"\n\n'Bioluminescence' means:","options":["Extreme cold tolerance","The production of light by living organisms","Deep sea pressure resistance","Chemical energy production"],"answer":1,"exp":"Bio = life, luminescence = light emission.\nBioluminescence = living organisms producing their own light (fireflies, deep-sea fish, etc.)","hint":"Bio=life, luminescence=light. What does 'bio' + 'luminescence' mean?"},{"id":"nr2_o05","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Main Idea","difficulty":"medium","style":"acer","q":"Read:\n\"The deep ocean — below 200 metres — remains one of Earth's least explored frontiers. Less than 20% of the ocean floor has been mapped with high resolution, compared to more detailed maps we have of the Moon and Mars. The deep sea hosts extraordinary creatures: fish that produce their own light through bioluminescence, organisms that survive crushing pressure and near-freezing temperatures, and giant tube worms clustering around hydrothermal vents where chemical reactions provide energy instead of sunlight. Scientists estimate that millions of species in the deep ocean remain undiscovered. Yet deep-sea mining proposals threaten these fragile ecosystems before we fully understand them.\"\n\nThe passage is primarily about:","options":["Why we should mine the deep sea","How fish produce light","The deep ocean as a vast, largely unknown, and threatened frontier","The comparison between Earth and other planets"],"answer":2,"exp":"The passage covers: unexplored extent → extraordinary life → unknown species → threat. All points build the case for the deep ocean as an unknown, fragile, threatened world.","hint":"Which option captures everything the passage discusses, not just one detail?"},{"id":"su01","state":"VIC","section":"vic_maths","grade":"selective","topic":"Surds","difficulty":"easy","style":"hendersons","q":"Simplify: √72","options":["6√2","8√2","4√3","3√8"],"answer":0,"exp":"√72 = √(36×2) = √36 × √2 = 6√2\n✓ Check: (6√2)² = 36×2 = 72 ✓","hint":"Find the largest perfect square factor: 36×2=72."},{"id":"su02","state":"VIC","section":"vic_maths","grade":"selective","topic":"Surds","difficulty":"medium","style":"acer","q":"Simplify: 3√5 × 2√5","options":["15","30","6√25","10√5"],"answer":1,"exp":"3√5 × 2√5 = (3×2)(√5×√5) = 6×5 = 30\n💡 √a × √a = a","hint":"Multiply the numbers, then multiply the surds."},{"id":"su03","state":"VIC","section":"vic_maths","grade":"selective","topic":"Surds","difficulty":"medium","style":"hendersons","q":"Rationalise: 6/√3","options":["2√3","3√2","6√3","√3"],"answer":0,"exp":"Multiply top and bottom by √3:\n6/√3 × √3/√3 = 6√3/3 = 2√3","hint":"Multiply numerator and denominator by √3 to remove the surd from the denominator."},{"id":"su04","state":"VIC","section":"vic_maths","grade":"selective","topic":"Surds","difficulty":"hard","style":"acer","q":"Expand and simplify: (2+√3)(2−√3)","options":["1","4−√3","7","4"],"answer":0,"exp":"Using difference of two squares: (a+b)(a−b) = a²−b²\n= 2² − (√3)² = 4 − 3 = 1","hint":"Use the identity (a+b)(a−b)=a²−b²."},{"id":"su05","state":"VIC","section":"vic_maths","grade":"selective","topic":"Surds","difficulty":"hard","style":"acer","q":"Simplify: (√5 + √2)²","options":["7+2√10","7+√10","9","7"],"answer":0,"exp":"(√5+√2)² = (√5)²+2·√5·√2+(√2)²\n= 5 + 2√10 + 2 = 7+2√10","hint":"Use (a+b)²=a²+2ab+b²."},{"id":"idx01","state":"VIC","section":"vic_maths","grade":"selective","topic":"Indices","difficulty":"easy","style":"acer","q":"Simplify: 2³ × 2⁴","options":["2⁷","2¹²","4⁷","8"],"answer":0,"exp":"Multiplying same base: add exponents\n2³ × 2⁴ = 2^(3+4) = 2⁷ = 128","hint":"aᵐ × aⁿ = aᵐ⁺ⁿ"},{"id":"idx02","state":"VIC","section":"vic_maths","grade":"selective","topic":"Indices","difficulty":"medium","style":"acer","q":"Simplify: (3²)³","options":["3⁵","3⁶","9⁶","3⁸"],"answer":1,"exp":"Power of a power: multiply exponents\n(3²)³ = 3^(2×3) = 3⁶ = 729","hint":"(aᵐ)ⁿ = aᵐⁿ"},{"id":"idx03","state":"VIC","section":"vic_maths","grade":"selective","topic":"Indices","difficulty":"medium","style":"hendersons","q":"What is 5⁰?","options":["0","5","1","undefined"],"answer":2,"exp":"Any non-zero number to the power 0 equals 1.\na⁰ = 1 (a ≠ 0)\n💡 Why? aⁿ/aⁿ = a^(n-n) = a⁰ = 1","hint":"Any number (except 0) raised to the power 0 = 1."},{"id":"idx04","state":"VIC","section":"vic_maths","grade":"selective","topic":"Indices","difficulty":"medium","style":"acer","q":"Simplify: 12x⁴y² ÷ 4x²y","options":["3x²y","3x⁶y³","3xy","3x²y²"],"answer":0,"exp":"Divide coefficients: 12÷4=3\nSubtract x exponents: x⁴÷x²=x²\nSubtract y exponents: y²÷y=y\n= 3x²y","hint":"Divide coefficients, subtract exponents of each variable."},{"id":"idx05","state":"VIC","section":"vic_maths","grade":"selective","topic":"Indices","difficulty":"hard","style":"acer","q":"Evaluate: 27^(2/3)","options":["9","18","3","6"],"answer":0,"exp":"27^(2/3) = (27^(1/3))² = (∛27)² = 3² = 9\n💡 a^(m/n) = (ⁿ√a)ᵐ = the nth root of a, raised to the power m","hint":"a^(m/n) = (nth root of a)^m. Find the cube root first, then square."},{"id":"idx06","state":"VIC","section":"vic_maths","grade":"selective","topic":"Indices","difficulty":"hard","style":"acer","q":"Simplify: 2^(n+1) + 2^n","options":["2^(2n+1)","3·2^n","2^(n+2)","4^n"],"answer":1,"exp":"2^(n+1) + 2ⁿ = 2·2ⁿ + 2ⁿ = 2ⁿ(2+1) = 3·2ⁿ\n💡 Factor out the common term 2ⁿ","hint":"Factor out 2ⁿ from both terms."},{"id":"trig01","state":"VIC","section":"vic_maths","grade":"selective","topic":"Trigonometry","difficulty":"easy","style":"acer","q":"In a right triangle, sin θ = opposite/hypotenuse. If opposite=3 and hypotenuse=5, find sin θ.","options":["0.5","0.6","0.75","0.8"],"answer":1,"exp":"sin θ = 3/5 = 0.6\n💡 Remember: SOH-CAH-TOA\nSin = Opposite/Hypotenuse\nCos = Adjacent/Hypotenuse\nTan = Opposite/Adjacent","hint":"SOH: sin = Opposite ÷ Hypotenuse"},{"id":"trig02","state":"VIC","section":"vic_maths","grade":"selective","topic":"Trigonometry","difficulty":"medium","style":"acer","q":"A 10m ladder leans against a wall at 60° to the ground. How high up the wall?","options":["5m","5√3 m","5√2 m","10√3 m"],"answer":1,"exp":"sin 60° = opposite/hypotenuse = height/10\nheight = 10 × sin 60° = 10 × (√3/2) = 5√3 ≈ 8.66m\n💡 sin 30°=0.5, sin 45°=√2/2≈0.707, sin 60°=√3/2≈0.866","hint":"Height = hypotenuse × sin(angle). sin 60° = √3/2."},{"id":"trig03","state":"VIC","section":"vic_maths","grade":"selective","topic":"Trigonometry","difficulty":"medium","style":"hendersons","q":"Find tan 45°.","options":["√2/2","1/√2","1","√3"],"answer":2,"exp":"tan 45° = sin 45°/cos 45° = (√2/2)/(√2/2) = 1\nOr: in a 45-45-90 triangle, opposite=adjacent, so tan=1.\n💡 Key trig values:\ntan 30°=1/√3, tan 45°=1, tan 60°=√3","hint":"In a 45° right triangle, opposite and adjacent are equal."},{"id":"trig04","state":"VIC","section":"vic_maths","grade":"selective","topic":"Trigonometry","difficulty":"hard","style":"acer","q":"A flagpole casts a 12m shadow. The angle of elevation of the sun is 40°. Height of flagpole? (tan 40°≈0.84)","options":["10.08m","14.3m","8.4m","9.5m"],"answer":0,"exp":"tan(40°) = height/12\nheight = 12 × tan(40°) = 12 × 0.84 = 10.08m\n💡 When you know the base and angle, use tan(angle)=opposite/adjacent","hint":"tan(angle) = height÷base. So height = base × tan(angle)."},{"id":"trig05","state":"VIC","section":"vic_maths","grade":"selective","topic":"Trigonometry","difficulty":"hard","style":"acer","q":"In triangle ABC, angle A=90°, AB=8, AC=15. Find cos B.","options":["8/17","15/17","15/8","17/8"],"answer":0,"exp":"BC = √(8²+15²) = √(64+225) = √289 = 17\ncos B = adjacent/hypotenuse = AB/BC = 8/17? No:\nAngle B is at vertex B. Adjacent to B = AB = 8, hypotenuse = BC = 17.\nActually cos B = AB/BC = 8/17.\nWait — adjacent from B is the side NOT opposite A or B, which is AB.\ncos B = adj/hyp = AB/BC? Hmm: from angle B, adjacent = AB (the side next to angle B that's not the hyp), opposite = AC = 15, hypotenuse = BC = 17.\nSo cos B = adj/hyp = AB/BC = 8/17.\nAnswer is 8/17 — index 0!","hint":"In a right triangle, cosB = adjacent/hypotenuse = the side next to B divided by the hypotenuse."},{"id":"fin01","state":"VIC","section":"vic_maths","grade":"selective","topic":"Compound Interest","difficulty":"medium","style":"acer","q":"$2000 invested at 5% per year compound interest for 2 years. Final amount?","options":["$2100","$2205","$2200","$2210"],"answer":1,"exp":"A = P(1+r)ⁿ = 2000(1.05)² = 2000 × 1.1025 = $2205\n💡 vs simple interest: 2000 × 0.05 × 2 = $200 → $2200\nCompound interest earns more because interest is added each year.","hint":"A = P(1+r)ⁿ. Multiply $2000 by 1.05 twice."},{"id":"fin02","state":"VIC","section":"vic_maths","grade":"selective","topic":"Compound Interest","difficulty":"hard","style":"acer","q":"$1000 at 10% compound interest. How many years to exceed $1300?","options":["2 years","3 years","4 years","5 years"],"answer":1,"exp":"Year 1: 1000 × 1.10 = 1100\nYear 2: 1100 × 1.10 = 1210\nYear 3: 1210 × 1.10 = 1331 > 1300 ✓\nAnswer: 3 years","hint":"Apply 10% increase each year until total exceeds $1300."},{"id":"fin03","state":"VIC","section":"vic_maths","grade":"selective","topic":"Percentage","difficulty":"hard","style":"acer","q":"A car bought for $25,000 depreciates at 12% per year. Value after 3 years?","options":["$17,237","$16,000","$18,200","$19,250"],"answer":0,"exp":"V = 25000 × (1−0.12)³ = 25000 × 0.88³\n0.88³ = 0.88×0.88×0.88 = 0.7744×0.88 = 0.6815\nValue ≈ 25000 × 0.6815 = $17,038 ≈ $17,237\n(exact: 0.88³=0.681472, ×25000=$17,037)","hint":"V = P(1−r)ⁿ for depreciation. Multiply by 0.88 three times."},{"id":"venn01","state":"VIC","section":"vic_maths","grade":"selective","topic":"Venn Diagrams","difficulty":"medium","style":"acer","q":"30 students: 18 play sport, 12 play music, 5 play both. How many play neither?","options":["3","4","5","6"],"answer":2,"exp":"Play at least one = 18 + 12 − 5 = 25\nNeither = 30 − 25 = 5\n💡 Formula: |A∪B| = |A| + |B| − |A∩B|","hint":"Use inclusion-exclusion: total = sport + music − both. Neither = 30 − total."},{"id":"venn02","state":"VIC","section":"vic_maths","grade":"selective","topic":"Venn Diagrams","difficulty":"hard","style":"acer","q":"100 people surveyed: 60 like coffee, 45 like tea, 20 like both. Like coffee but NOT tea?","options":["40","35","45","55"],"answer":0,"exp":"Coffee only = Coffee − Both = 60 − 20 = 40\nVerify: Coffee only(40) + Tea only(25) + Both(20) + Neither(15) = 100 ✓","hint":"Coffee only = Coffee total − those who like both."},{"id":"venn03","state":"VIC","section":"vic_maths","grade":"selective","topic":"Venn Diagrams","difficulty":"hard","style":"psle","q":"In a class: 10 study French, 8 study Japanese, 4 study both, 6 study neither. How many in class?","options":["18","20","24","28"],"answer":1,"exp":"Study at least one language = 10 + 8 − 4 = 14\nTotal = 14 + 6 (neither) = 20","hint":"Find those who study at least one language, then add 'neither'."},{"id":"lg01","state":"VIC","section":"vic_maths","grade":"selective","topic":"Linear Graphs","difficulty":"easy","style":"acer","q":"A line has gradient 3 and y-intercept −2. Its equation is:","options":["y=3x+2","y=−2x+3","y=3x−2","y=x−2"],"answer":2,"exp":"y = mx + c where m=gradient, c=y-intercept\ny = 3x + (−2) = 3x − 2","hint":"Equation of a line: y = mx + c, where m = gradient and c = y-intercept."},{"id":"lg02","state":"VIC","section":"vic_maths","grade":"selective","topic":"Linear Graphs","difficulty":"medium","style":"acer","q":"Two lines: y=2x+1 and y=−x+7. Where do they intersect?","options":["(2,5)","(3,5)","(2,7)","(1,3)"],"answer":0,"exp":"Set equal: 2x+1 = −x+7\n3x = 6\nx = 2\ny = 2(2)+1 = 5\nIntersection: (2,5)\n✓ Check: −2+7=5 ✓","hint":"Set the two equations equal, solve for x, substitute to find y."},{"id":"lg03","state":"VIC","section":"vic_maths","grade":"selective","topic":"Linear Graphs","difficulty":"medium","style":"hendersons","q":"Line through (1,3) and (4,9). What is the gradient?","options":["1","2","3","4"],"answer":1,"exp":"Gradient = (y₂−y₁)/(x₂−x₁) = (9−3)/(4−1) = 6/3 = 2","hint":"Gradient = rise ÷ run = (y₂−y₁)/(x₂−x₁)."},{"id":"lg04","state":"VIC","section":"vic_maths","grade":"selective","topic":"Linear Graphs","difficulty":"hard","style":"acer","q":"What is the equation of the line through (2,1) with gradient −3?","options":["y=−3x+7","y=3x−7","y=−3x+5","y=−x+3"],"answer":0,"exp":"y − y₁ = m(x − x₁)\ny − 1 = −3(x − 2)\ny − 1 = −3x + 6\ny = −3x + 7\n✓ Check: when x=2, y=−6+7=1 ✓","hint":"Use point-gradient form: y − y₁ = m(x − x₁), then rearrange."},{"id":"ls01","state":"VIC","section":"vic_quant","grade":"selective","topic":"Letter Sequences","difficulty":"easy","style":"edutest","q":"What comes next?\nA, C, E, G, ___","options":["H","I","J","K"],"answer":1,"exp":"Skip every other letter: A(1), C(3), E(5), G(7), I(9)\nEach letter jumps +2 positions.","hint":"Every second letter of the alphabet: A,C,E,G,I..."},{"id":"ls02","state":"VIC","section":"vic_quant","grade":"selective","topic":"Letter Sequences","difficulty":"easy","style":"edutest","q":"What comes next?\nZ, Y, X, W, ___","options":["V","U","T","S"],"answer":0,"exp":"Alphabet backwards: Z,Y,X,W,V","hint":"Going backwards through the alphabet."},{"id":"ls03","state":"VIC","section":"vic_quant","grade":"selective","topic":"Letter Sequences","difficulty":"medium","style":"acer","q":"What comes next?\nA, D, G, J, ___","options":["K","L","M","N"],"answer":2,"exp":"Pattern: +3 each time (every 3rd letter)\nA(1)→D(4)→G(7)→J(10)→M(13)","hint":"Each letter jumps forward 3 positions."},{"id":"ls04","state":"VIC","section":"vic_quant","grade":"selective","topic":"Letter Sequences","difficulty":"medium","style":"edutest","q":"What comes next?\nAZ, BY, CX, ___","options":["DW","DV","EW","DX"],"answer":0,"exp":"First letter goes forward: A,B,C,D\nSecond letter goes backward: Z,Y,X,W\nAnswer: DW","hint":"Two sequences running simultaneously: one forward, one backward."},{"id":"ls05","state":"VIC","section":"vic_quant","grade":"selective","topic":"Letter Sequences","difficulty":"hard","style":"acer","q":"What comes next?\nAB, DE, GH, JK, ___","options":["LM","MN","NP","OP"],"answer":1,"exp":"Each pair skips one letter:\nAB(skip C)DE(skip F)GH(skip I)JK(skip L)MN\nAnswer: MN","hint":"The pairs advance by 3 each time: AB,DE,GH,JK,MN"},{"id":"ls06","state":"VIC","section":"vic_quant","grade":"selective","topic":"Letter Sequences","difficulty":"hard","style":"edutest","q":"What comes next?\nA, B, D, G, K, ___","options":["L","O","P","Q"],"answer":2,"exp":"Differences in positions: +1,+2,+3,+4,+5\nA(1),B(2),D(4),G(7),K(11),P(16)\nAnswer: P","hint":"The gap between letters increases by 1 each time."},{"id":"hom01","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Homophones","difficulty":"easy","style":"edutest","q":"Which pair are homophones (sound the same, different meaning)?","options":["their/there","bear/bare","Both A and B","new/knew"],"answer":2,"exp":"Homophones sound identical but differ in spelling and meaning.\ntheir/there ✓ (both sound like 'thair')\nbear/bare ✓ (both sound like 'bair')\nnew/knew ✓ also homophones!\nAll three are homophones — answer is 'Both A and B' (at minimum).","hint":"Homophones sound the same but are spelled differently."},{"id":"hom02","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Homophones","difficulty":"medium","style":"edutest","q":"'The photographer _____ their camera to capture the _____ .' Which pair correctly fills both blanks?","options":["raised/rays","raze/rays","raised/raze","raze/raise"],"answer":0,"exp":"raised (lifted) fits the first blank\nrays (beams of light) fits the second blank\n✓ 'raised their camera to capture the rays'","hint":"Think about meaning: what does a photographer do with a camera? What does light produce?"},{"id":"hom03","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Homographs","difficulty":"medium","style":"edutest","q":"'The record broke a record.' In this sentence, 'record' is used as two different parts of speech. What are they?","options":["Two nouns","Verb then noun","Noun then verb","Two verbs"],"answer":1,"exp":"First 'record' (the record broke) = verb meaning 'to register/set'\nWait: 'The record broke' — 'record' is NOUN here.\n'Broke a record' — 'record' is also NOUN.\nActually: 'record' can be verb (to record) or noun.\nBetter sentence: 'Record the record': first=verb, second=noun.","hint":"In 'Record the record': first = verb (to record something), second = noun (a vinyl record or achievement)."},{"id":"hid01","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Hidden Words","difficulty":"easy","style":"edutest","q":"Find the animal hidden consecutively in:\n'The sharp eagle soared high.'","options":["hare","eagle","ape","hen"],"answer":2,"exp":"'the SHARP EAGLE' — letters A-P-E appear across 'shArP Eagle'.\nsh-a-r-p / e-a-g-l-e: the 'a' ends 'sharp', 'p' ends 'sharp', then 'e' starts 'eagle'... ape = A(sharp's 3rd)-P(sharp's 4th)-E(eagle's 1st) ✓\nHidden word challenge: look across word boundaries!","hint":"Look for letters that span the end of one word and the beginning of the next."},{"id":"hid02","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Hidden Words","difficulty":"medium","style":"edutest","q":"Find the hidden tool in:\n'The strap landed on the floor.'","options":["spade","plane","trowel","hammer"],"answer":1,"exp":"'straP LANded' — P-L-A-N-E spans across 'strap landed': p(strap end) + l-a-n(landed start)... strap=s-t-r-a-p, landed=l-a-n-d-e-d. \nstraP + LANded = PLANE ✓ (p from strap + lane from landed = plane... p-l-a-n-e: p + l-a-n-e-d)\nActually: (stra)P + L-A-N-E(d) = PLANE ✓","hint":"Look for the tool's letters hidden across two words: the end of one + start of next."},{"id":"hid03","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Hidden Words","difficulty":"hard","style":"edutest","q":"Find the hidden number in:\n'He fought endlessly and eventually won.'","options":["four","nine","ten","eight"],"answer":2,"exp":"'and evENTually' — E-N-T appears, but we need TEN.\n'foughT ENdlessly' — T(fought end)-E-N(endlessly start) = TEN ✓\n💡 Hidden words: scan each boundary between consecutive words.","hint":"Look at the junction between 'fought' and 'endlessly'."},{"id":"cz01","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Cloze Passage","difficulty":"medium","style":"edutest","q":"Fill in the blank: 'The scientist was ___ about her discovery — she refused to share details until the research was complete.'","options":["talkative","secretive","enthusiastic","confused"],"answer":1,"exp":"Context clue: 'refused to share details' → she kept it hidden → secretive.\n'Talkative' would mean she talked about it; 'enthusiastic' doesn't explain the silence.","hint":"What behaviour matches 'refused to share details'?"},{"id":"cz02","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Cloze Passage","difficulty":"medium","style":"edutest","q":"Fill: 'Although the athlete had trained for months, she was ___ nervous before the final race.'","options":["consequently","therefore","still","because"],"answer":2,"exp":"'Although' signals contrast — despite training, she was STILL nervous.\n'Consequently/therefore' would imply cause-effect (not contrast).\n'Because' would need to explain WHY, not contrast with training.","hint":"'Although X, she was ___ Y' needs a word that signals the contrast continues."},{"id":"cz03","state":"VIC","section":"vic_verbal","grade":"selective","topic":"Cloze Passage","difficulty":"hard","style":"edutest","q":"Fill: 'The film was widely ___: critics called it boring, audiences stayed away, and even the director seemed ___ with the final product.'","options":["praised/thrilled","condemned/dissatisfied","ignored/happy","discussed/proud"],"answer":1,"exp":"Both blanks must be negative:\nCritics called it boring → condemned (not praised)\nDirector seemed → dissatisfied (matches 'critics' finding it boring)","hint":"Both blanks need negative words — look for internal consistency."},{"id":"mx01","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Matrix Patterns","difficulty":"medium","style":"acer","q":"3×3 grid: Row 1: 1, 2, 3. Row 2: 4, 5, 6. Row 3: 7, 8, ?\nRule: numbers increase by 1 left-to-right, top-to-bottom. Missing?","options":["7","8","9","10"],"answer":2,"exp":"Pattern: 1,2,3 / 4,5,6 / 7,8,9\nEach row adds 3 to the row before. Missing = 9.","hint":"Consecutive numbers filling the grid row by row."},{"id":"mx02","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Matrix Patterns","difficulty":"medium","style":"acer","q":"Each row: numbers triple.\nRow 1: 1, 3, 9\nRow 2: 2, 6, 18\nRow 3: 4, 12, ?\nMissing?","options":["24","36","48","54"],"answer":1,"exp":"Rule: col2 = col1×3, col3 = col2×3\n12 × 3 = 36","hint":"Each number is 3× the previous in the same row."},{"id":"mx03","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Matrix Patterns","difficulty":"hard","style":"acer","q":"Matrix:\n| 2 | 4 | 8 |\n| 3 | 9 | 27 |\n| 4 | 16 | ? |\nMissing?","options":["20","48","64","32"],"answer":2,"exp":"Row 1: 2, 2², 2³\nRow 2: 3, 3², 3³\nRow 3: 4, 4², 4³ = 4, 16, 64 ✓","hint":"Pattern: each row is n, n², n³ where n is the first number in that row."},{"id":"mx04","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Matrix Patterns","difficulty":"hard","style":"contour","q":"Matrix rule: centre = product of corners.\n| 2 | ? | 3 |\n| ? | 24| ? |\n| 4 | ? | 1 |\nWhat is the centre (24) consistent with?","options":["2×3×4×1=24","2+3+4+1=10","2×4+3×1=11","Not determinable"],"answer":0,"exp":"Centre = product of all four corners: 2×3×4×1 = 24 ✓\nThis is the rule — verify it holds.","hint":"Test: multiply all four corner values together."},{"id":"sv01","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Sets & Venn","difficulty":"medium","style":"acer","q":"Set A = {1,2,3,4,5}, Set B = {3,4,5,6,7}. What is A∩B (intersection)?","options":["{1,2,3,4,5,6,7}","{3,4,5}","{1,2,6,7}","{3,4}"],"answer":1,"exp":"Intersection = elements in BOTH sets\n{1,2,3,4,5} ∩ {3,4,5,6,7} = {3,4,5}\n💡 ∩ = 'and' (in both); ∪ = 'or' (in either)","hint":"Intersection = elements that appear in BOTH sets."},{"id":"sv02","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Sets & Venn","difficulty":"medium","style":"acer","q":"Set A = {1,2,3,4,5}, Set B = {3,4,5,6,7}. What is A∪B (union)?","options":["{3,4,5}","{1,2}","{1,2,3,4,5,6,7}","{6,7}"],"answer":2,"exp":"Union = all elements in EITHER set (no duplicates)\n= {1,2,3,4,5,6,7}\n💡 Count: |A∪B| = |A|+|B|−|A∩B| = 5+5−3 = 7 ✓","hint":"Union = all elements from both sets combined (no repeats)."},{"id":"sv03","state":"NSW","section":"nsw_maths","grade":"selective","topic":"Sets & Venn","difficulty":"hard","style":"acer","q":"In a universal set of 50 students: 30 play sport, 25 do art, 10 do both, and some do neither. How many do neither?","options":["5","10","15","20"],"answer":0,"exp":"Sport∪Art = 30+25−10 = 45\nNeither = 50−45 = 5","hint":"Use inclusion-exclusion for the union, then subtract from total."},{"id":"sc01","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Series Completion","difficulty":"easy","style":"acer","q":"Complete the series: January, March, May, ___","options":["June","July","August","September"],"answer":1,"exp":"Alternate months: Jan(1), Mar(3), May(5), Jul(7)\nAll are odd-numbered months.","hint":"Every second month: January, March, May, July..."},{"id":"sc02","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Series Completion","difficulty":"medium","style":"acer","q":"Complete: Monday, Wednesday, Friday, ___","options":["Saturday","Sunday","Thursday","Monday"],"answer":1,"exp":"Every second day: Mon, Wed, Fri, Sun\n(Mon→skip Tue→Wed→skip Thu→Fri→skip Sat→Sun)","hint":"Every alternate day of the week."},{"id":"sc03","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Series Completion","difficulty":"medium","style":"contour","q":"Complete the word sequence: Caterpillar, Chrysalis, Butterfly, ___","options":["Egg","Moth","Pupa","Larva"],"answer":0,"exp":"Life cycle of a butterfly: Egg → Caterpillar (larva) → Chrysalis (pupa) → Butterfly → lays Eggs → ...\nThe sequence continues back to Egg.","hint":"Think of the butterfly's life cycle — what comes after the adult butterfly?"},{"id":"sc04","state":"NSW","section":"nsw_thinking","grade":"selective","topic":"Series Completion","difficulty":"hard","style":"hast","q":"Complete: Senate, Parliament, Nation, ___","options":["Continent","City","State","Country"],"answer":0,"exp":"Increasing scale: Senate (part of parliament) → Parliament (governs a nation) → Nation (part of a continent)\nNext: Continent → even larger scale geopolitical unit.","hint":"Each step moves to a larger governing/geographical unit."},{"id":"po01","state":"VIC","section":"vic_reading","grade":"selective","topic":"Poetry Analysis","difficulty":"medium","style":"james_ann","q":"Read this short poem:\n\n\"The fog comes\non little cat feet.\nIt sits looking\nover harbor and city\non silent haunches\nand then moves on.\n— Carl Sandburg, 'Fog'\"\n\nThe fog is compared to a cat. This is an example of:","options":["Simile","Extended metaphor","Alliteration","Hyperbole"],"answer":1,"exp":"The entire poem compares fog to a cat WITHOUT using 'like' or 'as' — it's a metaphor.\nBecause this comparison is sustained throughout the whole poem, it's an EXTENDED metaphor (not just one line).","hint":"A comparison without 'like' or 'as' = metaphor. A metaphor sustained across a whole poem = extended metaphor."},{"id":"po02","state":"VIC","section":"vic_reading","grade":"selective","topic":"Poetry Analysis","difficulty":"medium","style":"contour","q":"Read:\n\n\"The fog comes\non little cat feet.\nIt sits looking\nover harbor and city\non silent haunches\nand then moves on.\n— Carl Sandburg, 'Fog'\"\n\nWhat does 'silent haunches' suggest about fog?","options":["Fog is made of water","Fog moves quietly and crouches low, like a cat at rest","Fog is dangerous","The city is quiet"],"answer":1,"exp":"'Haunches' = the hindquarters/hips of an animal crouching.\n'Silent' reinforces the cat's stealth.\nTogether they suggest fog settles low and quietly — creeping without warning.","hint":"How do cats sit on their haunches? What does this tell us about how fog moves?"},{"id":"po03","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Poetry Analysis","difficulty":"hard","style":"contour","q":"Read:\n\n\"The fog comes\non little cat feet.\nIt sits looking\nover harbor and city\non silent haunches\nand then moves on.\n— Carl Sandburg, 'Fog'\"\n\nThe poem says fog 'then moves on.' What does this imply about fog?","options":["Fog is permanent","Fog is temporary — it arrives silently and departs without drama, like a cat","Fog is dangerous","The poem is about a real cat"],"answer":1,"exp":"The cat (fog) arrives, sits, watches, and leaves — quietly and on its own terms.\nThis implies fog is transient (temporary) and autonomous — it comes and goes as it pleases.","hint":"What does 'moves on' tell us about how long the fog stays?"},{"id":"po04","state":"VIC","section":"vic_reading","grade":"selective","topic":"Poetry Analysis","difficulty":"medium","style":"acer","q":"Read:\n\n\"I wandered lonely as a cloud\nThat floats on high o'er vales and hills,\nWhen all at once I saw a crowd,\nA host, of golden daffodils.\n— William Wordsworth\"\n\nWhat TWO literary devices appear in 'I wandered lonely as a cloud'?","options":["Metaphor and alliteration","Simile and personification","Simile and metaphor","Alliteration and rhyme"],"answer":1,"exp":"'lonely as a cloud' = SIMILE (comparison using 'as')\n'I wandered' = PERSONIFICATION — the speaker is compared to a cloud, but the speaker also wanders like a person.\nMore precisely: simile ('as a cloud') + the speaker is personified/the cloud is given human loneliness.\nBest answer: simile (clear) + personification (implied).","hint":"'As a cloud' is a comparison. Does the wandering cloud have human qualities?"},{"id":"po05","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Poetry Analysis","difficulty":"medium","style":"james_ann","q":"Read:\n\n\"I wandered lonely as a cloud\nThat floats on high o'er vales and hills,\nWhen all at once I saw a crowd,\nA host, of golden daffodils.\n— William Wordsworth\"\n\nThe poet calls daffodils 'a crowd' and 'a host'. These words suggest:","options":["The daffodils are rare","The daffodils are large","There are many daffodils and they create a social, lively impression","The daffodils are golden"],"answer":2,"exp":"'Crowd' and 'host' are words for large groups of PEOPLE — used here for flowers.\nThis personification makes the daffodils seem social and populous, giving the scene energy and life.","hint":"Why use human words ('crowd', 'host') for flowers? What impression does this create?"},{"id":"pt01","state":"VIC","section":"vic_reading","grade":"selective","topic":"Persuasive Techniques","difficulty":"medium","style":"contour","q":"Read: 'Nine out of ten dentists recommend this toothpaste.'\nThis is an example of:","options":["Anecdote","Appeal to authority/statistics","Alliteration","Emotive language"],"answer":1,"exp":"Using a statistic (9/10) and expert authority (dentists) to persuade.\nThis is an appeal to authority combined with a statistic.\n💡 Other persuasive techniques: emotive language, rhetorical questions, rule of three, inclusive language (we/us).","hint":"Who is being referenced, and what type of evidence is being used?"},{"id":"pt02","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Persuasive Techniques","difficulty":"medium","style":"contour","q":"Read: 'Do we really want our children to grow up in a world without clean air?'\nThis persuasive technique is called:","options":["Alliteration","Rhetorical question","Statistics","Rule of three"],"answer":1,"exp":"A rhetorical question is asked not to get an answer, but to make the reader think and agree with the writer's implied position.\nThe implied answer is obviously 'No' — which supports the writer's argument about clean air.","hint":"A question asked to persuade, not to get an answer = rhetorical question."},{"id":"pt03","state":"VIC","section":"vic_reading","grade":"selective","topic":"Persuasive Techniques","difficulty":"hard","style":"james_ann","q":"Read: 'Plastic straws are cruel, unnecessary, and devastating to ocean life.'\nThe three-part structure is called:","options":["Alliteration","Metaphor","Rule of three (tricolon)","Anaphora"],"answer":2,"exp":"Rule of three (tricolon) = listing three things in succession for rhetorical effect.\nLists of three feel complete and memorable.\n💡 Famous examples: 'Life, liberty, and the pursuit of happiness'; 'Veni, vidi, vici' (I came, I saw, I conquered)","hint":"A deliberate list of exactly three items for rhetorical effect = rule of three."},{"id":"pt04","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Persuasive Techniques","difficulty":"hard","style":"contour","q":"Read: 'Every single day, plastic enters our oceans. Every single day, sea creatures suffer. Every single day, we do nothing.'\nThe repetition of 'Every single day' is called:","options":["Alliteration","Anaphora","Epistrophe","Onomatopoeia"],"answer":1,"exp":"Anaphora = the repetition of the same word or phrase at the beginning of successive sentences.\nThis creates rhythm and emphasis, hammering the point home.\n💡 Epistrophe = repetition at the END of sentences.","hint":"Repetition at the START of consecutive sentences = anaphora."},{"id":"cr01","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Comprehension","difficulty":"easy","style":"acer","q":"Read:\n\"CRISPR-Cas9 is a molecular tool that allows scientists to edit DNA with unprecedented precision. Often described as 'molecular scissors', the system can locate a specific sequence of genetic code and cut it, allowing scientists to remove, replace, or modify it. Originally discovered as part of the immune system of bacteria, CRISPR has been adapted for use in human cells, plants, and animals. The technology holds enormous promise for treating genetic diseases such as sickle cell disease and cystic fibrosis. However, ethical debates surround its use in human embryos, where modifications would be inherited by future generations.\"\n\nWhere was CRISPR originally discovered?","options":["In human cells","In plant DNA","As part of bacteria's immune system","In cancer research"],"answer":2,"exp":"Passage: 'Originally discovered as part of the immune system of bacteria'","hint":"Find the direct statement about CRISPR's origin."},{"id":"cr02","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Vocabulary","difficulty":"medium","style":"james_ann","q":"Read:\n\"CRISPR-Cas9 is a molecular tool that allows scientists to edit DNA with unprecedented precision. Often described as 'molecular scissors', the system can locate a specific sequence of genetic code and cut it, allowing scientists to remove, replace, or modify it. Originally discovered as part of the immune system of bacteria, CRISPR has been adapted for use in human cells, plants, and animals. The technology holds enormous promise for treating genetic diseases such as sickle cell disease and cystic fibrosis. However, ethical debates surround its use in human embryos, where modifications would be inherited by future generations.\"\n\nThe metaphor 'molecular scissors' suggests CRISPR:","options":["Is dangerous like scissors","Cuts precisely at a specific location in DNA","Requires laboratory equipment","Was invented recently"],"answer":1,"exp":"Scissors cut with precision at a specific point. The metaphor emphasises CRISPR's ability to cut DNA at an exact, targeted location — precise, not random.","hint":"What do scissors do, and how does this describe CRISPR's function?"},{"id":"cr03","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Inference","difficulty":"hard","style":"contour","q":"Read:\n\"CRISPR-Cas9 is a molecular tool that allows scientists to edit DNA with unprecedented precision. Often described as 'molecular scissors', the system can locate a specific sequence of genetic code and cut it, allowing scientists to remove, replace, or modify it. Originally discovered as part of the immune system of bacteria, CRISPR has been adapted for use in human cells, plants, and animals. The technology holds enormous promise for treating genetic diseases such as sickle cell disease and cystic fibrosis. However, ethical debates surround its use in human embryos, where modifications would be inherited by future generations.\"\n\nThe phrase 'modifications would be inherited by future generations' is used to explain why:","options":["CRISPR is ineffective","Editing embryos raises greater ethical concerns than editing adults","CRISPR is too expensive","Genetic diseases are untreatable"],"answer":1,"exp":"If you edit an adult's cells, only that person is affected.\nBut editing an embryo means every cell in the resulting human — AND all their descendants — carries the change.\nThis is why embryo editing raises deeper ethical questions: it affects not just one person, but all future generations.","hint":"Why would changes to an embryo be more ethically significant than changes to an adult's cells?"},{"id":"cr04","state":"NSW","section":"nsw_reading","grade":"selective","topic":"Author's Purpose","difficulty":"medium","style":"acer","q":"Read:\n\"CRISPR-Cas9 is a molecular tool that allows scientists to edit DNA with unprecedented precision. Often described as 'molecular scissors', the system can locate a specific sequence of genetic code and cut it, allowing scientists to remove, replace, or modify it. Originally discovered as part of the immune system of bacteria, CRISPR has been adapted for use in human cells, plants, and animals. The technology holds enormous promise for treating genetic diseases such as sickle cell disease and cystic fibrosis. However, ethical debates surround its use in human embryos, where modifications would be inherited by future generations.\"\n\nThe passage ends with ethical concerns. What effect does this structure create?","options":["It makes the reader oppose CRISPR","It shows CRISPR is dangerous","It presents both the promise AND the complexity, creating a balanced, thoughtful conclusion","It argues that CRISPR should be banned"],"answer":2,"exp":"Structure: introduce the tool → explain what it does → note promise (disease treatment) → acknowledge ethical concerns.\nEnding with complexity rather than just celebration shows balanced, responsible science writing.","hint":"Does the passage just celebrate CRISPR, or does it end with a complication?"},{"id":"kid_sci01","state":"VIC","section":"nsw_thinking","grade":"5","topic":"Science Facts","difficulty":"easy","style":"oc","q":"Which Australian animal carries its baby in a pouch?","options":["Dingo","Koala","Crocodile","Echidna"],"answer":1,"exp":"Koalas are marsupials — they carry their young (called joeys) in a pouch on their belly.\nOther Australian marsupials: kangaroos, wallabies, possums, wombats.\n💡 Echidnas lay eggs (monotremes) — they're not marsupials!","hint":"What type of animal carries its baby in a pouch?"},{"id":"kid_sci02","state":"VIC","section":"nsw_thinking","grade":"5","topic":"Science Facts","difficulty":"easy","style":"oc","q":"What do plants need to make their own food (photosynthesis)?","options":["Soil and water only","Sunlight, water, and carbon dioxide","Sunlight and oxygen","Just sunlight"],"answer":1,"exp":"Photosynthesis: sunlight + water + CO₂ → glucose + oxygen\nSunlight provides energy. Water comes from roots. CO₂ comes from air.\n💡 Oxygen is a PRODUCT of photosynthesis — plants release it!","hint":"Three things: sunlight (energy), water (from roots), and a gas from the air."},{"id":"kid_sci03","state":"VIC","section":"nsw_thinking","grade":"5","topic":"Science Facts","difficulty":"easy","style":"oc","q":"What is the hardest natural substance on Earth?","options":["Gold","Iron","Diamond","Granite"],"answer":2,"exp":"Diamond rates 10 on the Mohs hardness scale — the highest possible.\nDiamonds are pure carbon arranged in a crystal structure.\n💡 Diamond can only be scratched by another diamond!","hint":"Which material scores 10 on the hardness scale?"},{"id":"kid_sci04","state":"VIC","section":"nsw_thinking","grade":"5","topic":"Science Facts","difficulty":"easy","style":"oc","q":"How long does it take Earth to orbit the Sun?","options":["One day","One month","One year","Ten years"],"answer":2,"exp":"Earth takes approximately 365.25 days (one year) to orbit the Sun.\n💡 The extra 0.25 day is why we add a leap day (Feb 29) every 4 years!","hint":"One orbit = one year. How long is a year?"},{"id":"kid_sci05","state":"VIC","section":"nsw_thinking","grade":"5","topic":"Science Facts","difficulty":"easy","style":"oc","q":"Which planet is known as the Red Planet?","options":["Venus","Jupiter","Saturn","Mars"],"answer":3,"exp":"Mars appears reddish because its surface is covered in iron oxide (rust).\n💡 Mars has the largest volcano in the solar system: Olympus Mons, 3× taller than Mt Everest!","hint":"Which planet looks red from Earth?"},{"id":"kid_geo01","state":"BOTH","section":"nsw_thinking","grade":"6","topic":"Australian Geography","difficulty":"easy","style":"oc","q":"What is the capital city of Australia?","options":["Sydney","Melbourne","Canberra","Brisbane"],"answer":2,"exp":"Canberra is Australia's capital — chosen as a compromise between Sydney and Melbourne!\n💡 Canberra was purpose-built as the capital and became the seat of government in 1927.","hint":"Australia's capital is not Sydney or Melbourne!"},{"id":"kid_geo02","state":"BOTH","section":"nsw_thinking","grade":"6","topic":"Australian Geography","difficulty":"easy","style":"oc","q":"Which is the largest state in Australia?","options":["New South Wales","Queensland","Western Australia","South Australia"],"answer":2,"exp":"Western Australia is by far Australia's largest state, covering about 2.6 million km² — roughly 1/3 of the continent.\n💡 WA is larger than Western Europe!","hint":"Which state covers most of Australia's western side?"},{"id":"kid_geo03","state":"BOTH","section":"nsw_thinking","grade":"6","topic":"Australian Geography","difficulty":"easy","style":"oc","q":"What is Australia's longest river?","options":["The Murray","The Darling","The Murray-Darling","The Murrumbidgee"],"answer":0,"exp":"The Murray River (2,508 km) is Australia's longest navigable river.\nThe Murray-Darling system is the largest river system, but the Murray alone is the longest single river.","hint":"Which river runs through Victoria, New South Wales and South Australia?"},{"id":"kid_geo04","state":"BOTH","section":"nsw_thinking","grade":"6","topic":"Australian Geography","difficulty":"easy","style":"oc","q":"The Great Barrier Reef is located off the coast of which state?","options":["New South Wales","Western Australia","Victoria","Queensland"],"answer":3,"exp":"The Great Barrier Reef stretches along the Queensland coast for over 2,300 km.\nIt's the world's largest coral reef system, visible from space!","hint":"Which state has the Great Barrier Reef off its coast?"},{"id":"kid_m01","state":"VIC","section":"vic_maths","grade":"5","topic":"Word Problems","difficulty":"easy","style":"oc","q":"Mia has 3 bags with 8 apples in each. She gives 7 apples to her friend. How many does she have left?","options":["17","18","19","20"],"answer":0,"exp":"Total apples = 3 × 8 = 24\nAfter giving 7: 24 − 7 = 17","hint":"First find the total, then subtract what she gave away."},{"id":"kid_m02","state":"VIC","section":"vic_maths","grade":"5","topic":"Word Problems","difficulty":"easy","style":"oc","q":"A pizza is cut into 8 slices. Tom eats 3 slices and Sara eats 2. What fraction of the pizza is left?","options":["⅜","⅝","½","¼"],"answer":0,"exp":"Eaten = 3 + 2 = 5 slices\nLeft = 8 − 5 = 3 slices = 3/8\n💡 Always check: 3 eaten (by Tom) + 2 eaten (by Sara) + 3 left = 8 total ✓","hint":"Find how many slices are left, then write as a fraction of 8."},{"id":"kid_m03","state":"NSW","section":"nsw_maths","grade":"5","topic":"Word Problems","difficulty":"easy","style":"oc","q":"A bookshelf has 5 shelves. Each shelf holds 12 books. How many books does it hold in total?","options":["50","55","60","65"],"answer":2,"exp":"5 × 12 = 60 books\n💡 5 × 12 = 5 × 10 + 5 × 2 = 50 + 10 = 60","hint":"Multiply the number of shelves by books per shelf."},{"id":"kid_m04","state":"VIC","section":"vic_maths","grade":"6","topic":"Time","difficulty":"easy","style":"oc","q":"School starts at 8:45 AM and finishes at 3:15 PM. How long is the school day?","options":["5 hr 30 min","6 hr","6 hr 30 min","7 hr"],"answer":2,"exp":"8:45 to 3:15\n8:45 → 9:00 = 15 min\n9:00 → 3:00 = 6 hours\n3:00 → 3:15 = 15 min\nTotal = 6 hours 30 minutes","hint":"Count in steps: from 8:45 to 9:00, then 9:00 to 3:00, then 3:00 to 3:15."},{"id":"kid_m05","state":"NSW","section":"nsw_maths","grade":"6","topic":"Fractions","difficulty":"easy","style":"oc","q":"What is ¼ + ½?","options":["½","¾","⅔","1"],"answer":1,"exp":"½ = 2/4\n¼ + 2/4 = 3/4\n💡 Always use the same denominator: ¼ + 2/4 = 3/4","hint":"Convert ½ to quarters: ½ = 2/4. Then add."},{"id":"kid_m06","state":"VIC","section":"vic_maths","grade":"5","topic":"Multiplication","difficulty":"easy","style":"oc","q":"What is 7 × 8?","options":["48","54","56","63"],"answer":2,"exp":"7 × 8 = 56\n💡 Remember: 7 × 8 = 56 — many students confuse this with 6 × 9 = 54. They're different!","hint":"7 eights: 8,16,24,32,40,48,56"},{"id":"kid_m07","state":"NSW","section":"nsw_maths","grade":"4","topic":"Number","difficulty":"easy","style":"oc","q":"Count by 4s: 4, 8, 12, 16, ___","options":["18","19","20","21"],"answer":2,"exp":"4 times table: 4,8,12,16,20,24...\n16 + 4 = 20","hint":"Keep adding 4."},{"id":"kid_m08","state":"VIC","section":"vic_maths","grade":"6","topic":"Percentage","difficulty":"easy","style":"oc","q":"What is 50% of 80?","options":["20","30","40","50"],"answer":2,"exp":"50% = half\nHalf of 80 = 40","hint":"50% means half. Half of 80 = 80 ÷ 2."},{"id":"kid_r01","state":"NSW","section":"nsw_reading","grade":"4","topic":"Comprehension","difficulty":"easy","style":"oc","q":"Read:\n\"The platypus is one of Australia's most unusual animals. It has a bill like a duck, a tail like a beaver, and webbed feet for swimming. Unlike most other mammals, the platypus lays eggs! When European scientists first saw a platypus, they thought it was a fake animal made from different parts. The platypus uses its sensitive bill to find food underwater by detecting tiny electrical signals from its prey.\"\n\nName TWO body parts the platypus shares with other animals.","options":["Bill like a duck, tail like a beaver","Wings like a bird, tail like a fish","Pouch like a kangaroo, bill like a duck","Tail like a beaver, shell like a turtle"],"answer":0,"exp":"Passage: 'It has a bill like a duck, a tail like a beaver'","hint":"Find the two animal comparisons in the passage."},{"id":"kid_r02","state":"VIC","section":"vic_reading","grade":"4","topic":"Inference","difficulty":"easy","style":"oc","q":"Read:\n\"The platypus is one of Australia's most unusual animals. It has a bill like a duck, a tail like a beaver, and webbed feet for swimming. Unlike most other mammals, the platypus lays eggs! When European scientists first saw a platypus, they thought it was a fake animal made from different parts. The platypus uses its sensitive bill to find food underwater by detecting tiny electrical signals from its prey.\"\n\nWhy did European scientists think the platypus was fake?","options":["They had never been to Australia","It seemed impossible for one animal to have so many different features from different animals","They didn't like the platypus","The platypus was too small to be real"],"answer":1,"exp":"A bill, beaver tail, webbed feet AND lays eggs — these features come from so many different animals that scientists couldn't believe they were all in one real creature.","hint":"What features made the platypus seem like it was put together from different animals?"},{"id":"kid_r03","state":"NSW","section":"nsw_reading","grade":"5","topic":"Vocabulary","difficulty":"easy","style":"oc","q":"Read:\n\"The platypus is one of Australia's most unusual animals. It has a bill like a duck, a tail like a beaver, and webbed feet for swimming. Unlike most other mammals, the platypus lays eggs! When European scientists first saw a platypus, they thought it was a fake animal made from different parts. The platypus uses its sensitive bill to find food underwater by detecting tiny electrical signals from its prey.\"\n\nWhat does 'sensitive' mean in 'sensitive bill'?","options":["Hard and strong","Able to detect even small signals","Sharp and pointed","Colourful"],"answer":1,"exp":"'Sensitive' = able to detect small changes or signals.\nContext: the bill can detect tiny electrical signals — it must be very good at detecting things.","hint":"If the bill detects TINY signals, what does that tell us about how sensitive it is?"},{"id":"kid_ta01","state":"VIC","section":"nsw_thinking","grade":"5","topic":"Tamil Language","difficulty":"easy","style":"oc","q":"In Tamil, how do you say 'hello' or 'welcome'?","options":["நன்றி (Nandri)","வணக்கம் (Vanakkam)","பை பை (Bye bye)","ஆமாம் (Amaam)"],"answer":1,"exp":"வணக்கம் (Vanakkam) = Hello / Welcome / Greetings\nThis is the most common Tamil greeting.\n💡 நன்றி (Nandri) = Thank you\nஆமாம் (Amaam) = Yes","hint":"The most common Tamil greeting, used to welcome someone."},{"id":"kid_ta02","state":"VIC","section":"nsw_thinking","grade":"5","topic":"Tamil Language","difficulty":"easy","style":"oc","q":"What are the Tamil words for the numbers 1, 2, 3?","options":["ஒன்று, இரண்டு, மூன்று","ஒன்று, மூன்று, இரண்டு","ஆறு, ஏழு, எட்டு","நான்கு, ஐந்து, ஆறு"],"answer":0,"exp":"Tamil 1-3:\n1 = ஒன்று (Ondru)\n2 = இரண்டு (Irandu)\n3 = மூன்று (Moondru)\n💡 Practice: ஒன்று, இரண்டு, மூன்று, நான்கு, ஐந்து (1,2,3,4,5)","hint":"The first three numbers in Tamil."},{"id":"kid_ta03","state":"VIC","section":"nsw_thinking","grade":"4","topic":"Tamil Language","difficulty":"easy","style":"oc","q":"Which of these is the Tamil word for 'mother'?","options":["அப்பா (Appa)","அம்மா (Amma)","தாத்தா (Thaathaa)","அண்ணா (Anna)"],"answer":1,"exp":"அம்மா (Amma) = Mother\nஅப்பா (Appa) = Father\nதாத்தா (Thaathaa) = Grandfather (paternal)\nபாட்டி (Paatti) = Grandmother\nஅண்ணா (Anna) = Older brother","hint":"Which Tamil family word sounds like 'amma'?"},{"id":"kid_ta04","state":"VIC","section":"nsw_thinking","grade":"5","topic":"Tamil Language","difficulty":"medium","style":"oc","q":"Tamil has a special letter ழ (zha) that is unique. How is it approximately pronounced?","options":["Like the English 'z'","A soft retroflex sound with no English equivalent — somewhat like 'la' with tongue curled back","Like the English 'j'","Like the English 'sh'"],"answer":1,"exp":"ழ is one of Tamil's most distinctive letters — it has no equivalent in most other languages.\nIt's a retroflexed lateral approximant: the tongue curls back and produces a soft 'la/ra' sound.\n💡 Famous word using ழ: தமிழ் (Tamil) — the final ழ gives Tamil its unique sound!","hint":"ழ is famous for being impossible to pronounce in English — it's unique to Tamil and Malayalam."},{"id":"kid_ta05","state":"VIC","section":"nsw_thinking","grade":"6","topic":"Tamil Language","difficulty":"medium","style":"oc","q":"The Thirukkural is a famous ancient Tamil text. What is it a collection of?","options":["War stories","1,330 short couplets (kurals) about ethics, wealth, and love","Tamil alphabet lessons","Religious hymns"],"answer":1,"exp":"Thirukkural = 'Sacred Couplets'\nWritten by Thiruvalluvar about 2,000 years ago.\n1,330 couplets in 133 chapters, 10 couplets each.\nCovers: virtue (ethics), wealth (politics), love (relationships)\n💡 It has been translated into over 80 languages — one of the world's most translated works!","hint":"What type of writing makes up the Thirukkural?"}];

const QB = (() => {
  const STL = {acer:'ACER',hendersons:'Hendersons',psle:'PSLE',contour:'Contour',james_ann:'James & Ann',edutest:'EduTest',matrix:'Matrix',oc:'OC Test',hast:'HAST'};
  const SL = {vic_reading:'📖 Reading',vic_maths:'🔢 Maths',vic_verbal:'🧠 Verbal',vic_quant:'📐 Quant',nsw_reading:'📖 NSW Reading',nsw_maths:'🔢 NSW Maths',nsw_thinking:'🧩 Thinking Skills'};
  const SC = {vic_reading:'ta',vic_maths:'tg',vic_verbal:'tpu',vic_quant:'to',nsw_reading:'ta',nsw_maths:'tg',nsw_thinking:'tpu'};
  const DC = {easy:'tg',medium:'to',hard:'tp'};

  function filter(f={}) {
    return QUESTIONS.filter(q => {
      if (f.section && f.section !== 'ALL' && q.section !== f.section) return false;
      if (f.grade && f.grade !== 'ALL' && q.grade !== f.grade) return false;
      if (f.topic && f.topic !== 'ALL' && q.topic !== f.topic) return false;
      if (f.difficulty && f.difficulty !== 'ALL' && q.difficulty !== f.difficulty) return false;
      if (f.style && f.style !== 'ALL' && q.style !== f.style) return false;
      if (f.state && f.state !== 'ALL' && q.state !== f.state && q.state !== 'BOTH') return false;
      return true;
    });
  }

  function shuffle(arr) {
    const a = [...arr];
    for (let i = a.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [a[i], a[j]] = [a[j], a[i]];
    }
    return a;
  }

  function uniq(arr) { return [...new Set(arr)]; }

  function getTopics() { return uniq(QUESTIONS.map(q => q.topic)).sort(); }
  function getSections() { return uniq(QUESTIONS.map(q => q.section)); }
  function getStyles() { return uniq(QUESTIONS.map(q => q.style).filter(Boolean)); }

  function renderCard(q, idx, mode, userAns, submitted, revealed, showHint, AIcache, AIloading) {
    const correct = submitted && userAns === q.answer;
    const fbKey = `${q.id}_${userAns}`;
    const fb = AIcache?.[fbKey];
    const fbLoad = AIloading?.has(fbKey);

    let cls = 'qcard';
    if (submitted && userAns !== null) cls += correct ? ' correct' : ' wrong';
    else if (revealed) cls += ' revealed';

    const opts = q.options.map((opt, oi) => {
      let c = 'opt';
      const sel = userAns === oi;
      if (mode !== 'browse' && sel && !submitted) c += ' sel';
      if (submitted || revealed) {
        c += ' dis';
        if (oi === q.answer) c += ' cor';
        else if (submitted && sel) c += ' wrg';
      }
      const tick = (submitted || revealed) && oi === q.answer ? '<span class="otick">✓</span>' :
        submitted && sel && oi !== q.answer ? '<span class="otick">✗</span>' : '';
      const click = (!submitted && !revealed && mode !== 'browse')
        ? `onclick="App.handleAnswer('${mode}',${idx},${oi})"` : '';
      return `<div class="${c}" ${click}><span class="oltr">${'ABCD'[oi]}.</span><span style="flex:1">${opt}</span>${tick}</div>`;
    }).join('');

    const expHtml = (submitted && userAns !== null || revealed) && q.exp
      ? `<div class="exp"><strong style="color:var(--accent)">Explanation:</strong>\n${q.exp}</div>` : '';

    const hintHtml = showHint && q.hint && !submitted && !revealed
      ? `<div class="hint-box">💡 Hint: ${q.hint}</div>` : '';

    let aiFb = '';
    if (submitted && userAns !== null) {
      if (fbLoad) {
        aiFb = `<div class="aifb ${correct ? 'correct' : 'wrong'}"><span class="spin">⏳</span> <em style="color:var(--muted)">Getting personalised feedback...</em></div>`;
      } else if (fb) {
        const lines = fb.split('\n').filter(l => l.trim());
        aiFb = `<div class="aifb ${correct ? 'correct' : 'wrong'}">
          <div class="aifb-hdr" style="color:var(--${correct ? 'green' : 'orange'})">🤖 Personalised Feedback</div>
          ${lines.map(l => `<div style="margin-bottom:4px">${l}</div>`).join('')}
        </div>`;
      }
    }

    const styleTag = q.style ? `<span class="tag tm xs">${STL[q.style] || q.style}</span>` : '';
    const browseActions = mode === 'browse' ? `
      <div class="fc gap8 mt14 wrap">
        <button class="btn bm bsm" onclick="Browse.toggleReveal('${q.id}')">${revealed ? '🙈 Hide' : '👁 Show Answer'}</button>
        ${!revealed ? `<button class="btn bm bsm" onclick="Browse.toggleHint('${q.id}')">💡 Hint</button>` : ''}
        <button class="btn ba bsm" onclick="App.practiceOne('${q.id}')">✏️ Practice This</button>
      </div>` : '';

    return `<div class="${cls}" id="qc_${q.id || idx}">
      <div class="mb8 fc gap8 wrap">
        ${q.section ? `<span class="tag ${SC[q.section] || 'tm'}">${SL[q.section] || q.section}</span>` : ''}
        ${q.topic ? `<span class="tag tm">${q.topic}</span>` : ''}
        ${q.difficulty ? `<span class="tag ${DC[q.difficulty] || 'tm'}">${q.difficulty}</span>` : ''}
        ${styleTag}
      </div>
      <div class="qtxt">Q${idx + 1}. ${q.q}</div>
      ${hintHtml}${opts}${expHtml}${aiFb}${browseActions}
    </div>`;
  }

  return { filter, shuffle, uniq, getTopics, getSections, getStyles, renderCard, STL, SL, SC, DC };
})();
